def _property_search_preview_timeout_seconds(*, prefer_fast: bool) -> float:
    env_name = (
        "PROPERTYQUARRY_SEARCH_PREVIEW_FAST_TIMEOUT_SECONDS"
        if prefer_fast
        else "PROPERTYQUARRY_SEARCH_PREVIEW_TIMEOUT_SECONDS"
    )
    raw_value = str(os.getenv(env_name) or "").strip()
    default_value = 8.0 if prefer_fast else 14.0
    if not raw_value:
        return default_value
    try:
        parsed = float(raw_value)
    except Exception:
        return default_value
    return max(1.0, min(parsed, 60.0))


def _property_search_source_fetch_lane(source_spec: dict[str, object]) -> str:
    access_level = str(source_spec.get("source_access_level") or "").strip().lower()
    provider_family = str(source_spec.get("provider_family") or "").strip().lower()
    if "browser" in access_level:
        return "browser"
    if provider_family in {"municipal_housing", "public_housing", "distressed_sales"}:
        return "official"
    return "provider"


def _property_search_provider_group_key(source_spec: dict[str, object]) -> str:
    provider_family = str(source_spec.get("provider_family") or "").strip().lower()
    if provider_family:
        return provider_family
    platform = str(source_spec.get("platform") or "").strip().lower()
    if platform:
        return platform
    label = " ".join(str(source_spec.get("label") or "").split()).strip()
    if "|" in label:
        label = label.split("|", 1)[0].strip()
    return label.casefold() or "provider"


def _property_search_provider_identity_key(source_spec: dict[str, object]) -> str:
    provider_source_key = str(source_spec.get("provider_source_key") or source_spec.get("source_provider_key") or "").strip()
    if provider_source_key:
        candidate = provider_source_key.split(":", 1)[0].strip().casefold()
        if candidate:
            return candidate
    for raw_key in ("provider_key", "platform", "provider_family", "label", "source_label"):
        key = str(source_spec.get(raw_key) or "").strip().lower()
        if raw_key in {"label", "source_label"}:
            if "|" in key:
                key = key.split("|", 1)[0].strip()
            if key:
                return key
        if key:
            return key
    return ""


def _property_search_interleave_by_provider_group(specs: list[dict[str, object]]) -> list[dict[str, object]]:
    if len(specs) < 2:
        return [dict(spec) for spec in specs]
    grouped: dict[str, deque[dict[str, object]]] = defaultdict(deque)
    ordered_keys: list[str] = []
    for spec in specs:
        copied = dict(spec)
        key = _property_search_provider_group_key(copied)
        if key not in grouped:
            ordered_keys.append(key)
        grouped[key].append(copied)
    interleaved: list[dict[str, object]] = []
    while grouped:
        for key in list(ordered_keys):
            queue = grouped.get(key)
            if not queue:
                continue
            interleaved.append(queue.popleft())
            if not queue:
                grouped.pop(key, None)
                ordered_keys = [existing for existing in ordered_keys if existing != key]
    return interleaved


def _property_search_provider_group_total(specs: list[dict[str, object]]) -> int:
    return len({_property_search_provider_group_key(dict(spec)) for spec in specs})


def _property_search_provider_total(specs: list[dict[str, object]]) -> int:
    provider_keys: set[str] = set()
    for spec in specs:
        key = _property_search_provider_identity_key(dict(spec))
        if key:
            provider_keys.add(key)
    return len(provider_keys)


def _property_search_prefetch_listing_urls(
    *,
    specs: list[dict[str, object]],
    force_refresh: bool,
    on_source_started: callable | None = None,
    on_source_finished: callable | None = None,
) -> dict[tuple[str, str], dict[str, object]]:
    if not specs:
        return {}
    ordered_specs = _property_search_interleave_by_provider_group(specs)
    provider_cap = _property_search_provider_fetch_concurrency()
    browser_cap = _property_search_browser_provider_concurrency()
    official_cap = _property_search_official_evidence_concurrency()
    overall_cap = max(1, min(len(specs), max(provider_cap + official_cap, browser_cap, provider_cap)))
    lane_semaphores = {
        "provider": threading.Semaphore(provider_cap),
        "browser": threading.Semaphore(browser_cap),
        "official": threading.Semaphore(official_cap),
    }

    def _task(source_spec: dict[str, object]) -> tuple[tuple[str, str], dict[str, object]]:
        source_url = urllib.parse.urldefrag(str(source_spec.get("url") or "").strip())[0]
        platform = str(source_spec.get("platform") or "").strip().lower()
        lane = _property_search_source_fetch_lane(source_spec)
        sem = lane_semaphores.get(lane, lane_semaphores["provider"])
        started_at = time.perf_counter()
        with sem:
            try:
                listing_urls, provider_cache_state = _property_scout_listing_urls_for_source(
                    source_url=source_url,
                    source_spec=source_spec,
                    force_refresh=force_refresh,
                )
                return (
                    (platform, source_url),
                    {
                        "listing_urls": listing_urls,
                        "provider_cache_state": provider_cache_state,
                        "timing_ms": {"provider_fetch": round((time.perf_counter() - started_at) * 1000.0, 2)},
                        "lane": lane,
                    },
                )
            except Exception as exc:
                return (
                    (platform, source_url),
                    {
                        "error": compact_text(str(exc or ""), fallback="property_scout_fetch_failed", limit=200),
                        "timing_ms": {"provider_fetch": round((time.perf_counter() - started_at) * 1000.0, 2)},
                        "lane": lane,
                    },
                )

    prefetched: dict[tuple[str, str], dict[str, object]] = {}
    queued_specs = iter(ordered_specs)

    def _submit(executor: concurrent.futures.ThreadPoolExecutor, active: dict[concurrent.futures.Future, dict[str, object]]) -> bool:
        try:
            source_spec = dict(next(queued_specs))
        except StopIteration:
            return False
        if callable(on_source_started):
            try:
                on_source_started(dict(source_spec))
            except Exception:
                pass
        active[executor.submit(_task, source_spec)] = source_spec
        return True

    with concurrent.futures.ThreadPoolExecutor(max_workers=overall_cap, thread_name_prefix="property-source-fetch") as executor:
        active: dict[concurrent.futures.Future, dict[str, object]] = {}
        for _ in range(overall_cap):
            if not _submit(executor, active):
                break
        while active:
            done, _ = concurrent.futures.wait(
                tuple(active.keys()),
                return_when=concurrent.futures.FIRST_COMPLETED,
            )
            for future in done:
                source_spec = active.pop(future)
                try:
                    key, payload = future.result()
                except Exception:
                    _submit(executor, active)
                    continue
                prefetched[key] = payload
                if callable(on_source_finished):
                    try:
                        on_source_finished(dict(source_spec), dict(payload or {}))
                    except Exception:
                        pass
                _submit(executor, active)
    return prefetched


def _property_candidate_supports_live_tour(candidate: dict[str, object]) -> bool:
    facts = dict(candidate.get("property_facts") or {}) if isinstance(candidate.get("property_facts"), dict) else {}
    source_virtual_tour_url = _safe_provider_live_360_url(facts.get("source_virtual_tour_url"))
    return bool(
        facts.get("has_360")
        or source_virtual_tour_url
    )


def _safe_provider_live_360_url(value: object) -> str:
    normalized = _safe_live_property_tour_url(value)
    if not normalized:
        return ""
    try:
        parsed = urllib.parse.urlparse(normalized)
    except Exception:
        return ""
    host = str(parsed.hostname or "").strip().lower().rstrip(".")
    path = str(parsed.path or "").strip().lower()
    if host == "api.willhaben.at" and ("/logevent/" in path or path.endswith("/virtual-tour-link-clicked")):
        return ""
    return normalized


def _property_tour_status_is_pending(value: object) -> bool:
    normalized = str(value or "").strip().lower()
    return normalized in {"queued", "pending", "processing", "running", "in_progress", "started", "rendering", "repairing"}


def _property_tour_status_is_terminal(value: object) -> bool:
    normalized = str(value or "").strip().lower()
    return normalized in {"created", "existing", "ready", "blocked", "failed", "skipped", "not_applicable"}


def _property_parse_iso_datetime(value: object) -> datetime | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    try:
        normalized = raw[:-1] + "+00:00" if raw.endswith("Z") else raw
        parsed = datetime.fromisoformat(normalized)
    except Exception:
        return None
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def _property_visual_elapsed_minutes(
    *,
    status: object = "",
    requested_at: object = "",
    status_updated_at: object = "",
) -> int:
    normalized_status = str(status or "").strip().lower()
    requested_dt = _property_parse_iso_datetime(requested_at)
    updated_dt = _property_parse_iso_datetime(status_updated_at)
    if normalized_status in {"processing", "running", "in_progress", "started", "rendering", "repairing"}:
        started = updated_dt or requested_dt
    else:
        started = requested_dt or updated_dt
    if started is None:
        return 0
    elapsed = _utcnow() - started
    return max(int(elapsed.total_seconds() // 60), 0)


def _normalize_property_visual_request_kind(request_kind: object) -> str:
    normalized_kind = str(request_kind or "tour").strip().lower() or "tour"
    if normalized_kind in {"walkthrough", "generated_reconstruction_walkthrough"}:
        return "flythrough"
    return normalized_kind if normalized_kind in {"tour", "flythrough"} else "tour"


def _property_visual_initial_eta_minutes(*, status: object, eta_minutes: object = "") -> int:
    normalized_status = str(status or "").strip().lower()
    raw_eta = str(eta_minutes or "").strip()
    try:
        if raw_eta:
            return max(int(float(raw_eta)), 1)
    except Exception:
        pass
    return 5 if normalized_status in {"processing", "running", "in_progress", "started", "rendering"} else 10


def _property_visual_progress_pct(
    *,
    request_kind: str,
    status: object,
    ready_url: object = "",
    eta_minutes: object = "",
    requested_at: object = "",
    status_updated_at: object = "",
) -> int:
    normalized_kind = _normalize_property_visual_request_kind(request_kind)
    normalized_status = str(status or "").strip().lower()
    if str(ready_url or "").strip():
        return 100
    elapsed_minutes = _property_visual_elapsed_minutes(
        status=normalized_status,
        requested_at=requested_at,
        status_updated_at=status_updated_at,
    )
    eta_budget = _property_visual_initial_eta_minutes(status=normalized_status, eta_minutes=eta_minutes)
    if normalized_status in {"processing", "running", "in_progress", "started", "rendering"}:
        base = 64 if normalized_kind == "flythrough" else 58
        if elapsed_minutes >= eta_budget * 3:
            return 88 if normalized_kind == "flythrough" else 84
        if elapsed_minutes >= eta_budget * 2:
            return 80 if normalized_kind == "flythrough" else 76
        if elapsed_minutes >= eta_budget:
            return 72 if normalized_kind == "flythrough" else 68
        return base
    if normalized_status in {"queued", "pending"}:
        base = 18 if normalized_kind == "flythrough" else 14
        if elapsed_minutes >= eta_budget * 3:
            return 52 if normalized_kind == "flythrough" else 46
        if elapsed_minutes >= eta_budget * 2:
            return 40 if normalized_kind == "flythrough" else 34
        if elapsed_minutes >= eta_budget:
            return 28 if normalized_kind == "flythrough" else 22
        return base
    return 0


def _property_visual_eta_label(
    *,
    request_kind: str,
    status: object,
    eta_minutes: object = "",
    requested_at: object = "",
    status_updated_at: object = "",
) -> str:
    normalized_status = str(status or "").strip().lower()
    if normalized_status in {"queued", "pending", "processing", "running", "in_progress", "started", "rendering"}:
        eta_value = _property_visual_initial_eta_minutes(status=normalized_status, eta_minutes=eta_minutes)
        elapsed_minutes = _property_visual_elapsed_minutes(
            status=normalized_status,
            requested_at=requested_at,
            status_updated_at=status_updated_at,
        )
        if elapsed_minutes >= eta_value:
            return f"delayed · {elapsed_minutes} min so far"
        return f"about {eta_value} min"
    return ""


def _normalize_property_flythrough_result(result: dict[str, object] | None) -> dict[str, object]:
    payload = dict(result or {})
    published_video_url = _published_walkthrough_asset_url(payload.get("video_url") or payload.get("flythrough_url"))
    if published_video_url:
        payload["video_url"] = published_video_url
        payload["flythrough_url"] = published_video_url
    else:
        payload.pop("flythrough_url", None)
    status = str(payload.get("status") or "").strip().lower()
    if published_video_url and status not in {"rendered", "existing", "ready"}:
        payload["status"] = "rendered"
        payload.setdefault("reason", "")
    return payload


