def _property_realestate_international_preview_facts(source_url: str, source_html: str) -> dict[str, object]:
    host = urllib.parse.urlparse(str(source_url or "")).netloc.lower()
    if not any(marker in host for marker in ("realestate.com.au", "realtor.com")):
        return {}
    facts: dict[str, object] = {}

    def _first_int(*values: object) -> int:
        for value in values:
            if isinstance(value, (int, float)) and value:
                return int(value)
            match = re.search(r"\b(\d{1,3})\b", str(value or ""))
            if match:
                try:
                    return int(match.group(1))
                except ValueError:
                    continue
        return 0

    def _first_float(*values: object) -> float | None:
        for value in values:
            if isinstance(value, (int, float)) and float(value) > 0:
                return float(value)
            normalized = str(value or "").strip()
            if not normalized:
                continue
            match = re.search(r"\d[\d,.\s]*", normalized)
            if not match:
                continue
            try:
                return float(match.group(0).replace(" ", "").replace(",", ""))
            except ValueError:
                continue
        return None

    schema_objects: list[dict[str, object]] = []
    for match in re.finditer(
        r"<script[^>]+type=[\"']application/ld\+json[\"'][^>]*>(.*?)</script>",
        source_html,
        flags=re.IGNORECASE | re.DOTALL,
    ):
        raw_json = html.unescape(match.group(1).strip())
        try:
            payload = json.loads(raw_json)
        except Exception:
            continue
        if isinstance(payload, dict):
            schema_objects.append(payload)
        elif isinstance(payload, list):
            schema_objects.extend(item for item in payload if isinstance(item, dict))

    for schema in schema_objects:
        main_entities = schema.get("mainEntity")
        entities = list(main_entities or []) if isinstance(main_entities, list) else ([main_entities] if isinstance(main_entities, dict) else [])
        for entity in entities:
            if not isinstance(entity, dict):
                continue
            offers = entity.get("offers")
            if isinstance(offers, dict):
                price_amount = _first_float(offers.get("price"))
                currency = compact_text(str(offers.get("priceCurrency") or "").strip().upper(), fallback="", limit=12)
                if price_amount and not facts.get("price_amount"):
                    facts["price_amount"] = price_amount
                if currency and not facts.get("price_currency"):
                    facts["price_currency"] = currency
                if price_amount and currency and not facts.get("price_display"):
                    facts["price_display"] = f"{currency} {price_amount:,.0f}"
            if entity.get("description") and not facts.get("listing_description"):
                facts["listing_description"] = compact_text(str(entity.get("description") or ""), fallback="", limit=500)
            if entity.get("name") and not facts.get("listing_name"):
                facts["listing_name"] = compact_text(str(entity.get("name") or ""), fallback="", limit=180)
        breadcrumbs = schema.get("breadCrumb")
        if isinstance(breadcrumbs, dict):
            items = breadcrumbs.get("itemListElement")
            if isinstance(items, list):
                labels = []
                for item in items:
                    node = item.get("item") if isinstance(item, dict) else None
                    if isinstance(node, dict) and str(node.get("name") or "").strip():
                        labels.append(str(node.get("name") or "").strip())
                if labels:
                    facts.setdefault("country_label", labels[1] if len(labels) > 1 else labels[0])
                    facts.setdefault("region_label", labels[2] if len(labels) > 2 else "")
                    facts.setdefault("location", labels[-1])
                    facts.setdefault("postal_name", labels[-1])

    next_match = re.search(
        r"<script[^>]+id=[\"']__NEXT_DATA__[\"'][^>]*>(.*?)</script>",
        source_html,
        flags=re.IGNORECASE | re.DOTALL,
    )
    if next_match:
        try:
            next_payload = json.loads(next_match.group(1))
        except Exception:
            next_payload = {}
        apollo_state = (
            dict(next_payload.get("props", {}).get("apolloState") or {})
            if isinstance(next_payload, dict) and isinstance(next_payload.get("props"), dict)
            else {}
        )
        listing_nodes = [
            value
            for key, value in apollo_state.items()
            if str(key).startswith("ListingDetail:") and isinstance(value, dict)
        ]
        for node in listing_nodes:
            bedrooms = _first_int(node.get("bedrooms"))
            bathrooms = _first_int(node.get("bathrooms"))
            if bedrooms:
                facts["bedrooms"] = bedrooms
                facts.setdefault("rooms", bedrooms)
            if bathrooms:
                facts["bathrooms"] = bathrooms
            property_types = node.get("propertyTypes") or node.get('propertyTypes({"language":"en"})')
            if isinstance(property_types, dict) and isinstance(property_types.get("json"), list) and property_types.get("json"):
                facts["property_type"] = str(property_types["json"][0]).strip().lower()
            elif isinstance(property_types, list) and property_types:
                facts["property_type"] = str(property_types[0]).strip().lower()
            land_area = _first_float(node.get('landSize({"language":"en","unit":"SQUARE_METERS"})'))
            if land_area:
                facts["land_area_sqm"] = land_area
                facts["land_area_display"] = f"{land_area:,.0f} m2"
            if node.get("displayAddress"):
                address = compact_text(str(node.get("displayAddress") or ""), fallback="", limit=180)
                facts["postal_name"] = address
                facts["location"] = address
            price_ref = node.get('price({"currency":"AUD","language":"en"})')
            price_node_id = str(price_ref.get("id") or "") if isinstance(price_ref, dict) else ""
            price_node = dict(apollo_state.get(price_node_id) or {}) if price_node_id else {}
            display_price = compact_text(str(price_node.get("displayListingPrice") or ""), fallback="", limit=80)
            if display_price:
                facts["price_display"] = display_price
                price_match = re.search(r"\b([A-Z]{3})\b\s*\$?\s*([\d,]+(?:\.\d+)?)", display_price)
                if price_match:
                    facts["price_currency"] = price_match.group(1)
                    facts["price_amount"] = float(price_match.group(2).replace(",", ""))
            if node.get("description") and not facts.get("listing_description"):
                facts["listing_description"] = compact_text(str(node.get("description") or ""), fallback="", limit=500)

    description_blob = " ".join(
        str(value or "")
        for value in (
            facts.get("listing_description"),
            facts.get("listing_name"),
            _property_scout_extract_meta_content(source_html, "og:description"),
            _property_scout_extract_meta_content(source_html, "description"),
        )
    )
    if not facts.get("bedrooms"):
        bedrooms = _first_int(*(re.findall(r"\b(\d{1,2})\s+bedrooms?\b", description_blob, flags=re.IGNORECASE)[:1]))
        if bedrooms:
            facts["bedrooms"] = bedrooms
            facts.setdefault("rooms", bedrooms)
    if not facts.get("bathrooms"):
        bathrooms = _first_int(*(re.findall(r"\b(\d{1,2})\s+bathrooms?\b", description_blob, flags=re.IGNORECASE)[:1]))
        if bathrooms:
            facts["bathrooms"] = bathrooms
    if not facts.get("property_type") and re.search(r"\bhouse\b", description_blob, flags=re.IGNORECASE):
        facts["property_type"] = "house"
    if facts:
        facts.setdefault("provider_channel", "realestate_international")
    return facts


def _property_scout_page_preview(property_url: str, *, prefer_fast: bool = False) -> dict[str, object]:
    normalized = urllib.parse.urldefrag(str(property_url or "").strip())[0]
    if not normalized:
        return {}
    parsed = urllib.parse.urlparse(normalized)
    if "angebote.sozialbau.at" in parsed.netloc.lower():
        query = urllib.parse.parse_qs(parsed.query)
        if str((query.get("pq_listing") or [""])[0]).strip() == "1":
            return _property_sozialbau_preview_from_url(normalized)
    willhaben_packet_preview: dict[str, object] = {}
    if _is_willhaben_property_url(normalized) and not prefer_fast:
        try:
            packet = _load_willhaben_property_packet_compat(normalized, timeout_seconds=4)
            property_facts = dict(packet.get("property_facts_json") or {})
            description = compact_text(
                " | ".join(f"{key}: {value}" for key, value in property_facts.items() if str(value or "").strip()),
                fallback="",
                limit=300,
            )
            willhaben_packet_preview = {
                "listing_id": str(packet.get("listing_id") or "").strip(),
                "title": compact_text(str(packet.get("title") or "").strip(), fallback=normalized, limit=160),
                "summary": description,
                "property_facts_json": property_facts,
            }
            if _property_candidate_has_floorplan(
                property_url=normalized,
                title=str(willhaben_packet_preview.get("title") or ""),
                summary=str(willhaben_packet_preview.get("summary") or ""),
                property_facts=property_facts,
                preview=willhaben_packet_preview,
            ):
                return willhaben_packet_preview
        except RuntimeError:
            pass
    if not prefer_fast and _property_scout_is_floorplan_archive_candidate_url(url=normalized, context=normalized):
        floorplan_urls = _property_scout_extract_floorplan_urls_from_archive(
            source_url=normalized,
            archive_url=normalized,
            context=normalized,
        )
        if floorplan_urls:
            parsed_host = urllib.parse.urlparse(normalized).netloc.lower()
            property_facts: dict[str, object] = {
                "has_floorplan": True,
                "floorplan_count": len(floorplan_urls),
                "floorplan_urls_json": list(floorplan_urls),
                "media_count": 0,
                "has_360": False,
            }
            if "edikte" in parsed_host or "justiz" in parsed_host:
                property_facts.update(
                    {
                        "distressed_sale": True,
                        "sale_channel": "judicial_auction",
                        "provider_channel": "justiz_edikte_at",
                    }
                )
            if any(marker in parsed_host for marker in ("gesiba.at", "siedlungsunion.at", "wbv-gpa.at", "frieden.at", "sozialbau.at")):
                property_facts.update(
                    {
                        "provider_group": "genossenschaften_at",
                        "provider_channel": parsed_host,
                    }
                )
            property_facts = _property_enrich_missing_fact_research(
                facts=property_facts,
                property_url=normalized,
                title=normalized,
                summary="Document bundle with extracted floor plan material.",
                floorplan_urls=tuple(floorplan_urls[:6]),
            )
            return {
                "listing_id": normalized,
                "title": normalized,
                "summary": "Document bundle with extracted floor plan material.",
                "property_facts_json": property_facts,
                "media_urls_json": (),
                "floorplan_urls_json": floorplan_urls[:6],
                "source_virtual_tour_url": "",
                "panorama_source": "",
            }
    html = _property_scout_fetch_html_compat(normalized, timeout_seconds=4.0)
    title_match = re.search(r"<title[^>]*>(.*?)</title>", html, re.IGNORECASE | re.DOTALL)
    title = compact_text(title_match.group(1) if title_match else "", fallback="", limit=160)
    og_title = _property_scout_extract_meta_content(html, "og:title")
    og_description = _property_scout_extract_meta_content(html, "og:description")
    meta_description = _property_scout_extract_meta_content(html, "description")
    if _is_willhaben_property_url(normalized) and not willhaben_packet_preview and not (og_title or title):
        try:
            packet = _load_willhaben_property_packet_compat(normalized, timeout_seconds=4)
            property_facts = dict(packet.get("property_facts_json") or {})
            description = compact_text(
                " | ".join(f"{key}: {value}" for key, value in property_facts.items() if str(value or "").strip()),
                fallback="",
                limit=300,
            )
            willhaben_packet_preview = {
                "listing_id": str(packet.get("listing_id") or "").strip(),
                "title": compact_text(str(packet.get("title") or "").strip(), fallback=normalized, limit=160),
                "summary": description,
                "property_facts_json": property_facts,
                "media_urls_json": tuple(str(item or "").strip() for item in list(packet.get("media_urls_json") or []) if str(item or "").strip()),
                "floorplan_urls_json": tuple(str(item or "").strip() for item in list(packet.get("floorplan_urls_json") or []) if str(item or "").strip()),
                "source_virtual_tour_url": str(packet.get("source_virtual_tour_url") or "").strip(),
            }
        except RuntimeError:
            pass
    media_urls = _property_scout_extract_detail_media_urls(source_url=normalized, html=html)
    floorplan_urls = _property_scout_extract_floorplan_urls(source_url=normalized, html=html, resolve_archives=not prefer_fast)
    gallery_floorplan_urls, gallery_floorplan_diagnostics = _property_scout_extract_gallery_floorplan_urls(
        source_url=normalized,
        html=html,
        media_urls=tuple(media_urls),
        resolve_images=not prefer_fast and not floorplan_urls,
    )
    if gallery_floorplan_urls:
        floorplan_urls = tuple(dict.fromkeys([*floorplan_urls, *gallery_floorplan_urls]))
    source_virtual_tour_url = _property_scout_extract_source_virtual_tour_url(source_url=normalized, html=html)
    property_facts = _property_distressed_sale_preview_facts(normalized, html)
    if willhaben_packet_preview:
        packet_facts = dict(willhaben_packet_preview.get("property_facts_json") or {})
        for key, value in packet_facts.items():
            if value not in (None, "", (), []):
                property_facts.setdefault(key, value)
        if not media_urls:
            media_urls = tuple(str(item or "").strip() for item in list(willhaben_packet_preview.get("media_urls_json") or []) if str(item or "").strip())
        if not floorplan_urls:
            floorplan_urls = tuple(str(item or "").strip() for item in list(willhaben_packet_preview.get("floorplan_urls_json") or []) if str(item or "").strip())
        if not source_virtual_tour_url:
            source_virtual_tour_url = str(willhaben_packet_preview.get("source_virtual_tour_url") or "").strip()
    if not prefer_fast and str(property_facts.get("provider_channel") or "").strip() == "justiz_edikte_at":
        for detail_url in _property_scout_extract_context_links(
            source_url=normalized,
            html=html,
            markers=("kurzgutachten", "schätzungsgutachten", "schaetzungsgutachten"),
            limit=2,
        ):
            try:
                detail_html = _property_scout_fetch_html_compat(detail_url, timeout_seconds=4.0)
            except Exception:
                continue
            detail_text = _property_html_fragment_text(detail_html)
            detail_facts = _property_justiz_edikte_facts(detail_url, detail_html, detail_text)
            for key, value in dict(detail_facts or {}).items():
                if value not in (None, "", (), []):
                    property_facts[key] = value
            if property_facts.get("area_sqm"):
                break
    cooperative_facts = _property_cooperative_housing_facts(normalized, html, _property_html_fragment_text(html))
    if cooperative_facts:
        property_facts.update(cooperative_facts)
    international_facts = _property_realestate_international_preview_facts(normalized, html)
    if international_facts:
        property_facts.update({key: value for key, value in international_facts.items() if value not in (None, "", (), [])})
    floorplan_recovery_diagnostics = (
        {}
        if floorplan_urls
        else _property_scout_floorplan_recovery_diagnostics(source_url=normalized, html=html)
    )
    property_facts.update(
        {
            "has_360": bool(source_virtual_tour_url),
            "source_virtual_tour_url": source_virtual_tour_url,
            "panorama_source": urllib.parse.urlparse(source_virtual_tour_url).netloc.lower() if source_virtual_tour_url else "",
            "has_floorplan": bool(floorplan_urls) or bool(property_facts.get("has_floorplan")),
            "floorplan_count": len(floorplan_urls) or int(property_facts.get("floorplan_count") or 0),
            "media_count": len(media_urls) or int(property_facts.get("media_count") or 0),
        }
    )
    if floorplan_urls:
        property_facts["floorplan_urls_json"] = list(floorplan_urls)
        if gallery_floorplan_urls:
            property_facts["floorplan_detection_method"] = "gallery_marker_or_visual_classifier"
    elif floorplan_recovery_diagnostics:
        property_facts["floorplan_recovery_diagnostics"] = floorplan_recovery_diagnostics
    if gallery_floorplan_diagnostics:
        property_facts["gallery_floorplan_diagnostics"] = gallery_floorplan_diagnostics
    summary = _property_preview_summary_from_facts(
        base_summary=og_description or meta_description,
        property_facts=property_facts,
    )
    property_facts = _property_enrich_missing_fact_research(
        facts=property_facts,
        property_url=normalized,
        title=og_title or title or normalized,
        summary=summary,
        source_label=urllib.parse.urlparse(normalized).netloc.lower(),
        floorplan_urls=tuple(floorplan_urls[:6]),
    )
    quiet_signal = _property_quiet_signal_from_floorplan(
        property_facts=property_facts,
        title=og_title or title or normalized,
        summary=summary,
    )
    if str(quiet_signal.get("signal") or "").strip().lower() not in {"", "none"}:
        property_facts["quiet_layout_signal"] = str(quiet_signal.get("signal") or "").strip().lower()
        property_facts["quiet_layout_signal_summary"] = str(quiet_signal.get("summary") or "").strip()
        property_facts["quiet_layout_signal_confidence"] = str(quiet_signal.get("confidence") or "").strip() or "low"
        property_facts["quiet_layout_signal_reason"] = str(quiet_signal.get("reason") or "").strip()
        if isinstance(quiet_signal.get("diagnostics"), dict) and quiet_signal.get("diagnostics"):
            property_facts["quiet_layout_signal_diagnostics"] = dict(quiet_signal.get("diagnostics") or {})
    return {
        "property_url": normalized,
        "listing_id": normalized,
        "title": og_title or title or str(willhaben_packet_preview.get("title") or "") or normalized,
        "summary": summary or str(willhaben_packet_preview.get("summary") or ""),
        "property_facts_json": property_facts,
        "media_urls_json": media_urls[:12],
        "floorplan_urls_json": floorplan_urls[:6],
        "source_virtual_tour_url": source_virtual_tour_url,
        "panorama_source": urllib.parse.urlparse(source_virtual_tour_url).netloc.lower() if source_virtual_tour_url else "",
    }


def _property_scout_page_preview_compat(property_url: str, *, prefer_fast: bool = False) -> dict[str, object]:
    try:
        return _property_scout_page_preview(property_url, prefer_fast=prefer_fast)
    except TypeError as exc:
        if "prefer_fast" not in str(exc):
            raise
        return _property_scout_page_preview(property_url)


def _property_scout_page_preview_with_timeout(property_url: str, *, prefer_fast: bool = False) -> dict[str, object]:
    timeout_seconds = _property_search_preview_timeout_seconds(prefer_fast=prefer_fast)
    result: dict[str, object] = {}
    error: dict[str, BaseException] = {}
    finished = threading.Event()

    def _runner() -> None:
        try:
            result["preview"] = _property_scout_page_preview_compat(property_url, prefer_fast=prefer_fast)
        except BaseException as exc:  # pragma: no cover - surfaced to caller
            error["exc"] = exc
        finally:
            finished.set()

    thread = threading.Thread(
        target=_runner,
        name=f"property-preview:{'fast' if prefer_fast else 'full'}",
        daemon=True,
    )
    thread.start()
    finished.wait(timeout_seconds)
    if not finished.is_set():
        raise TimeoutError(
            f"property_preview_timeout:{'fast' if prefer_fast else 'full'}:{round(timeout_seconds, 2)}"
        )
    if "exc" in error:
        raise error["exc"]
    preview = result.get("preview")
    return dict(preview) if isinstance(preview, dict) else {}


def _property_floorplan_candidate_stage(candidate: dict[str, object]) -> str:
    return str(candidate.get("candidate_stage") or "").strip().lower()



def _property_fact_value_is_weak(value: object) -> bool:
    if value is None:
        return True
    if value is False:
        return True
    if isinstance(value, (int, float)):
        return float(value) <= 0.0
    if isinstance(value, str):
        return not value.strip()
    if isinstance(value, (list, tuple)):
        if not value:
            return True
        return all(_property_fact_value_is_weak(item) for item in value)
    if isinstance(value, dict):
        return not value
    return False


@lru_cache(maxsize=256)
def _property_source_research_snapshot(property_url: str, image_urls: tuple[str, ...] = ()) -> dict[str, object]:
    normalized = urllib.parse.urldefrag(str(property_url or "").strip())[0]
    if not normalized:
        return {}
    try:
        preview = _property_scout_page_preview(normalized, prefer_fast=True)
    except Exception:
        preview = {}
    facts = dict(preview.get("property_facts_json") or {}) if isinstance(preview, dict) else {}
    title = str(preview.get("title") or "").strip() if isinstance(preview, dict) else ""
    summary = str(preview.get("summary") or "").strip() if isinstance(preview, dict) else ""
    if title or summary:
        try:
            facts = _property_enrich_facts_from_listing_text(
                facts=facts,
                title=title,
                summary=summary,
                listing_mode="buy",
                property_url=normalized,
            )
        except Exception:
            facts = dict(facts or {})
    if image_urls and "floorplan_urls_json" not in facts:
        facts["floorplan_urls_json"] = [value for value in image_urls if str(value or "").strip()]
    try:
        source_html = _property_scout_fetch_html_compat(normalized, timeout_seconds=4.0)
    except Exception:
        source_html = ""
    plain_text = _property_html_fragment_text(source_html)
    lowered_text = plain_text.lower()
    if "genossenschaften_at" == str(facts.get("provider_group") or "").strip().lower():
        amount_match = re.search(r"finanzierungsbeitrag[^0-9]*([0-9][0-9\.\, ]+)", plain_text, flags=re.IGNORECASE)
        if amount_match:
            try:
                facts["finanzierungsbeitrag_eur"] = int(float(amount_match.group(1).replace(" ", "").replace(".", "").replace(",", ".")))
            except Exception:
                pass
        if any(marker in lowered_text for marker in ("miete mit kaufoption", "mietkauf", "kaufoption")):
            facts["miete_mit_kaufoption_available"] = True
        if "energieausweis" in lowered_text:
            facts["energy_certificate_present"] = True
        if "betriebskosten" in lowered_text:
            facts["operating_costs_present"] = True
        if any(marker in lowered_text for marker in ("ganztagsvolksschule", "ganztag", "ganztags")):
            facts["ganztag_signal"] = True
        if any(marker in lowered_text for marker in ("fernwärme", "fernwaerme")):
            facts["heating_type"] = "District heating"
        deadline_match = re.search(r"anmeldung\s+bis\s+(\d{2})\.(\d{2})\.(\d{4})", plain_text, flags=re.IGNORECASE)
        if deadline_match:
            deadline_iso = f"{deadline_match.group(3)}-{deadline_match.group(2)}-{deadline_match.group(1)}"
            facts["application_deadline"] = deadline_iso
            try:
                deadline_date = datetime.fromisoformat(f"{deadline_iso}T00:00:00+00:00")
                facts["application_window_days"] = max(1, int((deadline_date - datetime.now(timezone.utc)).total_seconds() // 86400))
            except Exception:
                pass
    ocr_hint: dict[str, object] = {}
    if image_urls and not any(facts.get(key) for key in ("street_address", "exact_address", "map_lat", "map_lng")):
        try:
            ocr_hint = _property_image_ocr_address_hint(
                image_urls,
                source_text=" | ".join(part for part in (title, summary) if part),
                property_url=normalized,
            )
        except Exception:
            ocr_hint = {}
    if ocr_hint:
        for key, value in ocr_hint.items():
            if value not in (None, "", (), [], {}):
                facts[key] = value
    research_lat = _float_or_none(facts.get("map_lat"))
    research_lng = _float_or_none(facts.get("map_lng"))
    if isinstance(research_lat, float) and isinstance(research_lng, float):
        try:
            nearby = _property_research_nearby_pois(research_lat, research_lng)
        except Exception:
            nearby = {}
        if isinstance(nearby, dict):
            for key, value in nearby.items():
                if value not in (None, "", (), [], {}) and _property_fact_value_is_weak(facts.get(key)):
                    facts[key] = value
    facts = _property_enrich_official_risk_evidence(facts)
    if not facts:
        return {}
    return {key: value for key, value in facts.items() if not _property_fact_value_is_weak(value)}


def _property_image_ocr_address_hint(image_urls: tuple[str, ...], *, source_text: str = "", property_url: str = "") -> dict[str, object]:
    if not image_urls or Image is None or pytesseract is None or not shutil.which("tesseract"):
        return {}
    normalized_source_text = " ".join(str(source_text or "").split())
    lowered_source_text = normalized_source_text.lower()
    parsed_property_url = urllib.parse.urlparse(str(property_url or "").strip())
    expected_postcodes = set(re.findall(r"\b(\d{4})\b", normalized_source_text))
    expected_city = "Wien" if "wien" in lowered_source_text else ""
    expected_country = "Österreich" if parsed_property_url.netloc.lower().endswith(".at") else ""
    street_tokens = (
        "straße",
        "strasse",
        "gasse",
        "weg",
        "platz",
        "allee",
        "kai",
        "ring",
        "zeile",
        "steig",
    )
    candidate_queries: list[str] = []
    seen_queries: set[str] = set()
    for image_url in image_urls[:6]:
        try:
            request = urllib.request.Request(str(image_url), headers={"User-Agent": _PROPERTY_SCOUT_USER_AGENT})
            with urllib.request.urlopen(request, timeout=8.0) as response:
                content_type = str(response.headers.get("Content-Type") or "").lower()
                content_length = int(response.headers.get("Content-Length") or "0")
                if content_type and not content_type.startswith("image/"):
                    continue
                if content_length > 10_000_000:
                    continue
                content = response.read()
        except (urllib.error.URLError, TimeoutError, ValueError):
            continue
        try:
            image = Image.open(io.BytesIO(content))
            gray = image.convert("L")
            text = pytesseract.image_to_string(gray, config="--psm 11")
        except Exception:
            continue
        for raw_line in text.splitlines():
            line = " ".join(str(raw_line or "").split())
            lowered = line.lower()
            if not line or not any(token in lowered for token in street_tokens):
                continue
            normalized = re.sub(r"[^0-9A-Za-zÄÖÜäöüß .,/\\-]", " ", line)
            normalized = " ".join(normalized.split())
            if not re.search(r"\d", normalized):
                continue
            search_query = normalized
            context_suffix = " ".join(part for part in (expected_city, expected_country) if part).strip()
            if context_suffix and expected_city.lower() not in normalized.lower() and expected_country.lower() not in normalized.lower():
                search_query = f"{normalized}, {context_suffix}"
            if search_query.lower() in seen_queries:
                continue
            seen_queries.add(search_query.lower())
            candidate_queries.append(search_query)
    for query in candidate_queries:
        geocoded = _property_research_forward_geocode(query)
        try:
            lat = float(geocoded.get("lat"))
            lon = float(geocoded.get("lon"))
        except (TypeError, ValueError):
            continue
        reverse = _property_research_reverse_geocode(lat, lon)
        address = dict(reverse.get("address") or {}) if isinstance(reverse.get("address"), dict) else {}
        road = str(address.get("road") or "").strip()
        house_number = str(address.get("house_number") or "").strip()
        if not road or not house_number:
            continue
        postcode = str(address.get("postcode") or "").strip()
        city = str(address.get("city") or address.get("town") or address.get("village") or "").strip()
        if expected_postcodes and postcode and postcode not in expected_postcodes:
            continue
        if expected_city and city and expected_city.lower() not in city.lower():
            continue
        findings: dict[str, object] = {
            "map_lat": lat,
            "map_lng": lon,
            "street_address": f"{road} {house_number}",
        }
        address_line_2 = " ".join(part for part in (postcode, city) if part).strip()
        findings["address_lines"] = [findings["street_address"], address_line_2] if address_line_2 else [findings["street_address"]]
        display_name = str(reverse.get("display_name") or geocoded.get("display_name") or "").strip()
        if display_name:
            findings["exact_address"] = display_name
        findings.update(_property_research_nearby_pois(lat, lon))
        return findings
    return {}










def _merge_property_facts_with_source_research(
    *,
    property_url: str,
    property_facts: dict[str, object],
    image_urls: tuple[str, ...] = (),
) -> dict[str, object]:
    merged = dict(property_facts or {})
    research = _property_source_research_snapshot(property_url, image_urls)
    if research:
        for key, value in research.items():
            existing = merged.get(key)
            if _property_fact_value_is_weak(existing):
                merged[key] = value
        merged["listing_research_snapshot"] = dict(research)
        merged["listing_research_meta"] = {
            "captured_at": _now_iso(),
            "source_url": str(property_url or "").strip(),
            "field_count": len(research),
            "strategy": "provider_html_plus_geo",
        }
    merged = _property_enrich_official_risk_evidence(merged)
    return _property_enrich_missing_fact_research(
        facts=merged,
        property_url=property_url,
        floorplan_urls=tuple(_property_nonempty_sequence(merged.get("floorplan_urls_json"))) or image_urls,
    )


def _property_scout_candidate_payload_from_preview(*, property_url: str, preview: dict[str, object]) -> dict[str, object]:
    normalized = urllib.parse.urldefrag(str(property_url or "").strip())[0]
    property_facts = dict(preview.get("property_facts_json") or {})
    title = str(preview.get("title") or "").strip()
    summary = str(preview.get("summary") or "").strip()
    text = " ".join(part for part in (title, summary, normalized) if part).lower()
    if "district" not in property_facts:
        for candidate in ("waehring", "währing", "doebling", "döbling", "1180", "1190"):
            if candidate in text:
                property_facts["district"] = candidate
                break
    if "has_360" not in property_facts:
        property_facts["has_360"] = any(token in text for token in ("360", "panorama", "photosphere", "rundgang"))
    if "has_floorplan" not in property_facts:
        property_facts["has_floorplan"] = _property_facts_have_floorplan(property_facts, preview=preview) or any(
            token in text for token in ("grundriss", "floor plan", "floorplan", "lageplan", "raumskizze", "plan_top")
        )
    if "floorplan_urls_json" not in property_facts:
        floorplan_urls = _property_nonempty_sequence(preview.get("floorplan_urls_json")) or _property_nonempty_sequence(
            preview.get("floorplan_urls")
        )
        if floorplan_urls:
            property_facts["floorplan_urls_json"] = floorplan_urls
    if "lift" not in property_facts:
        property_facts["lift"] = any(token in text for token in ("lift", "aufzug"))
    if "heating_type" not in property_facts:
        if "gas" in text or "gasheizung" in text:
            property_facts["heating_type"] = "Gasheizung"
        elif "fernwärme" in text or "fernwaerme" in text:
            property_facts["heating_type"] = "Fernwaerme"
    return _property_enrich_missing_fact_research(
        facts=property_facts,
        property_url=property_url,
        title=title,
        summary=summary,
        floorplan_urls=tuple(_property_nonempty_sequence(property_facts.get("floorplan_urls_json"))),
    )


def _property_investment_price_eur(facts: dict[str, object]) -> float | None:
    def _parse_money_like(value: object) -> float | None:
        text = str(value or "").strip()
        if not text:
            return None
        match = re.search(r"([0-9][0-9\.\,\s]*)(?:\s*,-)?", text)
        if not match:
            return None
        number_text = str(match.group(1) or "").replace(" ", "").strip(".,")
        if not number_text:
            return None
        if "." in number_text and "," in number_text:
            number_text = number_text.replace(".", "").replace(",", ".")
        elif "," in number_text:
            integer_part, decimal_part = number_text.rsplit(",", 1)
            number_text = integer_part + decimal_part if len(decimal_part) == 3 else integer_part + "." + decimal_part
        elif number_text.count(".") > 1:
            number_text = number_text.replace(".", "")
        elif "." in number_text:
            integer_part, decimal_part = number_text.rsplit(".", 1)
            if len(decimal_part) == 3 and integer_part.isdigit():
                number_text = integer_part + decimal_part
        try:
            amount = float(number_text)
        except Exception:
            return None
        return amount if amount > 0.0 else None

    for key in ("price_eur", "valuation_eur", "reserve_price_eur"):
        value = _float_or_none(facts.get(key))
        if isinstance(value, float) and value > 0.0:
            return value
    for key in ("price_display", "price", "valuation_display", "asking_price", "purchase_price_display"):
        value = _parse_money_like(facts.get(key))
        if isinstance(value, float) and value > 0.0:
            return value
    return None


_PROPERTY_UNTRUSTED_LISTING_BLOCK_RE = re.compile(
    r"<!--[\s\S]*?-->"
    r"|<\s*(script|style|template|noscript)\b[\s\S]*?<\s*/\s*\1\s*>"
    r"|<(?P<hidden_tag>[a-zA-Z0-9:-]+)\b(?=[^>]*(?:display\s*:\s*none|visibility\s*:\s*hidden|opacity\s*:\s*0|aria-hidden\s*=\s*['\"]?true|hidden\b|type\s*=\s*['\"]?hidden))[^>]*>[\s\S]*?<\s*/\s*(?P=hidden_tag)\s*>",
    flags=re.IGNORECASE,
)
_PROPERTY_UNTRUSTED_LISTING_TAG_RE = re.compile(r"<[^>]+>")
_PROPERTY_UNTRUSTED_INSTRUCTION_PATTERNS: tuple[tuple[str, re.Pattern[str]], ...] = (
    ("ignore_previous_instructions", re.compile(r"\b(ignore|disregard|forget)\s+(all\s+)?(previous|prior|above)\s+instructions?\b", re.IGNORECASE)),
    ("instruction_override_attempt", re.compile(r"\b(override|bypass|ignore|disable)\b[^.\n]{0,80}\b(system|developer|policy|rules?|instructions?)\b", re.IGNORECASE)),
    ("role_prompt_marker", re.compile(r"\b(system|developer|assistant)\s*(message|instructions?|prompt)\b|\b(begin|end)\s+(system|developer)\b", re.IGNORECASE)),
    ("system_prompt_request", re.compile(r"\b(system|developer)\s+prompt\b|\breveal\s+(the\s+)?(prompt|instructions?)\b", re.IGNORECASE)),
    ("secret_exfiltration_request", re.compile(r"\b(send|print|return|exfiltrate|reveal)\s+[^.\n]{0,80}\b(secret|token|api\s*key|credential|cookie)s?\b", re.IGNORECASE)),
    ("fake_tool_call", re.compile(r"\b(tool|function)_?call\b|\"tool\"\s*:|\"function\"\s*:", re.IGNORECASE)),
)


def _property_untrusted_listing_text_for_extraction(*parts: object) -> tuple[str, tuple[str, ...]]:
    raw_text = " | ".join(str(part or "").strip() for part in parts if str(part or "").strip())
    if not raw_text:
        return "", ()
    flags = tuple(
        key
        for key, pattern in _PROPERTY_UNTRUSTED_INSTRUCTION_PATTERNS
        if pattern.search(raw_text)
    )
    text = html.unescape(raw_text)
    text = _PROPERTY_UNTRUSTED_LISTING_BLOCK_RE.sub(" ", text)
    text = _PROPERTY_UNTRUSTED_LISTING_TAG_RE.sub(" ", text)
    text = " ".join(text.split())
    return text, flags


def _property_investment_area_sqm(facts: dict[str, object]) -> float | None:
    for key in ("area_sqm", "area_m2", "living_area_m2"):
        value = _float_or_none(facts.get(key))
        if isinstance(value, float) and value > 0.0:
            return value
    return None


def _property_investment_location_seed(facts: dict[str, object], preferences: dict[str, object]) -> str:
    for key in ("postal_name", "street_address", "district", "address"):
        value = str(facts.get(key) or "").strip()
        if value:
            return value
    return str(preferences.get("location_query") or "").strip()


def _property_url_location_conflicts_with_source_scope(*, property_url: object, facts: dict[str, object]) -> bool:
    parsed = urllib.parse.urlparse(str(property_url or "").strip())
    path = urllib.parse.unquote(str(parsed.path or "").strip()).casefold()
    if not path:
        return False
    try:
        has_location_probe = _property_candidate_url_has_location_probe(str(property_url or ""))
    except Exception:
        has_location_probe = bool(re.search(r"\b\d{4,5}\b", path))
    if not has_location_probe:
        return False
    source_codes = _property_source_scope_postal_codes(facts)
    url_codes = set(re.findall(r"\b\d{4,5}\b", path))
    if url_codes:
        return not source_codes or bool(url_codes - set(source_codes))
    normalized_path = re.sub(r"[\s,;|/\\()[\]{}._-]+", " ", path).strip()
    source_postal_code = _property_postal_code_core(facts.get("source_postal_code"))
    source_city = str(facts.get("source_city") or "").strip().casefold()
    scope_candidates = {
        str(facts.get("source_scope_location") or "").strip().casefold(),
        source_city,
        " ".join(part for part in (source_postal_code, source_city) if part).strip().casefold(),
    }
    scope_candidates = {value for value in scope_candidates if value and not value.isdigit()}
    if scope_candidates and any(value in normalized_path for value in scope_candidates):
        return False
    return True


def _property_clear_source_scope_location_placeholders_for_url(
    *,
    facts: dict[str, object],
    property_url: object,
) -> dict[str, object]:
    enriched = dict(facts or {})
    if not _property_url_location_conflicts_with_source_scope(property_url=property_url, facts=enriched):
        return enriched
    cleared = False
    for key in ("postal_name", "address", "district", "location", "city"):
        if _property_location_value_is_source_scope_placeholder(enriched.get(key), enriched):
            enriched.pop(key, None)
            cleared = True
    if cleared:
        enriched["source_scope_location_placeholder_cleared"] = True
        enriched.setdefault("listing_location_evidence_kind", "url_region")
    return enriched


def _property_enrich_facts_from_listing_text(
    *,
    facts: dict[str, object],
    title: str,
    summary: str,
    listing_mode: str,
    property_url: object = "",
) -> dict[str, object]:
    enriched = dict(facts or {})
    text, instruction_flags = _property_untrusted_listing_text_for_extraction(title, summary)
    if not text:
        return _property_clear_source_scope_location_placeholders_for_url(
            facts=enriched,
            property_url=property_url,
        )
    if instruction_flags:
        enriched["untrusted_listing_instruction_detected"] = True
        enriched["untrusted_listing_instruction_flags"] = list(instruction_flags[:8])
        enriched.setdefault("listing_text_trust_boundary", "external_content_data_only")
    price_match = re.search(r"(?:€|EUR)\s*([\d\.\s]+(?:,\d+)?)", text, flags=re.IGNORECASE)
    if price_match:
        raw_amount = str(price_match.group(1) or "").strip().replace(" ", "")
        normalized_amount = raw_amount.replace(".", "").replace(",", ".")
        try:
            amount = float(normalized_amount)
        except Exception:
            amount = 0.0
        if amount > 0.0:
            if listing_mode == "rent":
                enriched.setdefault("total_rent_eur", amount)
                enriched.setdefault("rent_display", compact_text(price_match.group(0), fallback=f"EUR {amount:.0f}", limit=120))
            else:
                enriched.setdefault("price_eur", amount)
                enriched.setdefault("price_display", compact_text(price_match.group(0), fallback=f"EUR {amount:.0f}", limit=120))
    area_matches = re.findall(r"(\d+(?:[.,]\d+)?)\s*m[²2]", text, flags=re.IGNORECASE)
    if area_matches and "area_sqm" not in enriched and "area_m2" not in enriched and "living_area_m2" not in enriched:
        try:
            area_value = max(float(str(raw or "").replace(",", ".")) for raw in area_matches)
            if area_value > 0.0:
                enriched["area_m2"] = area_value
        except Exception:
            pass
    rooms_match = re.search(r"(\d+(?:[.,]\d+)?)\s*[- ]?Zimmer", text, flags=re.IGNORECASE)
    if rooms_match and "rooms" not in enriched and "room_count" not in enriched:
        try:
            enriched["rooms"] = float(str(rooms_match.group(1) or "").replace(",", "."))
        except Exception:
            pass
    postal_evidence = _property_postal_location_evidence(text)
    if postal_evidence:
        existing_evidence = [
            dict(item)
            for item in list(enriched.get("listing_postal_evidence") or [])
            if isinstance(item, dict)
        ]
        enriched["listing_postal_evidence"] = [*existing_evidence, *[dict(row) for row in postal_evidence]][:8]
        postal_name = str(postal_evidence[0].get("postal_name") or "").strip()[:160]
        source_scope_candidates = {
            str(enriched.get("source_scope_location") or "").strip().casefold(),
            " ".join(
                str(enriched.get(key) or "").strip()
                for key in ("source_postal_code", "source_city")
                if str(enriched.get(key) or "").strip()
            ).casefold(),
        }
        source_scope_candidates.discard("")
        current_postal_name = str(enriched.get("postal_name") or "").strip()
        current_address = str(enriched.get("address") or "").strip()
        if postal_name and (
            not current_postal_name
            or current_postal_name.casefold() in source_scope_candidates
            or _property_postal_code_core(current_postal_name) in _property_source_scope_postal_codes(enriched)
        ):
            enriched["postal_name"] = postal_name
        if postal_name and (not current_address or current_address.casefold() in source_scope_candidates):
            enriched.setdefault("address", postal_name)
            if current_address.casefold() in source_scope_candidates:
                enriched["address"] = postal_name
    return _property_clear_source_scope_location_placeholders_for_url(
        facts=enriched,
        property_url=property_url,
    )


def _property_investment_location_match_score(
    *,
    location_query: str,
    title: str,
    summary: str,
    facts: dict[str, object],
) -> int:
    normalized_query = compact_text(str(location_query or "").strip().lower(), fallback="", limit=160)
    if not normalized_query:
        return 1
    location_text = " ".join(
        part
        for part in (
            str(title or "").strip(),
            str(summary or "").strip(),
            str(facts.get("postal_name") or "").strip(),
            str(facts.get("district") or "").strip(),
            str(facts.get("street_address") or facts.get("address") or "").strip(),
        )
        if part
    ).lower()
    if not location_text:
        return 0
    postal_codes = re.findall(r"\b\d{4}\b", normalized_query)
    if postal_codes and any(postal in location_text for postal in postal_codes):
        return 3
    city_tokens = [
        token
        for token in re.split(r"[^a-zA-ZäöüÄÖÜß]+", normalized_query)
        if len(token) >= 4 and not token.isdigit()
    ]
    if city_tokens and any(token in location_text for token in city_tokens):
        return 2
    if any(token in location_text for token in ("wien", "vienna")) and any(token in normalized_query for token in ("wien", "vienna")):
        return 2
    return 0


def _property_investment_comp_samples(
    *,
    property_url: str,
    country_code: str,
    listing_mode: str,
    location_query: str,
    selected_platforms: tuple[str, ...],
    max_samples: int,
) -> list[dict[str, object]]:
    deadline = time.monotonic() + 20.0
    preferences = normalize_property_search_preferences(
        {
            "country_code": country_code,
            "listing_mode": listing_mode,
            "property_type": "apartment",
            "location_query": location_query,
            "keywords": "",
            "selected_platforms": list(selected_platforms),
        }
    )
    source_specs = generated_property_source_specs(
        preferences=preferences,
        selected_platforms=tuple(selected_platforms),
    )[: min(max(2, len(selected_platforms) or 2), 3)]
    normalized_current = urllib.parse.urldefrag(str(property_url or "").strip())[0]
    seen_urls: set[str] = {normalized_current}
    scored_samples: list[tuple[int, dict[str, object]]] = []
    for source in source_specs:
        if time.monotonic() >= deadline:
            break
        source_url = str(source.get("url") or "").strip()
        if not source_url:
            continue
        try:
            source_html = _property_scout_fetch_html(source_url, timeout_seconds=4.0)
        except Exception:
            continue
        listing_urls = _property_scout_extract_listing_urls(source_url=source_url, html=source_html)[: max(24, max_samples * 8)]
        for candidate_url in listing_urls:
            if time.monotonic() >= deadline:
                break
            normalized_candidate = urllib.parse.urldefrag(str(candidate_url or "").strip())[0]
            if not normalized_candidate or normalized_candidate in seen_urls:
                continue
            seen_urls.add(normalized_candidate)
            try:
                preview = _property_scout_page_preview(normalized_candidate, prefer_fast=True)
            except Exception:
                continue
            if not preview:
                continue
            preview_facts = _property_enrich_facts_from_listing_text(
                facts=dict(preview.get("property_facts_json") or {}),
                title=str(preview.get("title") or "").strip(),
                summary=str(preview.get("summary") or "").strip(),
                listing_mode=listing_mode,
                property_url=normalized_candidate,
            )
            location_score = _property_investment_location_match_score(
                location_query=location_query,
                title=str(preview.get("title") or "").strip(),
                summary=str(preview.get("summary") or "").strip(),
                facts=preview_facts,
            )
            if location_score <= 0:
                continue
            try:
                enriched = _merge_property_facts_with_source_research(
                    property_url=normalized_candidate,
                    property_facts=preview_facts,
                    image_urls=tuple(str(value or "").strip() for value in (preview.get("media_urls_json") or ()) if str(value or "").strip()),
                )
            except Exception:
                enriched = dict(preview_facts)
            area_sqm = _property_investment_area_sqm(enriched)
            if not isinstance(area_sqm, float) or area_sqm <= 0.0:
                continue
            amount = _float_or_none(enriched.get("total_rent_eur") if listing_mode == "rent" else _property_investment_price_eur(enriched))
            if not isinstance(amount, float) or amount <= 0.0:
                continue
            per_sqm = round(amount / area_sqm, 2)
            sample = {
                "property_url": normalized_candidate,
                "title": str(preview.get("title") or normalized_candidate).strip() or normalized_candidate,
                "source_label": str(source.get("label") or source.get("platform") or "Source").strip() or "Source",
                "amount_eur": round(amount, 2),
                "area_sqm": round(area_sqm, 2),
                "per_sqm_eur": per_sqm,
            }
            scored_samples.append((location_score, sample))
            if len(scored_samples) >= max_samples and all(score >= 3 for score, _ in scored_samples[-max_samples:]):
                break
    if not scored_samples:
        return []
    scored_samples.sort(key=lambda item: (item[0], -abs(float(item[1].get("area_sqm") or 0.0))), reverse=True)
    best_score = max(score for score, _ in scored_samples)
    filtered = [sample for score, sample in scored_samples if score == best_score]
    return filtered[:max_samples]


@lru_cache(maxsize=128)
def _property_investment_research_snapshot(
    *,
    property_url: str,
    country_code: str,
    location_query: str,
    selected_platforms_csv: str,
    current_price_eur: float,
    current_area_sqm: float,
    research_level: str,
) -> dict[str, object]:
    if not property_url or not country_code or current_price_eur <= 0.0 or current_area_sqm <= 0.0:
        return {}
    selected_platforms = tuple(
        normalize_property_platform(value)
        for value in str(selected_platforms_csv or "").split(",")
        if normalize_property_platform(value)
    )
    if not selected_platforms:
        rent_defaults = tuple(default_platforms_for_country_listing_mode(country_code, "rent")[:2])
        buy_defaults = tuple(default_platforms_for_country_listing_mode(country_code, "buy")[:4])
        selected_platforms = tuple(dict.fromkeys(rent_defaults + buy_defaults))[:4]
    sample_limit = 2 if research_level == "preview" else 5
    rent_samples = _property_investment_comp_samples(
        property_url=property_url,
        country_code=country_code,
        listing_mode="rent",
        location_query=location_query,
        selected_platforms=selected_platforms,
        max_samples=sample_limit,
    )
    buy_samples = _property_investment_comp_samples(
        property_url=property_url,
        country_code=country_code,
        listing_mode="buy",
        location_query=location_query,
        selected_platforms=selected_platforms,
        max_samples=sample_limit,
    )
    current_price_per_sqm = round(current_price_eur / current_area_sqm, 2)
    rent_per_sqm_samples = [float(sample["per_sqm_eur"]) for sample in rent_samples if sample.get("per_sqm_eur") not in (None, "")]
    buy_per_sqm_samples = [float(sample["per_sqm_eur"]) for sample in buy_samples if sample.get("per_sqm_eur") not in (None, "")]
    snapshot: dict[str, object] = {
        "current_price_eur": round(current_price_eur, 2),
        "current_area_sqm": round(current_area_sqm, 2),
        "current_price_per_sqm_eur": current_price_per_sqm,
        "rent_sample_count": len(rent_samples),
        "buy_sample_count": len(buy_samples),
        "rent_samples": rent_samples,
        "buy_samples": buy_samples,
        "research_level": research_level,
    }
    if buy_per_sqm_samples:
        median_buy = round(float(statistics.median(buy_per_sqm_samples)), 2)
        snapshot["market_buy_per_sqm_eur"] = median_buy
        snapshot["market_buy_delta_pct"] = round(((current_price_per_sqm / median_buy) - 1.0) * 100.0, 1)
    if rent_per_sqm_samples:
        median_rent = round(float(statistics.median(rent_per_sqm_samples)), 2)
        expected_rent = round(median_rent * current_area_sqm, 2)
        annual_rent = round(expected_rent * 12.0, 2)
        gross_yield = round((annual_rent / current_price_eur) * 100.0, 2) if current_price_eur > 0 else 0.0
        payback_years = round(current_price_eur / annual_rent, 1) if annual_rent > 0 else 0.0
        snapshot.update(
            {
                "market_rent_per_sqm_eur": median_rent,
                "expected_monthly_rent_eur": expected_rent,
                "expected_annual_rent_eur": annual_rent,
                "gross_yield_pct": gross_yield,
                "payback_years": payback_years,
            }
        )
    return snapshot


