def _property_search_goal(preferences: dict[str, object] | None) -> str:
    value = str(dict(preferences or {}).get("search_goal") or "").strip().lower() or "home"
    return value if value in {"home", "investment"} else "home"


def _property_investment_strategy(preferences: dict[str, object] | None) -> str:
    value = str(dict(preferences or {}).get("investment_strategy") or "").strip().lower() or "best_overall"
    return value if value in {"best_overall", "cash_flow", "appreciation", "undervalued", "low_risk"} else "best_overall"


def _property_investment_min_gross_yield_pct(preferences: dict[str, object] | None) -> float:
    try:
        return max(0.0, min(15.0, float(str(dict(preferences or {}).get("min_gross_yield_pct") or "").strip())))
    except Exception:
        return 0.0


def _property_investment_score_bucket(score: float) -> str:
    value = max(0.0, min(float(score or 0.0), 100.0))
    if value >= 78.0:
        return "strong"
    if value >= 62.0:
        return "good"
    if value >= 45.0:
        return "mixed"
    return "weak"


def _property_investment_score_bucket_label(score: float) -> str:
    return {
        "strong": "Strong",
        "good": "Solid",
        "mixed": "Mixed",
        "weak": "Weak",
    }.get(_property_investment_score_bucket(score), "Mixed")


def _property_investment_dimension_tooltips() -> dict[str, str]:
    return {
        "return": "Return weighs gross yield, rent evidence, and how quickly the current price can be earned back on gross rent assumptions.",
        "value": "Value compares this buy price per square meter against local buy comparables. Below-median pricing scores better.",
        "demand": "Demand estimates whether the micro-location should keep attracting renters or buyers using transport, daily-life access, and longer-term area context.",
        "liquidity": "Liquidity estimates how easy this should be to exit or re-let without waiting on a thin market.",
        "risk": "Risk control penalizes legal complexity, climate and burden flags, unclear tenant posture, and documentation gaps.",
        "execution": "Execution measures how much work is still needed before this is truly actionable: floorplans, tenant clarity, CAPEX, and renovation friction.",
        "evidence": "Evidence confidence measures how much of this underwriting read is actually proven by comps, documents, and structured signals.",
    }


def _property_investment_underwriting_payload(
    *,
    title: str,
    summary: str,
    facts: dict[str, object],
    preferences: dict[str, object],
    snapshot: dict[str, object] | None,
) -> dict[str, object]:
    snapshot_json = dict(snapshot or {})
    gross_yield_pct = _float_or_none(snapshot_json.get("gross_yield_pct"))
    market_delta_pct = _float_or_none(snapshot_json.get("market_buy_delta_pct"))
    expected_monthly_rent_eur = _float_or_none(snapshot_json.get("expected_monthly_rent_eur"))
    payback_years = _float_or_none(snapshot_json.get("payback_years"))
    current_price_per_sqm = _float_or_none(snapshot_json.get("current_price_per_sqm_eur"))
    market_buy_per_sqm = _float_or_none(snapshot_json.get("market_buy_per_sqm_eur"))
    market_rent_per_sqm = _float_or_none(snapshot_json.get("market_rent_per_sqm_eur"))
    buy_sample_count = max(0, int(snapshot_json.get("buy_sample_count") or 0))
    rent_sample_count = max(0, int(snapshot_json.get("rent_sample_count") or 0))
    floorplan_ready = bool(
        facts.get("has_floorplan")
        or facts.get("floorplan_count")
        or facts.get("floorplans_count")
        or facts.get("floorplan_urls_json")
    )
    legal_complexity = _property_candidate_has_investment_legal_complexity(title=title, summary=summary, facts=facts)
    tenant_clarity = any(
        str(facts.get(key) or "").strip()
        for key in ("tenant_status", "occupancy_status", "rental_status", "vacant")
    )
    heavy_renovation = _property_candidate_needs_major_renovation(title=title, summary=summary, facts=facts)
    future_research = dict(facts.get("future_change_research") or {}) if isinstance(facts.get("future_change_research"), dict) else {}
    official_risk_evidence = dict(facts.get("official_risk_evidence") or {}) if isinstance(facts.get("official_risk_evidence"), dict) else {}
    official_risk_sources = [
        dict(row)
        for row in list(official_risk_evidence.get("sources") or [])
        if isinstance(row, dict)
    ]
    official_risk_keys = {
        str(row.get("risk_key") or "").strip().lower()
        for row in official_risk_sources
        if str(row.get("risk_key") or "").strip()
    }
    missing_fact_items = list(dict(facts.get("missing_fact_research") or {}).get("items") or []) if isinstance(facts.get("missing_fact_research"), dict) else []
    transit_m = min(
        value
        for value in (
            _float_or_none(facts.get("nearest_subway_m")),
            _float_or_none(facts.get("nearest_tram_bus_m")),
        )
        if isinstance(value, float) and value >= 0.0
    ) if any(isinstance(_float_or_none(facts.get(key)), float) and _float_or_none(facts.get(key)) >= 0.0 for key in ("nearest_subway_m", "nearest_tram_bus_m")) else None
    supermarket_m = _float_or_none(facts.get("nearest_supermarket_m"))
    medical_m = _float_or_none(facts.get("nearest_medical_care_m"))
    school_context = property_school_context_summary(future_research) or property_school_context_summary(facts)
    planning_confidence = str(future_research.get("planning_confidence") or "").strip().lower()
    investment_impact = str(future_research.get("investment_impact") or "").strip().lower()
    value_drivers = [str(item or "").strip() for item in list(future_research.get("future_value_drivers") or []) if str(item or "").strip()]
    value_risks = [str(item or "").strip() for item in list(future_research.get("future_value_risks") or []) if str(item or "").strip()]
    source_trust_tier = str(facts.get("source_trust_tier") or "").strip().lower()
    source_access_level = str(facts.get("source_access_level") or "").strip().lower()
    source_confidence_bonus = 0.0
    if source_trust_tier == "high":
        source_confidence_bonus += 8.0
    elif source_trust_tier == "medium":
        source_confidence_bonus += 4.0
    if source_access_level in {"direct", "verified"}:
        source_confidence_bonus += 4.0
    energy_certificate_present = bool(facts.get("energy_certificate_present"))
    has_360 = bool(facts.get("has_360") or facts.get("source_virtual_tour_url"))
    location_confident = bool(facts.get("map_lat") and facts.get("map_lng"))
    external_model = property_investment_external_snapshot(
        country_code=str(preferences.get("country_code") or facts.get("country_code") or "AT").strip() or "AT",
        property_url=str(facts.get("property_url") or facts.get("source_url") or "").strip(),
        title=title,
        facts=facts,
        preferences=preferences,
        snapshot=snapshot_json,
    )
    net_yield_pct = _float_or_none(external_model.get("net_yield_pct"))
    cap_rate_pct = _float_or_none(external_model.get("cap_rate_pct"))
    cash_on_cash_yield_pct = _float_or_none(external_model.get("cash_on_cash_yield_pct"))
    dscr = _float_or_none(dict(external_model.get("financing") or {}).get("dscr")) if isinstance(external_model.get("financing"), dict) else None
    external_confidence_label = str(external_model.get("confidence_label") or "").strip()
    feed_status_label = str(external_model.get("feed_status_label") or "").strip()
    feed_status_detail = str(external_model.get("feed_status_detail") or "").strip()

    def _clamp(value: float) -> float:
        return round(max(0.0, min(float(value or 0.0), 100.0)), 1)

    return_score = 40.0
    if isinstance(gross_yield_pct, float) and gross_yield_pct > 0.0:
        if gross_yield_pct >= 7.0:
            return_score = 88.0
        elif gross_yield_pct >= 5.5:
            return_score = 77.0
        elif gross_yield_pct >= 4.5:
            return_score = 68.0
        elif gross_yield_pct >= 3.5:
            return_score = 56.0
        elif gross_yield_pct >= 2.5:
            return_score = 44.0
        else:
            return_score = 30.0
        if isinstance(payback_years, float) and payback_years > 0.0:
            if payback_years <= 18.0:
                return_score += 8.0
            elif payback_years >= 30.0:
                return_score -= 8.0
    else:
        return_score = 22.0
    if rent_sample_count >= 4:
        return_score += 6.0
    elif rent_sample_count == 0:
        return_score -= 8.0
    if isinstance(net_yield_pct, float):
        if net_yield_pct >= 5.0:
            return_score += 10.0
        elif net_yield_pct >= 3.75:
            return_score += 5.0
        elif net_yield_pct < 2.25:
            return_score -= 10.0
    if isinstance(cash_on_cash_yield_pct, float):
        if cash_on_cash_yield_pct >= 8.0:
            return_score += 8.0
        elif cash_on_cash_yield_pct < 3.0:
            return_score -= 8.0
    return_score = _clamp(return_score)

    value_score = 46.0
    if isinstance(market_delta_pct, float):
        if market_delta_pct <= -15.0:
            value_score = 90.0
        elif market_delta_pct <= -8.0:
            value_score = 80.0
        elif market_delta_pct <= -3.0:
            value_score = 68.0
        elif market_delta_pct < 3.0:
            value_score = 55.0
        elif market_delta_pct < 10.0:
            value_score = 40.0
        else:
            value_score = 24.0
    if buy_sample_count >= 4:
        value_score += 5.0
    elif buy_sample_count == 0:
        value_score -= 10.0
    value_score = _clamp(value_score)

    demand_score = 45.0
    if isinstance(transit_m, float):
        if transit_m <= 250.0:
            demand_score += 15.0
        elif transit_m <= 550.0:
            demand_score += 9.0
        elif transit_m >= 1200.0:
            demand_score -= 10.0
    if isinstance(supermarket_m, float) and supermarket_m <= 500.0:
        demand_score += 5.0
    if isinstance(medical_m, float) and medical_m <= 1200.0:
        demand_score += 4.0
    if school_context:
        demand_score += 5.0
    if investment_impact:
        if any(token in investment_impact for token in ("positive", "tailwind", "upside", "strong", "supportive")):
            demand_score += 10.0
        elif any(token in investment_impact for token in ("negative", "weak", "headwind", "adverse")):
            demand_score -= 10.0
    if value_drivers:
        demand_score += min(len(value_drivers) * 2.0, 8.0)
    if value_risks:
        demand_score -= min(len(value_risks) * 2.0, 8.0)
    demand_score = _clamp(demand_score)

    liquidity_score = 48.0
    if isinstance(transit_m, float):
        if transit_m <= 400.0:
            liquidity_score += 12.0
        elif transit_m >= 1200.0:
            liquidity_score -= 12.0
    if buy_sample_count >= 4:
        liquidity_score += 10.0
    elif buy_sample_count == 0:
        liquidity_score -= 12.0
    if source_trust_tier == "high":
        liquidity_score += 4.0
    if source_access_level in {"direct", "verified"}:
        liquidity_score += 4.0
    if any(token in investment_impact for token in ("oversupply", "supply", "softening", "negative")):
        liquidity_score -= 8.0
    if legal_complexity:
        liquidity_score -= 12.0
    if isinstance(dscr, float):
        if dscr >= 1.35:
            liquidity_score += 6.0
        elif dscr < 1.0:
            liquidity_score -= 12.0
    liquidity_score = _clamp(liquidity_score)

    risk_score = 63.0
    if legal_complexity:
        risk_score -= 16.0
    if not tenant_clarity:
        risk_score -= 8.0
    if heavy_renovation:
        risk_score -= 12.0
    if not energy_certificate_present:
        risk_score -= 5.0
    for risk_key in ("flood_risk", "noise_risk", "air_quality_risk", "crime_risk", "parking_pressure_risk", "drinking_water_risk"):
        if bool(facts.get(risk_key)) or risk_key in official_risk_keys:
            risk_score -= 6.0
    if planning_confidence in {"high", "verified"}:
        risk_score += 4.0
    elif planning_confidence in {"unknown", "low"}:
        risk_score -= 3.0
    if isinstance(dscr, float):
        if dscr >= 1.25:
            risk_score += 6.0
        elif dscr < 1.0:
            risk_score -= 14.0
    if isinstance(net_yield_pct, float) and net_yield_pct < 2.0:
        risk_score -= 6.0
    risk_score = _clamp(risk_score)

    execution_score = 50.0
    if floorplan_ready:
        execution_score += 12.0
    else:
        execution_score -= 12.0
    if tenant_clarity:
        execution_score += 8.0
    if energy_certificate_present:
        execution_score += 5.0
    if has_360:
        execution_score += 3.0
    if heavy_renovation:
        execution_score -= 16.0
    execution_score -= min(float(len(missing_fact_items)) * 4.0, 18.0)
    if str(feed_status_label).lower().startswith("live"):
        execution_score += 5.0
    execution_score = _clamp(execution_score)

    evidence_score = 32.0
    evidence_score += min(float(buy_sample_count) * 6.0, 18.0)
    evidence_score += min(float(rent_sample_count) * 6.0, 18.0)
    if floorplan_ready:
        evidence_score += 8.0
    if tenant_clarity:
        evidence_score += 5.0
    if location_confident:
        evidence_score += 5.0
    evidence_score += min(float(len(official_risk_sources)) * 2.0, 8.0)
    evidence_score += source_confidence_bonus
    if not snapshot_json:
        evidence_score -= 16.0
    if external_confidence_label == "High confidence":
        evidence_score += 10.0
    elif external_confidence_label == "Partial evidence":
        evidence_score += 4.0
    else:
        evidence_score -= 6.0
    evidence_score = _clamp(evidence_score)

    strategy = _property_investment_strategy(preferences)
    weights = {
        "best_overall": {"return": 0.23, "value": 0.19, "demand": 0.14, "liquidity": 0.13, "risk": 0.16, "execution": 0.10, "evidence": 0.05},
        "cash_flow": {"return": 0.34, "value": 0.10, "demand": 0.14, "liquidity": 0.12, "risk": 0.16, "execution": 0.09, "evidence": 0.05},
        "appreciation": {"return": 0.08, "value": 0.31, "demand": 0.18, "liquidity": 0.16, "risk": 0.12, "execution": 0.10, "evidence": 0.05},
        "undervalued": {"return": 0.15, "value": 0.33, "demand": 0.12, "liquidity": 0.11, "risk": 0.10, "execution": 0.14, "evidence": 0.05},
        "low_risk": {"return": 0.07, "value": 0.05, "demand": 0.10, "liquidity": 0.16, "risk": 0.30, "execution": 0.14, "evidence": 0.18},
    }.get(strategy) or {"return": 0.23, "value": 0.19, "demand": 0.14, "liquidity": 0.13, "risk": 0.16, "execution": 0.10, "evidence": 0.05}
    dimension_scores = {
        "return": return_score,
        "value": value_score,
        "demand": demand_score,
        "liquidity": liquidity_score,
        "risk": risk_score,
        "execution": execution_score,
        "evidence": evidence_score,
    }
    score = sum(dimension_scores[key] * float(weight) for key, weight in weights.items())

    reasons: list[str] = []
    blockers: list[str] = []
    if isinstance(gross_yield_pct, float) and gross_yield_pct > 0.0:
        reasons.append(f"Expected gross yield is about {gross_yield_pct:.1f}%.")
    else:
        blockers.append("Gross yield still needs rent evidence.")
    if isinstance(net_yield_pct, float):
        reasons.append(f"Net yield screens at about {net_yield_pct:.1f}% after tax, opex, vacancy, and capex reserves.")
    else:
        blockers.append("Net yield still depends on fallback assumptions.")
    if isinstance(cap_rate_pct, float):
        reasons.append(f"Cap rate screens at about {cap_rate_pct:.1f}%.")
    if isinstance(market_delta_pct, float):
        if market_delta_pct < 0.0:
            reasons.append(f"Pricing looks {abs(market_delta_pct):.1f}% below local buy comparables.")
        elif market_delta_pct > 0.0:
            blockers.append(f"Pricing looks {market_delta_pct:.1f}% above local buy comparables.")
    else:
        blockers.append("Local buy comparables are still partial.")
    if demand_score >= 65.0:
        reasons.append("Micro-location demand signals look supportive.")
    elif demand_score <= 40.0:
        blockers.append("Demand signals are still thin for this micro-location.")
    if liquidity_score >= 65.0:
        reasons.append("Exit and reletting liquidity look usable.")
    elif liquidity_score <= 40.0:
        blockers.append("Exit liquidity looks thinner than ideal.")
    if floorplan_ready:
        reasons.append("Layout evidence is already available.")
    else:
        blockers.append("No floorplan is attached yet.")
    if legal_complexity:
        blockers.append("Listing text suggests legal complexity.")
    if not tenant_clarity:
        blockers.append("Tenant or occupancy status is still unclear.")
    if heavy_renovation:
        blockers.append("Listing reads like a heavier renovation case.")
    if evidence_score <= 45.0:
        blockers.append("The underwriting read is still relying on partial evidence.")
    if isinstance(dscr, float):
        if dscr >= 1.25:
            reasons.append(f"Debt coverage screens at {dscr:.2f}x.")
        else:
            blockers.append(f"Debt coverage is only {dscr:.2f}x.")
    elif str(feed_status_label).lower().startswith("fallback"):
        blockers.append("Debt coverage is still using fallback financing.")
    min_yield = _property_investment_min_gross_yield_pct(preferences)
    if min_yield > 0.0 and isinstance(gross_yield_pct, float) and gross_yield_pct < min_yield:
        blockers.append(f"Expected yield is below the {min_yield:.0f}% floor.")
        score -= 18.0
    if bool(preferences.get("investment_require_floorplan")) and not floorplan_ready:
        score -= 100.0
    if bool(preferences.get("investment_require_legal_clarity")) and legal_complexity:
        score -= 100.0
    if bool(preferences.get("investment_require_tenant_clarity")) and not tenant_clarity:
        score -= 100.0
    if bool(preferences.get("investment_avoid_major_renovation")) and heavy_renovation:
        score -= 100.0
    min_dscr = _float_or_none(preferences.get("min_dscr"))
    if isinstance(min_dscr, float) and min_dscr > 0.0 and isinstance(dscr, float) and dscr < min_dscr:
        blockers.append(f"Debt coverage is below the {min_dscr:.2f}x floor.")
        score -= 18.0
    score = _clamp(score)

    confidence_label = (
        "High confidence"
        if evidence_score >= 72.0 and not blockers[:1]
        else ("Partial evidence" if evidence_score >= 48.0 else "Needs manual verification")
    )
    currency_code = _property_currency_code_from_facts(facts)
    overall_bucket = _property_investment_score_bucket(score)
    overall_bucket_label = _property_investment_score_bucket_label(score)
    headline = reasons[0] if reasons else "This opportunity still needs more evidence before it can rank as a strong investment."
    if blockers:
        headline = f"{headline} Main issue: {blockers[0]}"
    tooltips = _property_investment_dimension_tooltips()
    label_map = {
        "return": "Return",
        "value": "Value",
        "demand": "Demand",
        "liquidity": "Liquidity",
        "risk": "Risk control",
        "execution": "Execution",
        "evidence": "Evidence",
    }
    dimensions = [
        {
            "key": key,
            "label": label_map[key],
            "score": _clamp(raw_score),
            "bucket": _property_investment_score_bucket(raw_score),
            "bucket_label": _property_investment_score_bucket_label(raw_score),
            "tooltip": tooltips.get(key, ""),
        }
        for key, raw_score in dimension_scores.items()
    ]
    summary_parts = []
    for key in ("return", "value", "risk", "execution"):
        row = next((item for item in dimensions if item["key"] == key), None)
        if row:
            summary_parts.append(f"{row['label']} {row['bucket_label'].lower()}")
    return {
        "score": score,
        "score_display": f"{score:.0f}/100 institutional score",
        "score_bucket": overall_bucket,
        "score_bucket_label": overall_bucket_label,
        "strategy": strategy,
        "gross_yield_pct": round(gross_yield_pct, 2) if isinstance(gross_yield_pct, float) else None,
        "gross_yield_display": f"{gross_yield_pct:.1f}% gross yield" if isinstance(gross_yield_pct, float) else "",
        "market_delta_pct": round(market_delta_pct, 1) if isinstance(market_delta_pct, float) else None,
        "market_delta_display": (
            f"{abs(market_delta_pct):.1f}% below local buy median"
            if isinstance(market_delta_pct, float) and market_delta_pct < 0
            else (f"{market_delta_pct:.1f}% above local buy median" if isinstance(market_delta_pct, float) else "")
        ),
        "expected_rent_display": f"Rent model about {_property_money_amount_label(expected_monthly_rent_eur, currency_code=currency_code)}/mo" if isinstance(expected_monthly_rent_eur, float) and expected_monthly_rent_eur > 0 else "",
        "payback_display": f"Gross payback about {payback_years:.1f} years" if isinstance(payback_years, float) and payback_years > 0 else "",
        "net_yield_pct": round(net_yield_pct, 2) if isinstance(net_yield_pct, float) else None,
        "net_yield_display": f"{net_yield_pct:.1f}% net yield" if isinstance(net_yield_pct, float) else "",
        "cap_rate_pct": round(cap_rate_pct, 2) if isinstance(cap_rate_pct, float) else None,
        "cap_rate_display": f"{cap_rate_pct:.1f}% cap rate" if isinstance(cap_rate_pct, float) else "",
        "cash_on_cash_yield_pct": round(cash_on_cash_yield_pct, 2) if isinstance(cash_on_cash_yield_pct, float) else None,
        "cash_on_cash_display": f"{cash_on_cash_yield_pct:.1f}% cash-on-cash" if isinstance(cash_on_cash_yield_pct, float) else "",
        "dscr": round(dscr, 2) if isinstance(dscr, float) else None,
        "dscr_display": f"{dscr:.2f}x DSCR" if isinstance(dscr, float) else "",
        "price_per_sqm": f"Buy side about {_property_money_amount_label(current_price_per_sqm, currency_code=currency_code)}/m2" if isinstance(current_price_per_sqm, float) and current_price_per_sqm > 0 else "",
        "market_buy_per_sqm_display": f"Local buy median about {_property_money_amount_label(market_buy_per_sqm, currency_code=currency_code)}/m2" if isinstance(market_buy_per_sqm, float) and market_buy_per_sqm > 0 else "",
        "market_rent_per_sqm_display": f"Local rent median about {currency_code} {market_rent_per_sqm:,.2f}/m2".replace(",", " ") if isinstance(market_rent_per_sqm, float) and market_rent_per_sqm > 0 else "",
        "feed_status_label": feed_status_label,
        "feed_status_detail": feed_status_detail,
        "external_model": external_model,
        "headline": compact_text(headline, fallback="Investment read is still building from the confirmed listing facts.", limit=220),
        "confidence_label": confidence_label,
        "dimensions": dimensions,
        "underwriting_summary": " · ".join(summary_parts[:4]),
        "reasons": reasons[:4],
        "blockers": blockers[:4],
    }


def _property_candidate_has_investment_legal_complexity(*, title: str, summary: str, facts: dict[str, object]) -> bool:
    text = _property_candidate_text(property_url="", title=title, summary=summary, property_facts=facts).lower()
    return any(marker in text for marker in _PROPERTY_INVESTMENT_LEGAL_COMPLEXITY_MARKERS)


def _property_candidate_needs_major_renovation(*, title: str, summary: str, facts: dict[str, object]) -> bool:
    text = _property_candidate_text(property_url="", title=title, summary=summary, property_facts=facts).lower()
    return any(marker in text for marker in _PROPERTY_INVESTMENT_RENOVATION_MARKERS)


def _property_investment_candidate_payload(
    *,
    property_url: str,
    title: str,
    summary: str,
    facts: dict[str, object],
    preferences: dict[str, object],
    selected_platforms: tuple[str, ...],
) -> dict[str, object]:
    if _property_search_goal(preferences) != "investment":
        return {}
    current_price_eur = _property_investment_price_eur(facts)
    current_area_sqm = _property_investment_area_sqm(facts)
    location_query = str(preferences.get("location_query") or "").strip()
    snapshot = _property_investment_research_snapshot(
        property_url=property_url,
        country_code=str(preferences.get("country_code") or "").strip().upper(),
        location_query=location_query,
        selected_platforms_csv=",".join(selected_platforms),
        current_price_eur=float(current_price_eur or 0.0),
        current_area_sqm=float(current_area_sqm or 0.0),
        research_level="preview",
    ) if current_price_eur and current_area_sqm else {}
    return _property_investment_underwriting_payload(
        title=title,
        summary=summary,
        facts=facts,
        preferences=preferences,
        snapshot=snapshot,
    )


def _property_scout_rank_score(
    *,
    property_url: str,
    assessment: dict[str, object] | None,
    preview: dict[str, object],
    ordinal: int,
) -> float:
    fit_score = _property_alert_fit_score(assessment)
    if fit_score > 0.0:
        return max(0.0, min(100.0, fit_score + _property_scout_objective_review_boost(property_url=property_url, preview=preview)))
    text = " ".join(
        part
        for part in (
            str(preview.get("title") or "").lower(),
            str(preview.get("summary") or "").lower(),
            str(property_url or "").lower(),
        )
        if part
    )
    heuristic = 55.0 - min(float(ordinal) * 3.0, 18.0)
    if any(token in text for token in ("360", "panorama", "photosphere")):
        heuristic += 10.0
    if any(token in text for token in ("grundriss", "floorplan", "lageplan")):
        heuristic += 8.0
    if any(token in text for token in ("lift", "aufzug", "terrasse", "balkon")):
        heuristic += 4.0
    return max(0.0, min(100.0, heuristic + _property_scout_objective_review_boost(property_url=property_url, preview=preview)))


def _property_search_source_scope_location(*, source_url: str = "", source_label: str = "") -> str:
    text_parts = tuple(str(part or "").strip() for part in (source_label, source_url) if str(part or "").strip())
    text = " ".join(text_parts)
    if not text:
        return ""
    for part in text_parts:
        decoded_part = urllib.parse.unquote_plus(part)
        for row in _property_postal_location_evidence(decoded_part):
            postal_name = str(row.get("postal_name") or "").strip()
            if postal_name:
                return postal_name
    decoded = urllib.parse.unquote_plus(text)
    for row in _property_postal_location_evidence(decoded):
        postal_name = str(row.get("postal_name") or "").strip()
        if postal_name:
            return postal_name
    match = re.search(r"\b(1\d{3})\s*(?:Vienna|Wien)\b", decoded, flags=re.IGNORECASE)
    if match:
        return f"{match.group(1)} Vienna"
    retfield_match = re.search(r"(?:VPLZ|%5BVPLZ%5D)[^=]*=\(?([1-9]\d{3})\)?", decoded, flags=re.IGNORECASE)
    city_match = re.search(r"(?:VOrt|%5BVOrt%5D)[^=]*=\(?([A-Za-zÄÖÜäöüß]+)\)?", decoded, flags=re.IGNORECASE)
    if retfield_match:
        city = str(city_match.group(1) if city_match else "Vienna").strip()
        if city.lower() == "wien":
            city = "Vienna"
        return f"{retfield_match.group(1)} {city}".strip()
    label_parts = tuple(part.strip() for part in str(source_label or "").split("|") if part.strip())
    scope_stopwords = {
        "buy",
        "rent",
        "sale",
        "miete",
        "kaufen",
        "verkauf",
        "austria",
        "costa rica",
        "all costa rica",
        "all austria",
        "österreich",
        "osterreich",
        "country-wide",
        "countrywide",
    }
    for part in reversed(label_parts):
        normalized = re.sub(r"[^a-z0-9äöüß]+", " ", part.lower()).strip()
        if not normalized or normalized in scope_stopwords:
            continue
        if len(normalized) <= 2:
            continue
        return part
    try:
        parsed = urllib.parse.urlparse(str(source_url or ""))
        params = urllib.parse.parse_qs(parsed.query)
    except Exception:
        params = {}
    for key in ("q", "query", "location", "city", "region", "search"):
        for value in list(params.get(key) or []):
            candidate = str(value or "").strip()
            normalized = re.sub(r"[^a-z0-9äöüß]+", " ", candidate.lower()).strip()
            if candidate and normalized not in scope_stopwords and len(normalized) > 2:
                return candidate
    return ""


def _property_facts_with_source_scope(
    *,
    facts: dict[str, object] | None,
    source_url: str = "",
    source_label: str = "",
) -> dict[str, object]:
    enriched = dict(facts or {})
    scope_location = _property_search_source_scope_location(source_url=source_url, source_label=source_label)
    if not scope_location:
        return enriched
    enriched["source_scope_location"] = scope_location
    postal_match = re.search(r"\b([1-9]\d{3})\b", scope_location)
    if postal_match:
        enriched["source_postal_code"] = postal_match.group(1)
    city = re.sub(r"\b[1-9]\d{3}\b", "", scope_location).strip()
    if city:
        enriched["source_city"] = city
    return enriched


def _property_exact_source_scope_location_hints(*, source_url: str = "", source_label: str = "") -> tuple[str, ...]:
    """Return exact postal source-scope hints; broad provider labels are not listing evidence."""
    scope_location = _property_search_source_scope_location(source_url=source_url, source_label=source_label)
    hints: list[str] = []
    if scope_location and _property_postal_code_core(scope_location):
        hints.append(scope_location)
    for part in (source_label, source_url):
        for row in _property_postal_location_evidence(str(part or "")):
            postal_name = str(row.get("postal_name") or "").strip()
            if postal_name:
                hints.append(postal_name)
    return tuple(dict.fromkeys(hints))


_PROPERTY_POSTAL_LOCATION_RE = re.compile(
    r"\b(?P<code>(?:[A-Z]{1,3}[-\s]?)?\d{4,5}(?:-\d{3})?|\d{2}-\d{3}|\d{3}\s?\d{2}|\d{4}\s?[A-Z]{2})\s+"
    r"(?P<locality>[A-ZÄÖÜ][A-Za-zÄÖÜäöüß' .\-/]{1,60})",
    flags=re.IGNORECASE,
)


def _property_postal_code_core(value: object) -> str:
    normalized = str(value or "").strip()
    if not normalized:
        return ""
    match = re.search(r"\b(\d{4,5})\b", normalized)
    if match:
        return match.group(1)
    compact = re.sub(r"\D+", "", normalized)
    return compact[:5] if len(compact) >= 4 else ""


def _property_postal_location_evidence(value: object) -> tuple[dict[str, str], ...]:
    raw_text = html.unescape(str(value or ""))
    if not raw_text.strip():
        return ()
    slug_expanded_text = re.sub(
        r"\b(?P<code>[1-9]\d{3,4})[-_/]+(?=[A-Za-zÄÖÜäöüß])",
        r"\g<code> ",
        raw_text,
    )
    text = " ".join(slug_expanded_text.replace("|", " ").replace("·", " ").split())
    rows: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for match in _PROPERTY_POSTAL_LOCATION_RE.finditer(text):
        code = _property_postal_code_core(match.group("code"))
        locality = compact_text(str(match.group("locality") or ""), fallback="", limit=80)
        locality = re.split(r"[/#?&=]", locality, maxsplit=1)[0]
        locality = re.split(r"\s+https?\b", locality, maxsplit=1, flags=re.IGNORECASE)[0]
        locality = re.sub(
            r"\s+(?:m(?:²|2)|sqm|zimmer|rooms?|eur|€|usd|der\s+standard|willhaben|immobilien)\b.*$",
            "",
            locality,
            flags=re.IGNORECASE,
        ).strip(" ,.;:-")
        if re.search(
            r"\b(?:source|search|provider|selected|requested)\s+(?:scope|area|district|location)\b|"
            r"\b(?:scope|source)\s+(?:location|placeholder)\b",
            locality,
            flags=re.IGNORECASE,
        ):
            continue
        locality_lower = locality.lower()
        if locality and locality == locality_lower and locality_lower not in {"wien"}:
            locality = locality.title()
        if not code or not locality or not re.search(r"[A-Za-zÄÖÜäöüß]", locality):
            continue
        key = (code, locality.casefold())
        if key in seen:
            continue
        seen.add(key)
        rows.append({"postal_code": code, "postal_name": f"{code} {locality}".strip()})
    return tuple(rows)


def _property_source_scope_postal_codes(facts: dict[str, object] | None) -> frozenset[str]:
    payload = dict(facts or {})
    return frozenset(
        code
        for code in (
            _property_postal_code_core(payload.get("source_postal_code")),
            _property_postal_code_core(payload.get("source_scope_location")),
            _property_postal_code_core(
                " ".join(
                    str(payload.get(key) or "").strip()
                    for key in ("source_postal_code", "source_city")
                    if str(payload.get(key) or "").strip()
                )
            ),
        )
        if code
    )


def _property_location_value_is_source_scope_placeholder(value: object, facts: dict[str, object] | None) -> bool:
    """True when a location-like value only repeats the provider/search scope."""
    lowered = str(value or "").strip().lower()
    if not lowered:
        return False
    payload = dict(facts or {})
    if any(
        token in lowered
        for token in (
            "gasse",
            "straße",
            "strasse",
            "weg",
            "platz",
            "allee",
            "lane",
            "road",
            "street",
            "avenue",
            "drive",
            "boulevard",
            "square",
            "court",
            "terrace",
        )
    ):
        return False
    source_postal_code = _property_postal_code_core(payload.get("source_postal_code"))
    source_city = str(payload.get("source_city") or "").strip().lower()
    scope_candidates = {
        str(payload.get("source_scope_location") or "").strip().lower(),
        source_city,
        " ".join(part for part in (source_postal_code, source_city) if part).strip().lower(),
    }
    scope_candidates.discard("")
    if lowered in scope_candidates:
        return True
    if not (source_postal_code and _property_postal_code_core(lowered) == source_postal_code):
        return False
    remainder = re.sub(r"\b\d{4,5}\b", " ", lowered)
    if source_city:
        remainder = remainder.replace(source_city, " ")
    remainder = re.sub(r"[\s,;|/\\()\\[\\]{}._-]+", " ", remainder).strip()
    return not remainder


def _property_listing_observed_postal_codes(
    *,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> tuple[str, ...]:
    facts = dict(property_facts or {})
    source_codes = _property_source_scope_postal_codes(facts)
    evidence_parts: list[object] = [title, summary]
    for key in ("exact_address", "street_address", "address", "postal_name", "location", "district", "city"):
        value = str(facts.get(key) or "").strip()
        if value:
            evidence_parts.append(value)
    evidence_parts.extend(str(item or "").strip() for item in list(facts.get("address_lines") or []) if str(item or "").strip())
    evidence_parts.extend(str(item.get("postal_name") or "").strip() for item in list(facts.get("listing_postal_evidence") or []) if isinstance(item, dict))
    codes: list[str] = []
    for part in evidence_parts:
        for row in _property_postal_location_evidence(part):
            code = str(row.get("postal_code") or "").strip()
            if code and (code not in source_codes or str(part or "").strip() in {str(title or "").strip(), str(summary or "").strip()}):
                codes.append(code)
    return tuple(dict.fromkeys(codes))


def _property_scout_objective_review_boost(*, property_url: str, preview: dict[str, object]) -> float:
    facts = dict(preview.get("property_facts_json") or {}) if isinstance(preview.get("property_facts_json"), dict) else {}
    boost = 0.0
    if _property_facts_have_floorplan(facts, preview=preview):
        boost += 6.0
    area_sqm = _property_candidate_area_sqm(
        property_url=property_url,
        title=str(preview.get("title") or ""),
        summary=str(preview.get("summary") or ""),
        property_facts=facts,
    )
    if isinstance(area_sqm, float) and area_sqm >= 70.0:
        boost += 5.0
    provider_channel = str(facts.get("provider_channel") or "").strip().lower()
    provider_group = str(facts.get("provider_group") or "").strip().lower()
    sale_channel = str(facts.get("sale_channel") or "").strip().lower()
    if sale_channel == "judicial_auction" or provider_channel == "justiz_edikte_at":
        boost += 5.0
    elif provider_group == "genossenschaften_at":
        boost += 4.0
    if any(str(facts.get(key) or "").strip() for key in ("district", "postal_name", "location", "street_address")):
        boost += 2.0
    return max(0.0, min(24.0, boost))


def _property_austria_provider_is_public_or_cooperative(facts: dict[str, object] | None) -> bool:
    payload = dict(facts or {})
    provider_group = str(payload.get("provider_group") or "").strip().lower()
    provider_channel = str(payload.get("provider_channel") or "").strip().lower()
    return provider_group in {"genossenschaften_at", "public_housing_at"} or provider_channel in {
        "wohnberatung_wien",
        "wiener_wohnen",
        "gesiba",
        "siedlungsunion",
        "wbv_gpa",
        "frieden",
        "sozialbau",
        "oesw_at",
        "egw_at",
    }


def _property_austria_numeric_fact(facts: dict[str, object] | None, *keys: str) -> int:
    payload = dict(facts or {})
    for key in keys:
        value = payload.get(key)
        if value in (None, "", []):
            continue
        try:
            return int(round(float(str(value).replace(".", "").replace(",", "."))))
        except Exception:
            continue
    return 0


def _property_austria_preference_score_adjustment(
    *,
    preferences: dict[str, object] | None,
    property_facts: dict[str, object] | None,
    title: str = "",
    summary: str = "",
) -> tuple[float, tuple[str, ...]]:
    payload = dict(preferences or {})
    if normalize_country_code(payload.get("country_code")) != "AT":
        return 0.0, ()
    facts = dict(property_facts or {})
    text = " ".join(
        part
        for part in (
            str(title or "").strip(),
            str(summary or "").strip(),
            str(facts.get("marketing_type") or "").strip(),
            str(facts.get("availability_label") or "").strip(),
        )
        if part
    ).lower()
    official_sources = list(dict(facts.get("official_risk_evidence") or {}).get("sources") or []) if isinstance(facts.get("official_risk_evidence"), dict) else []
    official_risk_keys = {
        str(row.get("risk_key") or "").strip().lower()
        for row in official_sources
        if isinstance(row, dict) and str(row.get("risk_key") or "").strip()
    }
    district_text = " ".join(
        str(facts.get(key) or "").strip().lower()
        for key in ("postal_code", "postal_name", "district", "location", "street_address")
        if str(facts.get(key) or "").strip()
    )
    family_mode = bool(payload.get("enable_family_mode"))
    school_requested = family_mode or bool(payload.get("require_school_evidence")) or bool(list(payload.get("school_stage_preferences") or []))
    public_or_cooperative = _property_austria_provider_is_public_or_cooperative(facts)
    sale_channel = str(facts.get("sale_channel") or "").strip().lower()
    adjustment = 0.0
    notes: list[str] = []

    if bool(payload.get("subsidized_required")):
        if public_or_cooperative:
            adjustment += 8.0
            notes.append("subsidized supply matched")
        else:
            adjustment -= 18.0
            notes.append("not subsidized or cooperative")

    if bool(payload.get("wiener_wohnticket_available")) and str(facts.get("provider_channel") or "").strip().lower() in {"wohnberatung_wien", "wiener_wohnen"}:
        adjustment += 4.0
        notes.append("Wohn-Ticket-ready lane")

    if bool(payload.get("miete_mit_kaufoption")):
        if any(marker in text for marker in ("kaufoption", "miete mit kaufoption", "mietkauf")):
            adjustment += 6.0
            notes.append("kaufoption signal present")
        elif public_or_cooperative:
            adjustment -= 4.0
            notes.append("kaufoption not confirmed")

    eigenmittel_cap = int(payload.get("eigenmittel_max_eur") or 0)
    if eigenmittel_cap > 0:
        financing_value = _property_austria_numeric_fact(
            facts,
            "finanzierungsbeitrag_eur",
            "eigenmittel_eur",
            "deposit_eur",
        )
        if financing_value > 0 and financing_value > eigenmittel_cap:
            adjustment -= 12.0
            notes.append("Eigenmittel above cap")
        elif financing_value > 0 and financing_value <= eigenmittel_cap:
            adjustment += 3.0
            notes.append("Eigenmittel within cap")
        elif public_or_cooperative:
            adjustment -= 4.0
            notes.append("Eigenmittel not disclosed")

    application_window_days = int(payload.get("application_window_days") or 0)
    if application_window_days > 0 and public_or_cooperative:
        listing_window_days = _property_austria_numeric_fact(facts, "application_window_days")
        if listing_window_days > 0 and listing_window_days <= application_window_days:
            adjustment += 2.0
            notes.append("application window matches")
        elif listing_window_days > application_window_days:
            adjustment -= 5.0
            notes.append("application window too slow")
        else:
            adjustment -= 2.0
            notes.append("application window unknown")

    if school_requested:
        has_school_evidence = bool(property_school_context_summary(facts)) or "school_evidence" in official_risk_keys
        if has_school_evidence:
            adjustment += 3.0
            notes.append("school evidence attached")
        else:
            adjustment -= 6.0
            notes.append("school evidence missing")
        if bool(payload.get("ganztag_required")):
            if any(marker in text for marker in ("ganztag", "ganztags", "after-school", "after school")):
                adjustment += 3.0
                notes.append("ganztag signal present")
            else:
                adjustment -= 4.0
                notes.append("ganztag not confirmed")

    if bool(payload.get("avoid_noise_risk_area")):
        if bool(facts.get("noise_risk")):
            adjustment -= 10.0
            notes.append("noise risk flagged")
        elif "noise_risk" in official_risk_keys:
            adjustment += 2.0
            notes.append("noise evidence attached")
        else:
            adjustment -= 3.0
            notes.append("noise evidence missing")
            quiet_signal = str(facts.get("quiet_layout_signal") or "").strip().lower()
            if quiet_signal in {"weak_positive", "positive"}:
                adjustment += 1.0 if quiet_signal == "weak_positive" else 2.0
                notes.append("layout-derived quiet signal")

    if bool(payload.get("require_high_speed_internet")):
        if "broadband_availability" in official_risk_keys:
            adjustment += 3.0
            notes.append("broadband evidence attached")
        else:
            adjustment -= 5.0
            notes.append("broadband evidence missing")

    if bool(payload.get("prefer_heat_resilient_home")):
        heat_score = 0.0
        heat_notes: list[str] = []
        heat_risk_level = str(facts.get("heat_resilience_risk") or facts.get("urban_heat_risk") or facts.get("summer_heat_risk") or "").strip().lower()
        cooling_corridor_signal = str(facts.get("cooling_corridor_signal") or "").strip().lower()
        cooling_corridor_summary = str(facts.get("cooling_corridor_summary") or "").strip()
        flowing_water_distance_m = _float_or_none(facts.get("nearest_flowing_water_m"))
        if bool(facts.get("air_conditioning")) or any(marker in text for marker in ("klimaanlage", "air conditioning", "aircondition", "splitgerät", "splitgeraet")):
            heat_score += 5.0
            heat_notes.append("cooling present")
        if bool(facts.get("altbau")) or any(marker in text for marker in ("altbau", "dicke wände", "dicke waende", "thick walls")):
            heat_score += 3.0
            heat_notes.append("altbau or thick-wall cooling signal")
        if bool(facts.get("external_shading")) or bool(facts.get("aussenjalousien")) or any(marker in text for marker in ("außenjalous", "aussenjalous", "raffstore", "rollladen", "außenrollo", "aussenrollo")):
            heat_score += 4.0
            heat_notes.append("external shading present")
        if bool(facts.get("tree_shade_signal")) or bool(facts.get("green_shade_signal")) or any(marker in text for marker in ("bäume vor", "baeume vor", "baum vor", "schattiger innenhof", "begrünter innenhof", "begruenter innenhof")):
            heat_score += 3.0
            heat_notes.append("tree or courtyard shade signal")
        if cooling_corridor_signal in {"strong", "moderate", "weak"}:
            if cooling_corridor_signal == "strong":
                heat_score += 3.0
            elif cooling_corridor_signal == "moderate":
                heat_score += 2.0
            else:
                heat_score += 1.0
            if cooling_corridor_summary:
                heat_notes.append(cooling_corridor_summary)
            elif isinstance(flowing_water_distance_m, float) and flowing_water_distance_m > 0.0:
                heat_notes.append(f"Nearby flowing water (about {int(round(flowing_water_distance_m))} m) can soften summer heat.")
        elif "cooling_corridor" in official_risk_keys:
            heat_score += 1.0
            heat_notes.append("cooling-corridor evidence attached")
        if bool(facts.get("top_floor")) or bool(facts.get("dachgeschoss")) or any(marker in text for marker in ("dachgeschoss", "dg-wohnung", "top floor", "attic apartment", "mansarde")):
            heat_score -= 7.0
            heat_notes.append("top-floor heat risk")
        if bool(facts.get("large_south_windows")) or any(marker in text for marker in ("südseitige fenster", "suedseitige fenster", "südseitig", "suedseitig", "south-facing windows", "south facing windows")):
            heat_score -= 5.0
            heat_notes.append("large south-facing window risk")
        inner_vienna_markers = {"1010", "1020", "1030", "1040", "1050", "1060", "1070", "1080", "1090"}
        if any(marker in district_text for marker in inner_vienna_markers) or any(marker in district_text for marker in ("innere stadt", "leopoldstadt", "landstraße", "landstrasse", "wieden", "margareten", "mariahilf", "neubau", "josefstadt", "alsergrund")):
            heat_score -= 3.0
            heat_notes.append("inner-city Vienna heat-island heuristic")
        if heat_risk_level in {"high", "very_high", "severe"} or bool(facts.get("heat_resilience_risk")):
            heat_score -= 6.0
            heat_notes.append("official or extracted heat risk flagged")
        elif heat_risk_level in {"low", "cool", "good"}:
            heat_score += 3.0
            heat_notes.append("low heat-risk signal")
        if "heat_resilience" in official_risk_keys:
            heat_score += 1.0
            heat_notes.append("official climate evidence lane attached")
        else:
            heat_score -= 2.0
            heat_notes.append("official heat evidence missing")
        if heat_score:
            adjustment += max(-14.0, min(10.0, heat_score))
            notes.extend(heat_notes)

    if bool(payload.get("require_energy_certificate")):
        if bool(facts.get("energy_certificate_present")):
            adjustment += 3.0
            notes.append("energy certificate mentioned")
        else:
            adjustment -= 8.0
            notes.append("energy certificate missing")

    if bool(payload.get("require_operating_cost_statement")):
        if bool(facts.get("operating_costs_present")):
            adjustment += 2.0
            notes.append("operating costs disclosed")
        else:
            adjustment -= 6.0
            notes.append("operating costs missing")

    if bool(payload.get("enable_auction_legal_review")) and sale_channel == "judicial_auction":
        adjustment += 4.0
        notes.append("auction legal review enabled")

    return adjustment, tuple(notes)


def _property_search_location_hints(preferences: dict[str, object] | None) -> tuple[str, ...]:
    preference_payload = dict(preferences or {})
    selected_location_values = preference_payload.get("selected_location_values")
    if isinstance(selected_location_values, (list, tuple, set)):
        explicit_values = tuple(
            str(item or "").strip()
            for item in selected_location_values
            if str(item or "").strip()
        )
        if explicit_values:
            return explicit_values
    selected_district_values = preference_payload.get("selected_districts")
    if isinstance(selected_district_values, (list, tuple, set)):
        explicit_values = tuple(
            str(item or "").strip()
            for item in selected_district_values
            if str(item or "").strip()
        )
        if explicit_values:
            return explicit_values
    if isinstance(preference_payload.get("raw_preferences"), dict):
        raw_preferences = dict(preference_payload.get("raw_preferences") or {})
        raw_selected_district_values = raw_preferences.get("selected_districts")
        if isinstance(raw_selected_district_values, (list, tuple, set)):
            explicit_values = tuple(
                str(item or "").strip()
                for item in raw_selected_district_values
                if str(item or "").strip()
            )
            if explicit_values:
                return explicit_values
    raw_value = str(preference_payload.get("location_query") or "").strip()
    if not raw_value and isinstance(preference_payload.get("raw_preferences"), dict):
        raw_value = str(dict(preference_payload.get("raw_preferences") or {}).get("location_query") or "").strip()
    if not raw_value:
        return ()
    values = [str(item or "").strip() for item in raw_value.split(",")]
    broad_country_values = {
        "allaustria",
        "austria",
        "at",
        "österreich",
        "osterreich",
        "gesamtösterreich",
        "gesamtoesterreich",
    }
    hints: list[str] = []
    for value in values:
        normalized = re.sub(r"[^a-z0-9äöüß]+", "", value.lower())
        if not value or normalized in broad_country_values:
            continue
        hints.append(value)
    return tuple(hints)


