def _property_text_has_explicit_non_vienna_location(value: str) -> bool:
    text = re.sub(r"[^a-z0-9äöüß]+", " ", str(value or "").strip().lower())
    if not text:
        return False
    padded = f" {text} "
    return any(f" {marker} " in padded for marker in _PROPERTY_AT_NON_VIENNA_LOCATION_MARKERS)


def _property_location_text_conflicts_with_hints(
    *,
    country_code: str,
    region_code: str = "",
    location_hints: tuple[str, ...],
    concrete_text: str,
) -> bool:
    normalized_country = normalize_country_code(country_code)
    if not normalized_country or not location_hints:
        return False
    raw_text = str(concrete_text or "").strip().lower()
    normalized_text = re.sub(r"[^a-z0-9äöüß]+", "", raw_text)
    if not raw_text and not normalized_text:
        return False

    hint_values: set[str] = set()
    for hint in location_hints:
        lowered_hint = str(hint or "").strip().lower()
        if not lowered_hint:
            continue
        hint_values.add(lowered_hint)
        normalized_hint = re.sub(r"[^a-z0-9äöüß]+", "", lowered_hint)
        if normalized_hint:
            hint_values.add(normalized_hint)
    selection_hint_values = set(hint_values)
    explicit_hint_postal_codes = frozenset(re.findall(r"\b\d{4}\b", " ".join(str(item or "") for item in location_hints).lower()))
    if "wien" in hint_values or "vienna" in hint_values or any(
        re.fullmatch(r"1\d{3}", value) for value in hint_values
    ):
        hint_values.update({"wien", "vienna"})

    def _normalized_location_token(value: object) -> str:
        return re.sub(r"[^a-z0-9äöüß]+", "", str(value or "").strip().lower())

    def _add_hint_equivalent(value: object) -> None:
        raw = str(value or "").strip().lower()
        normalized = _normalized_location_token(raw)
        if raw:
            hint_values.add(raw)
        if normalized:
            hint_values.add(normalized)

    def _term_matches_hint(value: object) -> bool:
        raw = str(value or "").strip().lower()
        normalized = _normalized_location_token(raw)
        if not raw and not normalized:
            return False
        if explicit_hint_postal_codes:
            term_postal_codes = frozenset(re.findall(r"\b\d{4}\b", raw))
            if term_postal_codes and any(code in explicit_hint_postal_codes for code in term_postal_codes):
                return True
            return raw in selection_hint_values or normalized in selection_hint_values
        if raw in hint_values or normalized in hint_values:
            return True
        return any(
            bool(hint)
            and (
                hint in raw
                or hint in normalized
                or (normalized and normalized in hint)
                or (raw and raw in hint)
            )
            for hint in hint_values
        )

    requested_all_country = any(
        re.sub(r"[^a-z0-9äöüß]+", "", value) in {"costarica", "austria", "osterreich", "österreich"}
        for value in hint_values
    )
    if requested_all_country:
        return False

    location_option_rows: list[dict[str, object]] = []
    region_keys = [str(region_code or "").strip().lower()]
    try:
        region_keys.extend(str(row.get("value") or "").strip().lower() for row in region_options_for_country(normalized_country))
    except Exception:
        pass
    for key in dict.fromkeys(value for value in region_keys if value):
        try:
            options = location_options_for_country_region(normalized_country, key)
        except Exception:
            options = []
        for option in options:
            if not isinstance(option, dict):
                continue
            location_option_rows.append(option)
            selected_by_hint = any(
                _term_matches_hint(option.get(field))
                for field in ("value", "label", "detail")
            )
            if selected_by_hint:
                for field in ("value", "label"):
                    _add_hint_equivalent(option.get(field))

    known_locations: set[str] = set()
    for option in location_option_rows:
        if not isinstance(option, dict):
            continue
        for field in ("value", "label"):
            candidate = str(option.get(field) or "").strip().lower()
            if candidate:
                known_locations.add(candidate)
    known_locations = {
        value
        for value in known_locations
        if len(re.sub(r"[^a-z0-9äöüß]+", "", value)) > 2
        and _normalized_location_token(value) not in hint_values
        and value not in {"all costa rica", "costa rica", "all austria", "austria", "österreich", "osterreich"}
    }
    for known in known_locations:
        normalized_known = _normalized_location_token(known)
        if not normalized_known or normalized_known in hint_values:
            continue
        if known in raw_text or normalized_known in normalized_text:
            return True

    if normalized_country == "CR":
        for pattern in (
            r"\bfor[-_\s]+sale[-_\s]+in[-_\s]+([a-z0-9-]{3,80})",
            r"\bfor[-_\s]+rent[-_\s]+in[-_\s]+([a-z0-9-]{3,80})",
            r"(?:^|/)(?:[a-z]{2}/)?real-estate/([a-z0-9-]{3,120})(?:[-_]costa[-_]rica)?(?=$|[^a-z0-9-])",
            r"(?:^|/)international/cr/([a-z0-9-]{3,180})(?=$|[^a-z0-9-])",
        ):
            for match in re.finditer(pattern, raw_text, flags=re.IGNORECASE):
                slug = re.sub(r"[^a-z0-9äöüß]+", "", str(match.group(1) or "").lower())
                if slug and not any(hint in slug or slug in hint for hint in hint_values):
                    return True
    return False


def _property_search_notification_budget(preferences: dict[str, object] | None) -> tuple[int, str]:
    payload = dict(preferences or {})
    period = str(payload.get("search_agent_notification_period") or "").strip().lower()
    if period not in {"day", "week"}:
        period = "day"
    try:
        limit = int(float(str(payload.get("search_agent_notification_limit") or 5).strip()))
    except Exception:
        limit = 5
    return max(1, min(50, limit)), period


def _property_search_floorplan_hard_filter_enabled(preferences: dict[str, object] | None) -> bool:
    payload = dict(preferences or {})
    if not _property_truthy_flag(payload.get("require_floorplan")):
        return False
    country_code = normalize_country_code(payload.get("country_code"))
    if country_code in {"AT"}:
        return True
    raw_policy = str(payload.get("floorplan_requirement_mode") or "").strip().lower()
    return raw_policy in {"hard", "strict", "required"}


def _property_search_hard_filtered_total(payload: dict[str, object] | None) -> int:
    summary = dict(payload or {})
    return (
        int(summary.get("filtered_area_total") or 0)
        + int(summary.get("filtered_property_type_total") or 0)
        + int(summary.get("filtered_floorplan_total") or 0)
        + int(summary.get("filtered_availability_total") or 0)
        + int(summary.get("filtered_generic_page_total") or 0)
        + int(summary.get("filtered_listing_mode_total") or 0)
    )


def _property_review_page_neuronwriter_payload(
    *,
    title: str,
    summary: str,
    counterparty: str,
    assessment: dict[str, object] | None,
) -> dict[str, object]:
    try:
        from app.services.dossier_writer.models import DossierNarrativeDraft, DossierSectionDraft
        from app.services.dossier_writer.neuronwriter_adapter import recommend_for_draft
        from app.services.dossier_writer.redaction import public_safe_topic_text
    except Exception:
        return {"status": "unavailable", "reason": "neuronwriter_adapter_unavailable"}
    safe_topic = public_safe_topic_text(
        " ".join(
            part
            for part in (
                title,
                summary,
                counterparty,
                " ".join(str(item or "") for item in list(dict(assessment or {}).get("match_reasons_json") or [])[:3]),
                " ".join(str(item or "") for item in list(dict(assessment or {}).get("mismatch_reasons_json") or [])[:2]),
            )
            if str(part or "").strip()
        ),
        limit=420,
    )
    draft = DossierNarrativeDraft(
        dossier_id="property_review_page",
        privacy_mode="agent_share",
        packet_kind="agent_brief",
        language=str(os.getenv("PROPERTYQUARRY_NEURONWRITER_LANGUAGE") or "German").strip() or "German",
        tone="premium analytical",
        sections=[
            DossierSectionDraft(
                section_key="review_page",
                title="Property review page",
                claims_used=[],
                body_markdown=safe_topic,
                confidence="medium",
            )
        ],
        generated_by="propertyquarry_review_page.neuronwriter_public_safe.v1",
    )
    recommendation = recommend_for_draft(draft)
    dump = recommendation.model_dump() if hasattr(recommendation, "model_dump") else dict(recommendation or {})
    return {
        "status": str(dump.get("status") or "").strip(),
        "mode": str(dump.get("mode") or "").strip(),
        "reason": str(dump.get("reason") or "").strip(),
        "query_id": str(dump.get("query_id") or "").strip(),
        "query_url": str(dump.get("query_url") or "").strip(),
        "share_url": str(dump.get("share_url") or "").strip(),
        "readonly_url": str(dump.get("readonly_url") or "").strip(),
        "headings": [
            str(item or "").strip()
            for item in list(dump.get("headings") or [])
            if str(item or "").strip()
        ][:4],
        "questions": [
            str(item or "").strip()
            for item in list(dump.get("questions") or [])
            if str(item or "").strip()
        ][:4],
        "safe_topic": safe_topic,
        "generated_by": "propertyquarry_review_page.neuronwriter_public_safe.v1",
    }


def _property_candidate_matches_requested_location(
    *,
    location_hints: tuple[str, ...],
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
    country_code: str = "",
    region_code: str = "",
) -> bool:
    hints = tuple(str(item or "").strip() for item in location_hints if str(item or "").strip())
    if not hints:
        return True
    facts = dict(property_facts or {})
    def _listing_location_field(key: str) -> str:
        value = str(facts.get(key) or "").strip()
        return "" if _property_location_value_is_source_scope_placeholder(value, facts) else value

    address_lines = tuple(
        value
        for value in (str(item or "").strip() for item in list(facts.get("address_lines") or []))
        if value and not _property_location_value_is_source_scope_placeholder(value, facts)
    )
    concrete_parts = [
        str(property_url or "").strip(),
        str(title or "").strip(),
        str(summary or "").strip(),
        _listing_location_field("district"),
        _listing_location_field("postal_name"),
        _listing_location_field("location"),
        _listing_location_field("address"),
        _listing_location_field("street_address"),
        _listing_location_field("exact_address"),
        *address_lines,
    ]
    real_concrete_parts = [
        str(property_url or "").strip(),
        str(title or "").strip(),
        str(summary or "").strip(),
        _listing_location_field("district"),
        _listing_location_field("postal_name"),
        _listing_location_field("location"),
        _listing_location_field("address"),
        _listing_location_field("street_address"),
        _listing_location_field("exact_address"),
        *address_lines,
    ]
    strong_concrete_parts = [
        str(property_url or "").strip(),
        str(title or "").strip(),
        _listing_location_field("district"),
        _listing_location_field("postal_name"),
        _listing_location_field("location"),
        _listing_location_field("address"),
        _listing_location_field("street_address"),
        _listing_location_field("exact_address"),
        *address_lines,
    ]

    concrete_text = " ".join(part for part in concrete_parts if part).lower()
    normalized_concrete_text = re.sub(r"[^a-z0-9äöüß]+", "", concrete_text)
    real_concrete_text = " ".join(part for part in real_concrete_parts if part).lower()
    strong_concrete_text = " ".join(part for part in strong_concrete_parts if part).lower()
    normalized_real_concrete_text = re.sub(r"[^a-z0-9äöüß]+", "", real_concrete_text)

    def _matches_text(raw_text: str, normalized_text: str) -> bool:
        for hint in hints:
            lowered_hint = str(hint or "").strip().lower()
            if not lowered_hint:
                continue
            if lowered_hint in {"vienna", "wien"} and ("vienna" in raw_text or "wien" in raw_text):
                return True
            if lowered_hint in raw_text:
                return True
            normalized_hint = re.sub(r"[^a-z0-9äöüß]+", "", lowered_hint)
            if normalized_hint and normalized_hint in normalized_text:
                return True
            hint_tokens = tuple(token for token in _google_location_query_tokens(lowered_hint) if token not in {"vienna", "wien", "austria", "osterreich", "österreich"})
            if hint_tokens and all(token in raw_text or token in normalized_text for token in hint_tokens):
                return True
        return False

    hint_text = " ".join(hints).lower()
    explicit_hint_postal_codes = frozenset(re.findall(r"\b\d{4,5}\b", hint_text))
    wants_vienna = "wien" in hint_text or "vienna" in hint_text or any(str(code).startswith("1") for code in explicit_hint_postal_codes)
    observed_listing_postal_codes = _property_listing_observed_postal_codes(
        title=title,
        summary=summary,
        property_facts=facts,
    )
    if explicit_hint_postal_codes and observed_listing_postal_codes and not any(
        code in explicit_hint_postal_codes for code in observed_listing_postal_codes
    ):
        return False
    if wants_vienna and observed_listing_postal_codes and not any(str(code).startswith("1") for code in observed_listing_postal_codes):
        return False
    real_concrete_postal_codes = tuple(re.findall(r"\b\d{4,5}\b", real_concrete_text))
    strong_concrete_postal_codes = tuple(re.findall(r"\b\d{4,5}\b", strong_concrete_text))
    exact_postal_match = bool(
        explicit_hint_postal_codes
        and real_concrete_postal_codes
        and any(code in explicit_hint_postal_codes for code in real_concrete_postal_codes)
    )
    strong_exact_postal_match = bool(
        explicit_hint_postal_codes
        and strong_concrete_postal_codes
        and any(code in explicit_hint_postal_codes for code in strong_concrete_postal_codes)
    )
    if explicit_hint_postal_codes and real_concrete_postal_codes and not any(
        code in explicit_hint_postal_codes for code in real_concrete_postal_codes
    ):
        return False
    if wants_vienna and real_concrete_postal_codes and not any(str(code).startswith("1") for code in real_concrete_postal_codes):
        return False
    if wants_vienna and _property_text_has_explicit_non_vienna_location(real_concrete_text):
        return False
    effective_country_code = str(country_code or facts.get("country_code") or "").strip()
    effective_region_code = str(region_code or facts.get("region_code") or "").strip()
    if _property_location_text_conflicts_with_hints(
        country_code=effective_country_code,
        region_code=effective_region_code,
        location_hints=hints,
        concrete_text=real_concrete_text,
    ) and not strong_exact_postal_match:
        return False
    if wants_vienna and not explicit_hint_postal_codes:
        if observed_listing_postal_codes and any(str(code).startswith("1") for code in observed_listing_postal_codes):
            return True
        if real_concrete_postal_codes and any(str(code).startswith("1") for code in real_concrete_postal_codes):
            return True

    concrete_postal_codes = tuple(re.findall(r"\b\d{4,5}\b", concrete_text))
    if concrete_postal_codes:
        if explicit_hint_postal_codes and not any(code in explicit_hint_postal_codes for code in concrete_postal_codes):
            return False
        if wants_vienna and not any(str(code).startswith("1") for code in concrete_postal_codes):
            return False

    if explicit_hint_postal_codes:
        # Exact postal/district selections are hard filters. A provider/search-page
        # scope such as "Willhaben | ... | 1010 Vienna" is not listing evidence.
        return bool(exact_postal_match or _matches_text(real_concrete_text, normalized_real_concrete_text))

    if _matches_text(concrete_text, normalized_concrete_text):
        return True
    return False


def _property_search_adjacent_area_radius_m(preferences: dict[str, object] | None) -> int:
    packet = dict(preferences or {})
    direct_value = packet.get("adjacent_area_radius_m")
    try:
        direct_meters = int(float(direct_value))
    except Exception:
        direct_meters = 0
    if direct_meters > 0:
        return max(0, direct_meters)
    raw_value = packet.get("adjacent_area_radius_value")
    try:
        unit_value = max(0.0, float(raw_value))
    except Exception:
        unit_value = 0.0
    unit = str(packet.get("adjacent_area_radius_unit") or "m").strip().lower()
    multiplier = 1000 if unit == "km" else 1
    radius_m = max(0, int(round(unit_value * multiplier)))
    if radius_m > 0:
        return radius_m
    raw_preferences = packet.get("raw_preferences")
    if isinstance(raw_preferences, dict):
        return _property_search_adjacent_area_radius_m(raw_preferences)
    return 0


def _property_search_adjacent_location_hints(preferences: dict[str, object] | None) -> tuple[str, ...]:
    payload = dict(preferences or {})
    location_hints = _property_search_location_hints(payload)
    effective_radius_m = _property_search_effective_adjacent_area_radius_m(
        preferences=payload,
        location_hints=location_hints,
    )
    if effective_radius_m <= 0:
        return ()
    search_payload = dict(payload)
    search_payload["adjacent_area_radius_m"] = effective_radius_m
    try:
        return adjacent_location_query_variants(search_payload)
    except Exception:
        return ()


def _property_candidate_point(property_facts: dict[str, object] | None) -> tuple[float, float] | None:
    facts = dict(property_facts or {})
    try:
        lat = float(
            facts.get("map_lat")
            or facts.get("lat")
            or facts.get("latitude")
            or 0.0
        )
        lng = float(
            facts.get("map_lng")
            or facts.get("lng")
            or facts.get("lon")
            or facts.get("longitude")
            or 0.0
        )
    except Exception:
        return None
    if not lat or not lng:
        return None
    return lat, lng


def _property_search_area_reference_points(
    *,
    location_hints: tuple[str, ...],
    country_code: str = "",
    region_code: str = "",
) -> tuple[tuple[float, float], ...]:
    references: list[tuple[float, float]] = []
    region_hint = str(region_code or "").replace("_", " ").strip()
    country_hint = str(country_code or "").strip()
    for hint in location_hints:
        normalized_hint = str(hint or "").strip()
        if not normalized_hint:
            continue
        query_options = [normalized_hint]
        if region_hint and region_hint.lower() not in normalized_hint.lower():
            query_options.append(f"{normalized_hint}, {region_hint}")
        if country_hint and country_hint.lower() not in normalized_hint.lower():
            query_options.append(f"{normalized_hint}, {country_hint}")
        if region_hint and country_hint:
            query_options.append(f"{normalized_hint}, {region_hint}, {country_hint}")
        point: tuple[float, float] | None = None
        for query in query_options:
            geocoded = _property_research_forward_geocode(query)
            try:
                point = (float(geocoded.get("lat") or 0.0), float(geocoded.get("lon") or 0.0))
            except Exception:
                point = None
            if point and all(point):
                break
        if point and all(point):
            references.append(point)
    return tuple(references)


def _property_search_area_boundary_geojsons(
    *,
    location_hints: tuple[str, ...],
    country_code: str = "",
    region_code: str = "",
) -> tuple[dict[str, object], ...]:
    boundaries: list[dict[str, object]] = []
    region_hint = str(region_code or "").replace("_", " ").strip()
    country_hint = str(country_code or "").strip()
    seen_display_names: set[str] = set()
    for hint in location_hints:
        normalized_hint = str(hint or "").strip()
        if not normalized_hint:
            continue
        query_options = [normalized_hint]
        if region_hint and region_hint.lower() not in normalized_hint.lower():
            query_options.append(f"{normalized_hint}, {region_hint}")
        if country_hint and country_hint.lower() not in normalized_hint.lower():
            query_options.append(f"{normalized_hint}, {country_hint}")
        if region_hint and country_hint:
            query_options.append(f"{normalized_hint}, {region_hint}, {country_hint}")
        for query in query_options:
            record = _property_research_boundary_record(query)
            geojson = dict(record.get("geojson") or {}) if isinstance(record.get("geojson"), dict) else {}
            if not _property_research_geojson_outer_rings(geojson):
                continue
            display_name = str(record.get("display_name") or query).strip().lower()
            if display_name in seen_display_names:
                continue
            seen_display_names.add(display_name)
            boundaries.append(geojson)
            break
    return tuple(boundaries)


def _property_candidate_within_adjacent_area_radius(
    *,
    location_hints: tuple[str, ...],
    property_facts: dict[str, object] | None,
    country_code: str = "",
    region_code: str = "",
    adjacent_area_radius_m: int = 0,
) -> bool:
    if adjacent_area_radius_m <= 0:
        return False
    candidate_point = _property_candidate_point(property_facts)
    if candidate_point is None:
        return False
    candidate_lat, candidate_lon = candidate_point
    boundary_geojsons = _property_search_area_boundary_geojsons(
        location_hints=location_hints,
        country_code=country_code,
        region_code=region_code,
    )
    for geojson in boundary_geojsons:
        try:
            distance_m = _property_research_point_to_geojson_distance_m(candidate_lat, candidate_lon, geojson)
        except Exception:
            continue
        if distance_m is not None and distance_m <= float(adjacent_area_radius_m):
            return True

    reference_points = _property_search_area_reference_points(
        location_hints=location_hints,
        country_code=country_code,
        region_code=region_code,
    )
    if not reference_points:
        return False
    for ref_lat, ref_lon in reference_points:
        try:
            distance_m = _property_research_distance_m(candidate_lat, candidate_lon, ref_lat, ref_lon)
        except Exception:
            continue
        if distance_m <= adjacent_area_radius_m:
            return True
    return False


def _property_candidate_search_area_interior_ratio(
    *,
    location_hints: tuple[str, ...],
    property_facts: dict[str, object] | None,
    country_code: str = "",
    region_code: str = "",
) -> float | None:
    candidate_point = _property_candidate_point(property_facts)
    if candidate_point is None:
        return None
    candidate_lat, candidate_lon = candidate_point
    ratios: list[float] = []
    for geojson in _property_search_area_boundary_geojsons(
        location_hints=location_hints,
        country_code=country_code,
        region_code=region_code,
    ):
        try:
            ratio = _property_research_point_to_geojson_interior_ratio(candidate_lat, candidate_lon, geojson)
        except Exception:
            ratio = None
        if ratio is not None:
            ratios.append(float(ratio))
    if not ratios:
        return None
    return max(0.0, min(max(ratios), 1.0))


def _property_candidate_matches_search_area(
    *,
    location_hints: tuple[str, ...],
    request_preferences: dict[str, object] | None,
    source_spec: dict[str, object] | None,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> bool:
    preferences = dict(request_preferences or {})
    source = dict(source_spec or {})
    facts = dict(property_facts or {})
    effective_country_code = str(preferences.get("country_code") or source.get("country_code") or "").strip()
    effective_region_code = str(preferences.get("region_code") or "").strip()
    effective_adjacent_area_radius_m = _property_search_effective_adjacent_area_radius_m(
        preferences=preferences,
        location_hints=location_hints,
    )
    if _property_candidate_matches_requested_location(
        location_hints=location_hints,
        property_url=property_url,
        title=title,
        summary=summary,
        property_facts=facts,
        country_code=effective_country_code,
        region_code=effective_region_code,
    ):
        return True
    if _property_candidate_soft_matches_broad_search_area(
        location_hints=location_hints,
        request_preferences=preferences,
        property_url=property_url,
        title=title,
        summary=summary,
        property_facts=facts,
        country_code=effective_country_code,
        region_code=effective_region_code,
    ):
        return True
    adjacent_location_hints = _property_search_adjacent_location_hints(preferences)
    if adjacent_location_hints and _property_candidate_matches_requested_location(
        location_hints=adjacent_location_hints,
        property_url=property_url,
        title=title,
        summary=summary,
        property_facts=facts,
        country_code=effective_country_code,
        region_code=effective_region_code,
    ):
        return True
    return _property_candidate_within_adjacent_area_radius(
        location_hints=location_hints,
        property_facts=facts,
        country_code=effective_country_code,
        region_code=effective_region_code,
        adjacent_area_radius_m=effective_adjacent_area_radius_m,
    )


def _property_candidate_soft_matches_broad_search_area(
    *,
    location_hints: tuple[str, ...],
    request_preferences: dict[str, object] | None,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
    country_code: str = "",
    region_code: str = "",
) -> bool:
    preferences = dict(request_preferences or {})
    facts = dict(property_facts or {})
    if not location_hints:
        return False
    if _property_search_has_exact_scope(
        request_preferences=preferences,
        location_hints=location_hints,
    ):
        return False
    evidence_kind = _property_candidate_notification_location_evidence_kind(
        property_url=property_url,
        title=title,
        summary=summary,
        property_facts=facts,
    )
    if evidence_kind != "source_scope_only":
        return False
    source_scope_location = str(facts.get("source_scope_location") or "").strip()
    source_city = str(facts.get("source_city") or "").strip()
    source_postal_code = str(facts.get("source_postal_code") or "").strip()
    synthetic_location = ""
    if source_postal_code and source_city:
        synthetic_location = f"{source_postal_code} {source_city}".strip()
    elif source_scope_location:
        synthetic_location = source_scope_location
    elif source_city:
        synthetic_location = source_city
    if not synthetic_location:
        return False
    synthetic_facts = dict(facts)
    for key in ("source_scope_location", "source_postal_code", "source_city"):
        synthetic_facts.pop(key, None)
    for key in ("postal_name", "location", "district"):
        current = str(synthetic_facts.get(key) or "").strip()
        if not current:
            synthetic_facts[key] = synthetic_location
    if source_city and not str(synthetic_facts.get("city") or "").strip():
        synthetic_facts["city"] = source_city
    return _property_candidate_matches_requested_location(
        location_hints=location_hints,
        property_url=property_url,
        title=title,
        summary=summary,
        property_facts=synthetic_facts,
        country_code=country_code,
        region_code=region_code,
    )


def _property_candidate_url_has_location_probe(property_url: str) -> bool:
    parsed = urllib.parse.urlparse(str(property_url or "").strip())
    host = str(parsed.netloc or "").strip().lower()
    path = urllib.parse.unquote(str(parsed.path or "").strip().lower())
    if not host or not path:
        return False
    if "willhaben.at" in host:
        return "/iad/immobilien/d/" in path
    return bool(
        re.search(r"\b\d{4,5}\b", path)
        or any(
            marker in path
            for marker in (
                "/wien/",
                "wien-",
                "vienna",
                "salzburg",
                "steiermark",
                "oberoesterreich",
                "oberösterreich",
                "niederoesterreich",
                "niederösterreich",
                "burgenland",
                "kaernten",
                "kärnten",
                "tirol",
                "vorarlberg",
            )
        )
    )


def _property_candidate_url_has_exact_location_probe(property_url: str) -> bool:
    parsed = urllib.parse.urlparse(str(property_url or "").strip())
    path = urllib.parse.unquote(str(parsed.path or "").strip().lower())
    if not path:
        return False
    return bool(
        re.search(r"\b\d{4,5}\b", path)
        or re.search(r"\bwien-\d{4}\b", path)
        or re.search(r"\bvienna-\d{4}\b", path)
    )


def _property_candidate_notification_price_signal(
    facts: dict[str, object],
    *,
    listing_mode: str,
    title: object = "",
) -> str:
    normalized_mode = str(listing_mode or "").strip().lower()
    if normalized_mode == "buy":
        for key in (
            "price_display",
            "purchase_price_display",
            "buy_price_display",
            "price_eur",
            "purchase_price_eur",
            "buy_price_eur",
            "kaufpreis_eur",
        ):
            value = facts.get(key)
            if key.endswith("_eur"):
                try:
                    amount = float(str(value).replace(",", "").strip())
                except Exception:
                    amount = 0.0
                if amount > 0.0:
                    return f"{amount:.0f}"
            elif str(value or "").strip():
                return str(value).strip()
    else:
        for key in (
            "rent_display",
            "monthly_rent_display",
            "warm_rent_display",
            "cold_rent_display",
            "total_rent_display",
            "gesamtmiete_display",
            "rent_eur",
            "total_rent_eur",
            "warm_rent_eur",
            "cold_rent_eur",
        ):
            value = facts.get(key)
            if key.endswith("_eur"):
                try:
                    amount = float(str(value).replace(",", "").strip())
                except Exception:
                    amount = 0.0
                if amount > 0.0:
                    return f"{amount:.0f}"
            elif str(value or "").strip():
                return str(value).strip()
    title_text = " ".join(str(title or "").split()).strip()
    if not title_text:
        return ""
    currency_pattern = "|".join(re.escape(code) for code in supported_currency_codes())
    for pattern in (
        r"(€\s?[0-9][0-9\.\s]*(?:,[0-9]{1,2})?\s*,-?)",
        rf"((?:{currency_pattern})\s?[0-9][0-9\.,\s]*)",
    ):
        match = re.search(pattern, title_text, flags=re.IGNORECASE)
        if match:
            return " ".join(str(match.group(1) or "").split()).strip(" ,")
    return ""


