_PROPERTY_SEARCH_FUZZY_DISTRICT_ADJACENT_RADIUS_M = 4000


def _property_search_has_explicit_selected_area(preferences: dict[str, object] | None) -> bool:
    payload = dict(preferences or {})
    for key in ("selected_location_values", "selected_districts"):
        values = payload.get(key)
        if isinstance(values, (list, tuple, set)) and any(str(value or "").strip() for value in values):
            return True
    raw_preferences = payload.get("raw_preferences")
    if isinstance(raw_preferences, dict):
        for key in ("selected_location_values", "selected_districts"):
            values = raw_preferences.get(key)
            if isinstance(values, (list, tuple, set)) and any(str(value or "").strip() for value in values):
                return True
    return False


def _property_search_effective_adjacent_area_radius_m(
    *,
    preferences: dict[str, object] | None,
    location_hints: tuple[str, ...],
) -> int:
    configured_radius_m = _property_search_adjacent_area_radius_m(preferences)
    if configured_radius_m > 0:
        return configured_radius_m
    if _property_search_has_explicit_selected_area(preferences):
        return 0
    if (
        _property_search_mode(preferences) == "discovery"
        and any(
            re.search(r"\b\d{4,5}\b", str(value or ""))
            for value in location_hints
        )
    ):
        return _PROPERTY_SEARCH_FUZZY_DISTRICT_ADJACENT_RADIUS_M
    return 0


def _property_candidate_listing_mode_evidence(
    *,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> dict[str, object]:
    facts = dict(property_facts or {})
    mode_values = " ".join(
        str(facts.get(key) or "").strip().casefold()
        for key in ("listing_mode", "transaction_type", "marketing_type", "offer_type", "deal_type")
        if str(facts.get(key) or "").strip()
    )
    text = html.unescape(
        " ".join(
            part
            for part in (
                urllib.parse.unquote(str(property_url or "")),
                str(title or ""),
                str(summary or ""),
                mode_values,
            )
            if str(part or "").strip()
        )
    ).casefold()
    rent_text_markers = tuple(marker for marker in _PROPERTY_RENT_LISTING_MARKERS if marker in text)
    buy_text_markers = tuple(marker for marker in _PROPERTY_BUY_LISTING_MARKERS if marker in text)
    rent_fact_keys = (
        "rent_display",
        "monthly_rent_display",
        "warm_rent_display",
        "cold_rent_display",
        "total_rent_display",
        "gesamtmiete_display",
        "rent_eur",
        "total_rent_eur",
        "warm_rent_eur",
        "cold_rent_eur",
        "monthly_rent_eur",
    )
    buy_fact_keys = (
        "purchase_price_display",
        "buy_price_display",
        "kaufpreis_display",
        "purchase_price_eur",
        "buy_price_eur",
        "kaufpreis_eur",
        "valuation_eur",
        "reserve_price_eur",
    )
    rent_fact_signal = any(str(facts.get(key) or "").strip() for key in rent_fact_keys)
    buy_fact_signal = any(str(facts.get(key) or "").strip() for key in buy_fact_keys)
    generic_price_signal = any(str(facts.get(key) or "").strip() for key in ("price_eur", "price_display", "price"))
    mode_rent_signal = any(marker in mode_values for marker in ("rent", "rental", "miete", "mieten", "lease"))
    mode_buy_signal = any(marker in mode_values for marker in ("buy", "sale", "kauf", "kaufen", "verkauf"))
    rent_text_signal = bool(rent_text_markers or mode_rent_signal)
    buy_text_signal = bool(buy_text_markers or mode_buy_signal)
    if generic_price_signal and buy_text_signal and not rent_text_signal:
        buy_fact_signal = True
    return {
        "rent_text_signal": rent_text_signal,
        "buy_text_signal": buy_text_signal,
        "rent_fact_signal": rent_fact_signal,
        "buy_fact_signal": buy_fact_signal,
        "rent_text_markers": list(rent_text_markers[:8]),
        "buy_text_markers": list(buy_text_markers[:8]),
    }


def _property_candidate_listing_mode_mismatch(
    *,
    listing_mode: str,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> bool:
    normalized_mode = normalize_listing_mode(listing_mode)
    evidence = _property_candidate_listing_mode_evidence(
        property_url=property_url,
        title=title,
        summary=summary,
        property_facts=property_facts,
    )
    rent_signal = bool(evidence.get("rent_text_signal") or evidence.get("rent_fact_signal"))
    buy_signal = bool(evidence.get("buy_text_signal") or evidence.get("buy_fact_signal"))
    if normalized_mode == "rent":
        return bool(
            (evidence.get("buy_text_signal") and not evidence.get("rent_text_signal"))
            or (buy_signal and not rent_signal)
        )
    if normalized_mode == "buy":
        return bool(
            (evidence.get("rent_text_signal") and not evidence.get("buy_text_signal"))
            or (rent_signal and not buy_signal)
        )
    return False


def _property_candidate_is_generic_listing_page(
    *,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> bool:
    facts = dict(property_facts or {})
    text = " ".join(
        part
        for part in (
            str(title or "").strip(),
            str(summary or "").strip(),
            str(property_url or "").strip(),
        )
        if part
    ).lower()
    url = str(property_url or "").strip().lower()
    parsed_url = urllib.parse.urlparse(url)
    path = parsed_url.path.rstrip("/")
    query = str(parsed_url.query or "").lower()
    concrete_signals = any(
        str(facts.get(key) or "").strip()
        for key in (
            "price_display",
            "purchase_price_display",
            "rent_display",
            "total_rent_display",
            "buy_price_eur",
            "purchase_price_eur",
            "price_eur",
            "rent_eur",
            "total_rent_eur",
            "warm_rent_eur",
            "cold_rent_eur",
            "monthly_rent_eur",
            "exact_address",
            "street_address",
            "listing_id",
            "listing_uuid",
        )
    )
    has_identity_or_address_signal = any(
        str(facts.get(key) or "").strip()
        for key in (
            "exact_address",
            "street_address",
            "listing_id",
            "listing_uuid",
        )
    )
    search_result_count_marker = bool(
        re.search(
            r"\b(?:wählen\s+sie\s+aus|waehlen\s+sie\s+aus|choose\s+from|browse)\s+[\d.,\s]{2,}\s+(?:angeboten|offers|properties|listings)\b",
            text,
            flags=re.IGNORECASE,
        )
    )
    title_text = str(title or "").strip().lower()
    title_has_postal_signal = bool(re.search(r"\b\d{4,5}\b", title_text))
    title_has_home_shape_signal = bool(
        re.search(r"\b\d+(?:[,.]\d+)?\s*(?:m²|m2|qm)\b", title_text)
        or re.search(r"\b\d+(?:[,.]\d+)?\s*(?:zimmer|room|rooms)\b", title_text)
    )
    title_has_concrete_listing_signal = bool(title_has_postal_signal and title_has_home_shape_signal)
    if search_result_count_marker and not has_identity_or_address_signal and not title_has_concrete_listing_signal:
        return True
    if (
        any(marker in path for marker in ("/d/", "/expose/", "/detail/", "/objekt/", "/object/"))
        or path.endswith(("/detail", "/objekt", "/object"))
        or any(marker in query for marker in ("objektnummer=", "objectid=", "object_id=", "adid=", "ad_id="))
    ):
        return False
    if concrete_signals:
        return False
    generic_title_markers = (
        "immobiliensuche",
        "bestandsobjekte",
        "projekte",
        "gemeindewohnungen",
        "angebote",
        "ausschreibungen",
        "wettbewerbe",
        "overview",
        "suche",
        "projektdetail",
        "immobilien",
        "projektentwickler",
        "architekturwettbewerbe",
    )
    generic_url_markers = (
        "/suche",
        "/projekte",
        "/projekt/",
        "/angebote",
        "/ausschreibungen",
        "/wettbewerbe",
        "/immobilien/",
        "/immobilien",
        "/overview",
        "/bestandsobjekte",
        "/gemeindewohnungen",
    )
    generic_marker_hits = sum(1 for marker in generic_title_markers if marker in text)
    has_area_signal = any(str(facts.get(key) or "").strip() for key in ("area_sqm", "living_area_sqm", "usable_area_sqm", "area_m2", "living_area_m2"))
    has_rooms_signal = any(str(facts.get(key) or "").strip() for key in ("rooms", "room_count", "rooms_label"))
    has_detail_signal = bool(concrete_signals or has_area_signal or has_rooms_signal)
    non_listing_page_markers = (
        "architekturwettbewerb",
        "architekturwettbewerbe",
        "ausschreibung",
        "ausschreibungen",
        "wettbewerb",
        "wettbewerbe",
        "presseaussendung",
        "pressemitteilung",
        "newsroom",
        "news",
        "karriere",
        "jobs",
        "blog",
    )
    residential_listing_signals = (
        "wohnung",
        "mietwohnung",
        "eigentumswohnung",
        "haus",
        "zimmer",
        "balkon",
        "terrasse",
        "garten",
    )
    return bool(
        any(marker in url for marker in generic_url_markers)
        or (
            any(marker in text for marker in non_listing_page_markers)
            and not any(signal in text for signal in residential_listing_signals)
            and not has_detail_signal
        )
        or (generic_marker_hits >= 2 and not has_detail_signal)
        or ("angebote" in text and "wohnung" not in text and not has_detail_signal)
    )


def _property_candidate_has_concrete_location(property_facts: dict[str, object] | None) -> bool:
    facts = dict(property_facts or {})
    exact_address = str(facts.get("exact_address") or "").strip()
    street_address = str(facts.get("street_address") or "").strip()
    district = str(facts.get("district") or "").strip()
    postal_name = str(facts.get("postal_name") or "").strip()
    location = str(facts.get("location") or "").strip()

    for value in (exact_address, street_address, district):
        if value and not _property_location_value_is_source_scope_placeholder(value, facts):
            return True
    for value in (postal_name, location):
        lowered = value.lower()
        if not lowered:
            continue
        if _property_location_value_is_source_scope_placeholder(value, facts):
            continue
        if re.search(r"\b\d{4,5}\b", lowered):
            return True
        if any(token in lowered for token in ("gasse", "straße", "strasse", "weg", "platz", "allee", "lane", "road", "street", "avenue", "drive")):
            return True
        if lowered not in {"wien", "vienna", "österreich", "osterreich", "austria"}:
            return True
    return False


def _property_candidate_notification_location_evidence_kind(
    *,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> str:
    facts = dict(property_facts or {})
    if _property_listing_observed_postal_codes(title=title, summary=summary, property_facts=facts):
        return "listing_postal"
    if _property_candidate_url_has_exact_location_probe(property_url):
        return "url_postal"
    if _property_candidate_has_concrete_location(facts):
        return "listing_concrete"
    if _property_candidate_url_has_location_probe(property_url):
        return "url_region"
    if any(
        str(facts.get(key) or "").strip()
        for key in ("source_scope_location", "source_postal_code", "source_city")
    ):
        return "source_scope_only"
    return "missing"


def _property_candidate_notification_location_evidence_is_concrete(evidence_kind: object) -> bool:
    return str(evidence_kind or "").strip() in {"listing_postal", "url_postal", "listing_concrete"}


def _property_candidate_has_concrete_area(property_facts: dict[str, object] | None) -> bool:
    facts = dict(property_facts or {})
    return isinstance(_property_investment_area_sqm(facts), float)


def _property_candidate_display_facts(payload: dict[str, object]) -> dict[str, object]:
    top_level_facts = dict(payload.get("property_facts") or {}) if isinstance(payload.get("property_facts"), dict) else {}
    if isinstance(payload.get("property_facts_json"), dict):
        top_level_facts = {**top_level_facts, **dict(payload.get("property_facts_json") or {})}
    snapshot = dict(top_level_facts.get("listing_research_snapshot") or {}) if isinstance(top_level_facts.get("listing_research_snapshot"), dict) else {}
    merged = {**top_level_facts, **snapshot}

    def _normalized(value: object) -> str:
        return re.sub(r"\s+", " ", str(value or "").strip()).casefold()

    source_scope_location = str(top_level_facts.get("source_scope_location") or merged.get("source_scope_location") or "").strip()
    source_city = str(top_level_facts.get("source_city") or merged.get("source_city") or "").strip()
    source_postal_code = str(top_level_facts.get("source_postal_code") or merged.get("source_postal_code") or "").strip()
    source_scope_candidates = {
        _normalized(source_scope_location),
        _normalized(source_city),
    }
    if source_postal_code and source_city:
        source_scope_candidates.add(_normalized(f"{source_postal_code} {source_city}"))
    source_scope_candidates.discard("")

    listing_text = " ".join(
        part
        for part in (
            str(payload.get("title") or "").strip(),
            str(payload.get("listing_title") or "").strip(),
            str(payload.get("summary") or "").strip(),
        )
        if part
    )
    listing_postal_evidence = _property_postal_location_evidence(listing_text)
    listing_postal_name = str((listing_postal_evidence[0] if listing_postal_evidence else {}).get("postal_name") or "").strip()
    listing_postal_code = _property_postal_code_core(listing_postal_name)
    if listing_postal_name and (
        not str(merged.get("postal_name") or "").strip()
        or _normalized(merged.get("postal_name")) in source_scope_candidates
        or (source_postal_code and listing_postal_code and source_postal_code != listing_postal_code)
    ):
        merged["postal_name"] = listing_postal_name
        for key in ("district", "location", "address", "city"):
            current = str(merged.get(key) or "").strip()
            if not current or _normalized(current) in source_scope_candidates or (source_postal_code and listing_postal_code and source_postal_code != listing_postal_code):
                merged[key] = listing_postal_name

    if not snapshot:
        return merged

    def _is_scope_placeholder(value: object) -> bool:
        normalized_value = _normalized(value)
        if not normalized_value:
            return False
        return normalized_value in source_scope_candidates

    for key in ("district", "location", "postal_name", "address", "street_address", "exact_address", "city"):
        snapshot_value = str(snapshot.get(key) or "").strip()
        top_value = str(top_level_facts.get(key) or "").strip()
        if snapshot_value and (not top_value or _is_scope_placeholder(top_value)):
            merged[key] = snapshot_value
    return merged


def _property_candidate_google_maps_url(candidate: dict[str, object]) -> str:
    facts = _property_candidate_display_facts(candidate)

    def _text(*values: object) -> str:
        return next((str(value or "").strip() for value in values if str(value or "").strip()), "")

    lat = _text(facts.get("map_lat"), facts.get("lat"), facts.get("latitude"))
    lng = _text(facts.get("map_lng"), facts.get("lng"), facts.get("lon"), facts.get("longitude"))
    if lat and lng:
        return f"https://www.google.com/maps/search/?api=1&query={urllib.parse.quote(f'{lat},{lng}', safe=',')}"
    address_lines = " ".join(str(item or "").strip() for item in list(facts.get("address_lines") or []) if str(item or "").strip())
    query = _text(
        facts.get("exact_address"),
        facts.get("street_address"),
        facts.get("address"),
        address_lines,
        facts.get("postal_name"),
        facts.get("location"),
        candidate.get("title"),
    )
    if not query:
        return ""
    return f"https://www.google.com/maps/search/?api=1&query={urllib.parse.quote(query)}"


def _property_candidate_title_looks_like_url(value: object) -> bool:
    text = str(value or "").strip()
    if not text:
        return False
    try:
        parsed = urllib.parse.urlparse(text)
    except Exception:
        return False
    return bool(parsed.scheme in {"http", "https"} and parsed.netloc)


def _property_candidate_search_page_display(candidate: dict[str, object]) -> dict[str, object]:
    row = dict(candidate or {})
    title = str(row.get("title") or row.get("listing_title") or "").strip()
    property_url = str(row.get("property_url") or row.get("source_url") or "").strip()
    if not _property_candidate_title_looks_like_url(title):
        return row
    url = property_url or title
    try:
        parsed = urllib.parse.urlparse(url)
        query = urllib.parse.parse_qs(parsed.query)
    except Exception:
        parsed = urllib.parse.urlparse("")
        query = {}
    host = str(parsed.netloc or "").lower().removeprefix("www.")
    provider = str(row.get("source_label") or row.get("source_platform") or "").strip()
    if not provider:
        provider = {
            "remax.at": "RE/MAX Austria",
            "willhaben.at": "Willhaben",
        }.get(host, host or "Provider")
    location = str((query.get("q") or [""])[0] or row.get("location_label") or "").strip()
    location = urllib.parse.unquote_plus(location)
    min_area = str((query.get("minArea") or [""])[0] or "").strip()
    max_price = str((query.get("maxPrice") or [""])[0] or "").strip()
    title_parts = [provider]
    if location:
        title_parts.append(location)
    title_parts.append("search candidate")
    row["title"] = " · ".join(part for part in title_parts if part)
    detail_parts: list[str] = []
    if max_price:
        detail_parts.append(f"up to EUR {max_price}")
    if min_area:
        detail_parts.append(f"from {min_area} m2")
    filter_text = ", ".join(detail_parts)
    row["summary"] = (
        f"{provider} returned a search-results page"
        + (f" for {location}" if location else "")
        + (f" ({filter_text})" if filter_text else "")
        + ". PropertyQuarry is still extracting a concrete listing before this becomes a confirmed property."
    )
    row["display_title_was_url"] = True
    return row


def _property_search_ranked_candidates_from_sources(sources: object, *, limit: int | None = None) -> list[dict[str, object]]:
    rows_by_key: dict[str, dict[str, object]] = {}
    order_keys: list[str] = []

    hard_filter_reasons = {
        "area_mismatch",
        "availability_mismatch",
        "generic_listing_page",
        "listing_mode_mismatch",
        "location_mismatch",
        "location_scope",
        "outside_selected_area",
        "property_location_conflicts_with_active_search",
        "property_missing_concrete_location",
        "property_type_mismatch",
        "transaction_mismatch",
        "wrong_listing_mode",
        "wrong_property_type",
    }

    def _candidate_is_rankable(candidate: dict[str, object]) -> bool:
        status_fields = (
            "status",
            "review_status",
            "candidate_status",
            "filter_status",
            "repair_status",
        )
        blocked_statuses = {
            "dismissed",
            "filtered",
            "filtered_out",
            "hard_filtered",
            "maybe_false",
            "maybe_false_positive",
            "false_positive",
            "not_a_listing",
            "repair_only",
            "queued_for_repair",
        }
        if any(str(candidate.get(field) or "").strip().lower() in blocked_statuses for field in status_fields):
            return False
        blocked_flags = (
            "maybe_false",
            "maybe_false_positive",
            "false_positive",
            "flagged_for_repair",
            "repair_only",
            "filtered_out",
            "hard_filtered",
            "not_a_listing",
        )
        if any(_property_truthy_flag(candidate.get(flag)) for flag in blocked_flags):
            return False
        if str(candidate.get("hard_filter_reason") or "").strip():
            return False
        filter_reason = str(candidate.get("filter_reason") or "").strip().lower()
        if filter_reason in hard_filter_reasons:
            return False
        return True

    def _candidate_ref(row: dict[str, object], source_label: str) -> str:
        explicit_ref = str(row.get("candidate_ref") or row.get("research_candidate_ref") or "").strip()
        if explicit_ref:
            return explicit_ref
        raw = "|".join(
            (
                str(row.get("title") or "").strip(),
                urllib.parse.urldefrag(str(row.get("property_url") or "").strip())[0],
                str(row.get("review_url") or "").strip(),
                str(row.get("source_ref") or "").strip(),
                source_label,
            )
        )
        return hashlib.sha1(raw.encode("utf-8")).hexdigest()[:16]

    def _candidate_conflicts_source_scope(candidate: dict[str, object], source: dict[str, object]) -> bool:
        source_scope_hints = _property_exact_source_scope_location_hints(
            source_url=str(source.get("source_url") or source.get("url") or "").strip(),
            source_label=str(
                source.get("source_scope_label")
                or source.get("source_label")
                or source.get("label")
                or source.get("platform")
                or ""
            ).strip(),
        )
        source_scope_codes = {
            _property_postal_code_core(code)
            for code in re.findall(r"\b\d{4,5}\b", " ".join(source_scope_hints))
        }
        source_scope_codes.discard("")
        if not source_scope_codes:
            return False
        facts = dict(candidate.get("property_facts") or {}) if isinstance(candidate.get("property_facts"), dict) else {}
        listing_codes = _property_listing_observed_postal_codes(
            title=str(candidate.get("title") or candidate.get("listing_title") or "").strip(),
            summary=str(candidate.get("summary") or candidate.get("fit_summary") or "").strip(),
            property_facts=facts,
        )
        if not listing_codes:
            return False
        return not any(code in source_scope_codes for code in listing_codes)

    def _merge_candidate_rows(current: dict[str, object], incoming: dict[str, object]) -> dict[str, object]:
        merged = dict(current)
        merged_facts = dict(current.get("property_facts") or {}) if isinstance(current.get("property_facts"), dict) else {}
        incoming_facts = dict(incoming.get("property_facts") or {}) if isinstance(incoming.get("property_facts"), dict) else {}
        if incoming_facts:
            merged_facts.update(incoming_facts)
        for key, value in incoming.items():
            if key == "property_facts":
                continue
            if merged.get(key) in (None, "", [], {}):
                merged[key] = value
                continue
            if key in {
                "tour_url",
                "vendor_tour_url",
                "flythrough_url",
                "tour_status",
                "flythrough_status",
                "tour_requested_at",
                "tour_status_updated_at",
                "tour_eta_minutes",
                "tour_progress_pct",
                "flythrough_requested_at",
                "flythrough_status_updated_at",
                "flythrough_eta_minutes",
                "flythrough_progress_pct",
                "flythrough_reason",
                "blocked_reason",
                "packet_url",
                "review_url",
                "preview_image_url",
                "property_url",
                "map_url",
            } and value not in (None, "", [], {}):
                merged[key] = value
        if merged_facts:
            merged["property_facts"] = merged_facts
        return merged

    for source in list(sources or []):
        if not isinstance(source, dict):
            continue
        source_label = str(source.get("source_label") or source.get("platform") or "Property scout").strip() or "Property scout"
        for key in ("top_candidates", "research_candidates"):
            for candidate in list(source.get(key) or []):
                if not isinstance(candidate, dict):
                    continue
                if not _candidate_is_rankable(candidate):
                    continue
                if _candidate_conflicts_source_scope(candidate, source):
                    continue
                row = dict(candidate)
                row.setdefault("source_label", source_label)
                row = _property_candidate_search_page_display(row)
                if not str(row.get("map_url") or "").strip():
                    row["map_url"] = _property_candidate_google_maps_url(row)
                row.setdefault("candidate_ref", _candidate_ref(row, source_label))
                dedupe_key = str(row.get("source_ref") or row.get("property_url") or row.get("listing_id") or row.get("candidate_ref") or "").strip()
                if dedupe_key and dedupe_key not in rows_by_key:
                    rows_by_key[dedupe_key] = row
                    order_keys.append(dedupe_key)
                    continue
                if dedupe_key:
                    rows_by_key[dedupe_key] = _merge_candidate_rows(rows_by_key[dedupe_key], row)
                    continue
                synthetic_key = f"row-{len(order_keys)+1}"
                rows_by_key[synthetic_key] = row
                order_keys.append(synthetic_key)
    rows = [rows_by_key[key] for key in order_keys if key in rows_by_key]
    rows.sort(key=lambda item: float(item.get("ranking_score") or item.get("investment_score") or item.get("fit_score") or 0.0), reverse=True)
    for index, row in enumerate(rows, start=1):
        row["rank"] = index
    if limit is None:
        return rows
    return rows[: max(1, min(int(limit or 50), 200))]


def _property_search_live_reviewed_total_from_message(message: object) -> int:
    text = str(message or "").strip()
    if not text:
        return 0
    patterns: tuple[tuple[re.Pattern[str], str], ...] = (
        (re.compile(r"\bReviewing candidate\s+(\d+)\s+of\s+\d+\b", flags=re.IGNORECASE), "minus_one"),
        (re.compile(r"\bConfirming [^.]* candidate\s+(\d+)\s+of\s+\d+\b", flags=re.IGNORECASE), "minus_one"),
        (re.compile(r"\bRanked\s+(\d+)\s+of\s+\d+\s+candidate listings\b", flags=re.IGNORECASE), "direct"),
        (re.compile(r"\bPrepared\s+(\d+)\s+listing preview\(s\)\b", flags=re.IGNORECASE), "direct"),
        (re.compile(r"\bScoring enriched candidate\s+\d+\s+of\s+(\d+)\b", flags=re.IGNORECASE), "direct"),
        (re.compile(r"\bEnriching top\s+\d+\s+candidate\(s\)\s+out of\s+(\d+)\b", flags=re.IGNORECASE), "direct"),
    )
    for pattern, mode in patterns:
        match = pattern.search(text)
        if match is None:
            continue
        try:
            value = max(0, int(match.group(1) or "0"))
        except Exception:
            continue
        if mode == "minus_one":
            return max(0, value - 1)
        return value
    return 0


