def _property_candidate_text(
    *,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> str:
    facts = dict(property_facts or {})
    fact_values: list[str] = []
    for value in facts.values():
        if isinstance(value, (str, int, float)):
            fact_values.append(str(value))
        elif isinstance(value, (list, tuple)):
            fact_values.extend(str(item) for item in value if isinstance(item, (str, int, float)))
    return " ".join(
        part
        for part in (
            str(property_url or ""),
            str(title or ""),
            str(summary or ""),
            *fact_values,
        )
        if str(part or "").strip()
    ).strip().lower()


def _property_candidate_has_floorplan(
    *,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
    preview: dict[str, object] | None = None,
) -> bool:
    facts = dict(property_facts or {})
    preview_payload = dict(preview or {})
    if _property_facts_have_floorplan(facts, preview=preview_payload):
        return True
    preview_facts = (
        dict(preview_payload.get("property_facts_json") or {})
        if isinstance(preview_payload.get("property_facts_json"), dict)
        else {}
    )
    if preview_facts and _property_facts_have_floorplan(preview_facts, preview=preview_payload):
        return True
    text_facts = {
        key: value
        for key, value in {**preview_facts, **facts}.items()
        if str(key or "").strip()
        not in {
            "floorplan_recovery_diagnostics",
            "missing_floorplan_diagnostics",
            "provider_recovery_diagnostics",
        }
    }
    text = " ".join(
        part
        for part in (
            _property_candidate_text(
                property_url=property_url,
                title=title,
                summary=summary,
                property_facts=text_facts,
            ),
            str(preview_payload.get("title") or "").lower(),
            str(preview_payload.get("summary") or "").lower(),
            str(preview_payload.get("listing_id") or "").lower(),
        )
        if str(part or "").strip()
    )
    negative_markers = (
        "no floorplan",
        "no floor plan",
        "no extracted floorplan",
        "without floorplan",
        "without a floor plan",
        "without clear floorplan",
        "kein grundriss",
        "keinen grundriss",
        "ohne grundriss",
    )
    if any(marker in text for marker in negative_markers):
        return False
    compact_text_value = re.sub(r"[^a-z0-9äöüß]+", "", text)
    markers = (
        "grundriss",
        "floor plan",
        "floorplan",
        "floor-plan",
        "lageplan",
        "raumskizze",
        "plan_top",
        "plantop",
        "layout plan",
    )
    return any(marker in text or marker.replace(" ", "").replace("-", "") in compact_text_value for marker in markers)


def _property_candidate_matches_requested_property_type(
    *,
    property_type: object,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> bool:
    requested_types = [item for item in normalize_property_type_values(property_type) if item]
    if not requested_types:
        return True
    if requested_types == ["any"]:
        requested_types = ["apartment", "house", "land"]

    facts = dict(property_facts or {})
    fact_types = normalize_property_type_values(
        facts.get("property_type")
        or facts.get("object_type")
        or facts.get("category")
        or facts.get("listing_type")
    )
    concrete_types = {"apartment", "house", "office", "land"}

    concrete_requested_types = [item for item in requested_types if item in concrete_types]
    concrete_fact_types = [item for item in fact_types if item in concrete_types]
    if concrete_requested_types and concrete_fact_types and any(item in concrete_fact_types for item in concrete_requested_types):
        return True

    text = _property_candidate_text(
        property_url=property_url,
        title=title,
        summary=summary,
        property_facts=facts,
    )
    direct_text = " ".join(
        part.lower()
        for part in (
            str(property_url or "").strip(),
            str(title or "").strip(),
            str(summary or "").strip(),
        )
        if str(part or "").strip()
    )
    direct_compact_text_value = re.sub(r"[^a-z0-9äöüß]+", "", direct_text)
    compact_text_value = re.sub(r"[^a-z0-9äöüß]+", "", text)
    def _has_text_marker(markers: tuple[str, ...], include_compact: bool = False) -> bool:
        if include_compact:
            return any(
                marker in text or marker.replace(" ", "") in compact_text_value or marker.replace("-", "") in compact_text_value
                for marker in markers
            )
        return any(marker in text for marker in markers)

    has_office_marker = _has_text_marker(_PROPERTY_OFFICE_TEXT_MARKERS, include_compact=True)
    has_non_residential_only_marker = any(
        marker in text or marker.replace(" ", "") in compact_text_value
        for marker in _PROPERTY_NON_RESIDENTIAL_ONLY_MARKERS
    )
    has_direct_apartment_marker = any(marker in direct_text for marker in _PROPERTY_APARTMENT_TEXT_MARKERS)
    has_direct_house_marker = any(marker in direct_text for marker in _PROPERTY_HOUSE_TEXT_MARKERS)
    has_direct_land_marker = any(
        marker in direct_text
        or marker.replace(" ", "") in direct_compact_text_value
        or marker.replace("-", "") in direct_compact_text_value
        for marker in _PROPERTY_LAND_TEXT_MARKERS
    )
    has_direct_residential_text_signal = has_direct_apartment_marker or has_direct_house_marker or has_direct_land_marker

    has_apartment_marker = _has_text_marker(_PROPERTY_APARTMENT_TEXT_MARKERS)
    has_house_marker = _has_text_marker(_PROPERTY_HOUSE_TEXT_MARKERS)
    has_land_marker = _has_text_marker(_PROPERTY_LAND_TEXT_MARKERS, include_compact=True)

    def _single_requested_type_match(requested_type: str) -> bool:
        if requested_type == "any":
            return True
        if requested_type == "office":
            return has_office_marker
        if requested_type == "land":
            return has_land_marker and not (has_apartment_marker or has_house_marker)
        if requested_type == "apartment":
            if has_non_residential_only_marker and not has_direct_residential_text_signal:
                return False
            if has_office_marker and not (has_apartment_marker or has_house_marker or has_land_marker):
                return False
            if has_house_marker and not has_apartment_marker:
                return False
            if has_land_marker and not (has_apartment_marker or has_house_marker):
                return False
            return True
        if requested_type == "house":
            if has_non_residential_only_marker and not has_direct_residential_text_signal:
                return False
            if has_office_marker and not (has_house_marker or has_apartment_marker or has_land_marker):
                return False
            if has_apartment_marker and not has_house_marker:
                return False
            if has_land_marker and not (has_apartment_marker or has_house_marker):
                return False
            return True
        return True

    return any(_single_requested_type_match(item) for item in requested_types)


def _property_candidate_area_sqm(
    *,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> float | None:
    facts = dict(property_facts or {})
    for key in (
        "area_sqm",
        "area_m2",
        "living_area_m2",
        "living_area_sqm",
        "usable_area_m2",
        "usable_area_sqm",
        "wohnflaeche_sqm",
        "wohnfläche_sqm",
    ):
        area = _float_or_none(facts.get(key))
        if isinstance(area, float) and area > 0.0:
            return area
    text = _property_candidate_text(
        property_url=property_url,
        title=title,
        summary=summary,
        property_facts=facts,
    )
    return _property_extract_area_value(text)


def _property_candidate_matches_min_area(
    *,
    min_area_m2: float,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> bool:
    if min_area_m2 <= 0.0:
        return True
    area = _property_candidate_area_sqm(
        property_url=property_url,
        title=title,
        summary=summary,
        property_facts=property_facts,
    )
    return isinstance(area, float) and area >= min_area_m2


def _property_candidate_min_area_status(
    *,
    min_area_m2: float,
    property_url: str,
    title: str = "",
    summary: str = "",
    property_facts: dict[str, object] | None = None,
) -> str:
    if min_area_m2 <= 0.0:
        return "pass"
    area = _property_candidate_area_sqm(
        property_url=property_url,
        title=title,
        summary=summary,
        property_facts=property_facts,
    )
    if not isinstance(area, float):
        return "unknown"
    return "pass" if area >= min_area_m2 else "fail"


