_PROPERTY_IMMEDIATE_AVAILABILITY_MARKERS = (
    "ab sofort",
    "sofort",
    "immediately",
    "ready now",
    "available now",
    "bezugsfertig",
)


def _property_parse_availability_date(value: object) -> datetime | None:
    text = compact_text(str(value or "").strip(), fallback="", limit=120)
    if not text:
        return None
    lowered = text.lower()
    if any(marker in lowered for marker in _PROPERTY_IMMEDIATE_AVAILABILITY_MARKERS):
        return datetime.now(timezone.utc)
    normalized = lowered.replace(".", " ").replace(",", " ").replace("/", " ").replace("-", " ")
    normalized = " ".join(normalized.split())
    iso_match = re.search(r"(20\d{2})-(\d{2})-(\d{2})", text)
    if iso_match:
        try:
            return datetime(
                int(iso_match.group(1)),
                int(iso_match.group(2)),
                int(iso_match.group(3)),
                tzinfo=timezone.utc,
            )
        except Exception:
            return None
    quarter_match = re.search(r"\bq([1-4])\s*(20\d{2})\b", normalized)
    if quarter_match:
        quarter = int(quarter_match.group(1))
        year = int(quarter_match.group(2))
        return datetime(year, quarter * 3, 28, tzinfo=timezone.utc)
    quarter_match = re.search(r"\b(20\d{2})\s*q([1-4])\b", normalized)
    if quarter_match:
        year = int(quarter_match.group(1))
        quarter = int(quarter_match.group(2))
        return datetime(year, quarter * 3, 28, tzinfo=timezone.utc)
    month_match = re.search(r"\b([a-zA-Z]+)\s+(20\d{2})\b", normalized)
    if month_match:
        month = _PROPERTY_MONTH_NAME_INDEX.get(month_match.group(1).lower())
        if month:
            return datetime(int(month_match.group(2)), month, 28, tzinfo=timezone.utc)
    year_match = re.search(r"\b(20\d{2})\b", normalized)
    if year_match:
        return datetime(int(year_match.group(1)), 12, 31, tzinfo=timezone.utc)
    return None


def _property_candidate_availability_date(
    *,
    property_facts: dict[str, object] | None = None,
) -> datetime | None:
    facts = dict(property_facts or {})
    for key in ("available_from_iso", "available_from", "availability_date", "move_in_date", "move_in", "availability_label"):
        parsed = _property_parse_availability_date(facts.get(key))
        if parsed is not None:
            return parsed
    return None


def _property_candidate_matches_availability_horizon(
    *,
    available_within_years: int,
    property_facts: dict[str, object] | None = None,
) -> bool:
    if available_within_years <= 0:
        return True
    available_at = _property_candidate_availability_date(property_facts=property_facts)
    if available_at is None:
        return True
    deadline = datetime.now(timezone.utc) + timedelta(days=366 * available_within_years)
    return available_at <= deadline


def _property_distance_within_relaxed_radius(
    *,
    actual_m: object,
    requested_limit_m: int,
    relaxation_factor: float = 3.0,
) -> tuple[bool, str, float]:
    if requested_limit_m <= 0:
        return True, "not_requested", 0.0
    try:
        actual = float(actual_m or 0.0)
    except Exception:
        actual = 0.0
    if actual <= 0.0:
        return True, "unknown", actual
    if actual <= float(requested_limit_m):
        return True, "strict", actual
    relaxed_limit = float(requested_limit_m) * max(1.0, float(relaxation_factor or 1.0))
    if actual <= relaxed_limit:
        return True, "relaxed", actual
    return False, "outside_relaxed", actual


def _property_distance_relaxation_factor(value: object) -> float:
    normalized = str(value or "").strip().lower()
    if normalized in {"hard", "must_have", "must-have", "strict"}:
        return 2.0
    if normalized in {"important", "high", "strong", "strong_wish", "strong-wish", "strong wish"}:
        return 3.0
    if normalized in {"nice_to_have", "nice-to-have", "soft", "low"}:
        return 5.0
    return 3.0


def _property_distance_is_avoid_mode(value: object) -> bool:
    normalized = str(value or "").strip().lower()
    return normalized in {"avoid", "avoid_nearby", "avoid-nearby", "avoid_in_vicinity", "avoid-vicinity"}


def _property_distance_is_hard_mode(value: object) -> bool:
    normalized = str(value or "").strip().lower()
    return normalized in {"hard", "must_have", "must-have", "strict"}


def _property_distance_is_strong_mode(value: object) -> bool:
    normalized = str(value or "").strip().lower()
    return normalized in {"important", "high", "strong", "strong_wish", "strong-wish", "strong wish"}


def _property_distance_is_nice_mode(value: object) -> bool:
    normalized = str(value or "").strip().lower()
    return normalized in {"nice_to_have", "nice-to-have", "soft", "low"}


def _property_append_distance_relaxation(
    facts: dict[str, object],
    *,
    label: str,
    requested_m: int,
    actual_m: float,
) -> None:
    existing = facts.get("distance_relaxations_json")
    rows = list(existing) if isinstance(existing, list) else []
    rows.append({"label": label, "requested_m": int(requested_m), "actual_m": int(actual_m)})
    facts["distance_relaxations_json"] = rows


def _property_append_distance_unknown(
    facts: dict[str, object],
    *,
    label: str,
    requested_m: int,
) -> None:
    existing = facts.get("distance_unknowns_json")
    rows = list(existing) if isinstance(existing, list) else []
    row = {"label": label, "requested_m": int(requested_m)}
    if row not in rows:
        rows.append(row)
    facts["distance_unknowns_json"] = rows


def _property_append_distance_avoidance(
    facts: dict[str, object],
    *,
    label: str,
    requested_m: int,
    actual_m: float,
) -> None:
    existing = facts.get("distance_avoidances_json")
    rows = list(existing) if isinstance(existing, list) else []
    row = {"label": label, "requested_m": int(requested_m), "actual_m": int(actual_m)}
    if row not in rows:
        rows.append(row)
    facts["distance_avoidances_json"] = rows


def _property_apply_distance_gate(
    facts: dict[str, object],
    *,
    request_preferences: dict[str, object],
    preference_key: str,
    fact_key: str,
    label: str,
) -> bool:
    limit_m = int(request_preferences.get(preference_key) or 0)
    if limit_m <= 0:
        return True
    importance_mode = request_preferences.get(preference_key.replace("_m", "_importance"))
    if _property_distance_is_avoid_mode(importance_mode):
        try:
            actual = float(facts.get(fact_key) or 0.0)
        except Exception:
            actual = 0.0
        if actual <= 0.0:
            _property_append_distance_unknown(facts, label=label, requested_m=limit_m)
            return True
        if actual <= float(limit_m):
            _property_append_distance_avoidance(facts, label=label, requested_m=limit_m, actual_m=actual)
        return True
    distance_ok, distance_mode, actual_m = _property_distance_within_relaxed_radius(
        actual_m=facts.get(fact_key),
        requested_limit_m=limit_m,
        relaxation_factor=_property_distance_relaxation_factor(importance_mode),
    )
    if distance_mode == "unknown":
        _property_append_distance_unknown(facts, label=label, requested_m=limit_m)
    elif distance_mode == "relaxed":
        _property_append_distance_relaxation(facts, label=label, requested_m=limit_m, actual_m=actual_m)
    if _property_distance_is_hard_mode(importance_mode):
        return distance_ok
    return True


def _property_distance_preference_score_adjustment(
    *,
    preferences: dict[str, object] | None,
    property_facts: dict[str, object] | None,
) -> tuple[float, tuple[str, ...]]:
    payload = dict(preferences or {})
    facts = property_facts if isinstance(property_facts, dict) else {}
    rows = (
        ("max_distance_to_supermarket_m", ("nearest_supermarket_m",), "supermarket"),
        ("max_distance_to_subway_m", ("nearest_subway_m",), "underground"),
        ("max_distance_to_kindergarten_m", ("nearest_kindergarten_m", "nearest_school_m"), "kindergarten"),
        ("max_distance_to_ganztags_volksschule_m", ("nearest_full_day_primary_school_m", "nearest_school_m"), "full-day primary school"),
        ("max_distance_to_halbtags_volksschule_m", ("nearest_half_day_primary_school_m", "nearest_school_m"), "half-day primary school"),
        ("max_distance_to_playground_m", ("nearest_playground_m",), "playground"),
        ("max_distance_to_market_m", ("nearest_market_m",), "market"),
        ("max_distance_to_hardware_store_m", ("nearest_hardware_store_m",), "Baumarkt"),
        ("max_distance_to_shopping_center_m", ("nearest_shopping_center_m",), "shopping center"),
        ("max_distance_to_shopping_street_m", ("nearest_shopping_street_m",), "shopping street"),
        ("max_distance_to_theatre_m", ("nearest_theatre_m",), "theatre"),
        ("max_distance_to_public_pool_m", ("nearest_public_pool_m",), "public pool"),
        ("max_distance_to_medical_care_m", ("nearest_medical_care_m",), "medical care"),
        ("max_distance_to_library_m", ("nearest_library_m",), "library"),
        ("max_distance_to_zoo_m", ("nearest_zoo_m",), "zoo"),
        ("max_distance_to_starbucks_m", ("nearest_starbucks_m",), "Starbucks"),
        ("max_distance_to_fitness_center_m", ("nearest_fitness_center_m",), "fitness"),
        ("max_distance_to_cinema_m", ("nearest_cinema_m",), "cinema"),
        ("max_distance_to_bouldering_m", ("nearest_bouldering_m",), "bouldering"),
        ("max_distance_to_dog_park_m", ("nearest_dog_park_m",), "dog park"),
        ("max_distance_to_good_cafe_m", ("nearest_good_cafe_m",), "good cafe"),
    )
    adjustment = 0.0
    notes: list[str] = []
    for preference_key, fact_keys, label in rows:
        try:
            limit_m = int(payload.get(preference_key) or 0)
        except Exception:
            limit_m = 0
        if limit_m <= 0:
            continue
        importance_mode = str(payload.get(preference_key.replace("_m", "_importance")) or "").strip().lower()
        if importance_mode in {"", "any", "neutral", "no_preference", "no-preference"}:
            continue
        fact_value = None
        observed_fact_key = ""
        for fact_key in fact_keys:
            candidate_value = facts.get(fact_key)
            if candidate_value not in (None, "", 0, 0.0):
                fact_value = candidate_value
                observed_fact_key = str(fact_key)
                break

        def _distance_preference_note(*, keep_farther_than: bool = False) -> str:
            observed = _float_or_none(fact_value)
            if not isinstance(observed, float) or observed <= 0:
                return ""
            place_name = ""
            if observed_fact_key:
                place_name = compact_text(
                    str(facts.get(f"{observed_fact_key.removesuffix('_m')}_name") or "").strip(),
                    fallback="",
                    limit=80,
                )
            subject = f"Nearest {label}"
            if place_name:
                subject = f"{subject}: {place_name}"
            if keep_farther_than and limit_m > 0:
                return f"{subject} is {int(observed)} m away; you asked to keep it farther than {int(limit_m)} m."
            if limit_m > 0:
                return f"{subject} is {int(observed)} m away; your limit was {int(limit_m)} m."
            return f"{subject} is {int(observed)} m away."

        if _property_distance_is_avoid_mode(importance_mode):
            try:
                actual_m = float(fact_value or 0.0)
            except Exception:
                actual_m = 0.0
            if actual_m <= 0.0:
                _property_append_distance_unknown(facts, label=label, requested_m=limit_m)
            elif actual_m <= float(limit_m):
                adjustment -= 6.0
                notes.append(_distance_preference_note(keep_farther_than=True) or f"{label} too close for avoid preference")
            else:
                adjustment += 1.0
                notes.append(f"{label} avoided")
            continue
        distance_ok, distance_mode, _actual_m = _property_distance_within_relaxed_radius(
            actual_m=fact_value,
            requested_limit_m=limit_m,
            relaxation_factor=_property_distance_relaxation_factor(importance_mode),
        )
        if _property_distance_is_hard_mode(importance_mode):
            if distance_mode == "strict":
                adjustment += 2.0
                notes.append(f"{label} matched")
            elif distance_mode == "relaxed":
                adjustment += 0.5
                notes.append(f"{label} slightly farther than requested")
            elif distance_mode == "unknown":
                _property_append_distance_unknown(facts, label=label, requested_m=limit_m)
            continue
        if _property_distance_is_strong_mode(importance_mode):
            if distance_mode == "strict":
                adjustment += 6.0
                notes.append(f"{label} close by")
            elif distance_mode == "relaxed":
                adjustment += 2.0
                notes.append(f"{label} within wider radius")
            elif distance_mode == "unknown":
                _property_append_distance_unknown(facts, label=label, requested_m=limit_m)
            elif not distance_ok:
                adjustment -= 6.0
                notes.append(_distance_preference_note() or f"{label} farther away than wished")
            continue
        if _property_distance_is_nice_mode(importance_mode):
            if distance_mode == "strict":
                adjustment += 3.0
                notes.append(f"{label} nearby")
            elif distance_mode == "relaxed":
                adjustment += 1.0
                notes.append(f"{label} reasonably nearby")
            elif distance_mode == "unknown":
                _property_append_distance_unknown(facts, label=label, requested_m=limit_m)
            elif not distance_ok:
                adjustment -= 3.0
                notes.append(_distance_preference_note() or f"{label} less convenient")
    return adjustment, tuple(notes[:8])


