def _property_search_filter_disable_patch(filter_key: str) -> dict[str, object]:
    normalized = str(filter_key or "").strip()
    if normalized not in _PROPERTY_SEARCH_FEEDBACK_PATCH_KEYS:
        return {}
    if normalized == "require_floorplan":
        return {normalized: False}
    if normalized == "require_barrier_free":
        return {normalized: False}
    if normalized == "available_within_years":
        return {normalized: 0}
    return {normalized: None}


def _property_near_miss_distance_detail(
    *,
    filter_label: str,
    observed_distance_m: object = None,
    requested_distance_m: object = None,
    observed_place_name: object = "",
) -> str:
    observed = _float_or_none(observed_distance_m)
    requested = _float_or_none(requested_distance_m)
    if not isinstance(observed, float) or observed <= 0:
        return ""
    label = str(filter_label or "distance").strip().removesuffix(" radius").removesuffix(" distance") or "distance"
    place_name = compact_text(str(observed_place_name or "").strip(), fallback="", limit=80)
    subject = f"Nearest {label}"
    if place_name:
        subject = f"{subject}: {place_name}"
    if isinstance(requested, float) and requested > 0:
        return f"{subject} is {int(observed)} m away; your limit was {int(requested)} m."
    return f"{subject} is {int(observed)} m away."


def _property_near_miss_filter_message(
    *,
    title: str,
    source_label: str,
    filter_label: str,
    score: float,
    observed_distance_m: object = None,
    requested_distance_m: object = None,
    observed_place_name: object = "",
) -> str:
    distance_detail = _property_near_miss_distance_detail(
        filter_label=filter_label,
        observed_distance_m=observed_distance_m,
        requested_distance_m=requested_distance_m,
        observed_place_name=observed_place_name,
    )
    return compact_text(
        (
            f"Near miss: {title} looked like a strong match from {source_label}, "
            f"but was filtered out only by the {filter_label} filter. "
            f"{distance_detail + ' ' if distance_detail else ''}"
            f"Pre-filter score: {score:.0f}/100."
        ),
        fallback="Near miss: a strong property was filtered by one search filter.",
        limit=420,
    )


def _property_enrich_future_change_research(
    facts: dict[str, object] | None,
    *,
    investment_research_mode: str,
    available_within_years: int = 0,
) -> dict[str, object]:
    enriched = dict(facts or {})
    if str(investment_research_mode or "").strip().lower() == "off":
        enriched.pop("future_change_research", None)
        return enriched
    existing = dict(enriched.get("future_change_research") or {}) if isinstance(enriched.get("future_change_research"), dict) else {}
    existing.setdefault("status", "queued")
    existing.setdefault("planning_confidence", "unknown")
    existing.setdefault("investment_impact", "unknown")
    existing.setdefault("time_horizon_options", ["1y", "3y", "5y", "10y"])
    existing.setdefault("school_atlas_context_summary", "")
    existing.setdefault("school_atlas_quality_summary", "")
    existing.setdefault("school_atlas_progression_summary", "")
    existing.setdefault("school_atlas_gymnasium_progression_pct", "")
    existing.setdefault("school_atlas_top_secondary_destinations", [])
    existing.setdefault("school_atlas_nearby_schools", [])
    existing.setdefault("school_atlas_selected_school", {})
    existing.setdefault("school_atlas_evidence_type", "")
    existing.setdefault("school_atlas_source_url", _PROPERTY_SCHOOLATLAS_SOURCE_URL)
    existing.setdefault(
        "focus_areas",
        [
            "planned_transport_projects",
            "road_and_noise_risks",
            "rezoning_and_supply_pipeline",
            "employer_and_social_infrastructure",
            "climate_and_regulatory_risks",
            "school_atlas_quality_and_progression",
        ],
    )
    if available_within_years > 0:
        existing["requested_move_in_horizon_years"] = int(available_within_years)
    if not property_school_context_summary(existing) or not existing.get("school_atlas_progression_summary"):
        lat_value, lon_value = _property_schoolatlas_coords_from_facts(enriched)
        if lat_value is not None and lon_value is not None:
            schoolatlas_snapshot = _property_schoolatlas_snapshot(lat_value, lon_value)
            if isinstance(schoolatlas_snapshot, dict) and schoolatlas_snapshot:
                for key in (
                    "school_atlas_context_summary",
                    "school_atlas_quality_summary",
                    "school_atlas_progression_summary",
                    "school_atlas_gymnasium_progression_pct",
                    "school_atlas_top_secondary_destinations",
                    "school_atlas_nearby_schools",
                    "school_atlas_selected_school",
                    "school_atlas_evidence_type",
                    "school_atlas_source_url",
                ):
                    value = schoolatlas_snapshot.get(key)
                    if value not in (None, "", [], {}):
                        existing[key] = value
    existing["updated_at"] = str(existing.get("updated_at") or _now_iso())
    enriched["future_change_research"] = existing
    return enriched


def _property_enrich_official_risk_evidence(
    facts: dict[str, object] | None,
) -> dict[str, object]:
    enriched = dict(facts or {})
    existing = (
        dict(enriched.get("official_risk_evidence") or {})
        if isinstance(enriched.get("official_risk_evidence"), dict)
        else {}
    )
    lat_value, lon_value = _property_schoolatlas_coords_from_facts(enriched)
    if lat_value is None or lon_value is None or not _property_point_looks_like_austria(lat_value, lon_value):
        if existing:
            enriched["official_risk_evidence"] = existing
        return enriched
    official = _property_official_risk_evidence(lat=lat_value, lon=lon_value, facts=enriched)
    if isinstance(official, dict) and list(official.get("sources") or []):
        enriched["official_risk_evidence"] = official
    elif existing:
        enriched["official_risk_evidence"] = existing
    return enriched


def _is_invalid_property_scout_task_url(property_url: str, *, source_ref: str = "") -> bool:
    normalized_url = urllib.parse.urldefrag(str(property_url or "").strip())[0]
    normalized_source_ref = str(source_ref or "").strip()
    if normalized_source_ref.startswith("property-scout:"):
        if not normalized_url:
            return True
        return not _property_scout_is_supported_listing_url(normalized_url)
    return False


def _property_candidate_is_barrier_free(facts: dict[str, object] | None) -> bool:
    payload = dict(facts or {})
    for key in (
        "barrier_free",
        "is_barrier_free",
        "wheelchair_accessible",
        "accessible",
        "step_free",
        "is_step_free",
        "has_accessible_entry",
    ):
        value = payload.get(key)
        if value is True:
            return True
        normalized = str(value or "").strip().lower()
        if normalized in {"1", "true", "yes", "y", "on", "enabled"}:
            return True
    if payload.get("lift") is True or payload.get("has_lift") is True:
        entry_floor = _float_or_none(payload.get("floor")) or _float_or_none(payload.get("level"))
        if entry_floor is None or entry_floor <= 1.0:
            return True
    searchable_text = " ".join(
        str(payload.get(key) or "")
        for key in (
            "title",
            "summary",
            "description",
            "listing_body",
            "features_text",
            "amenities_text",
        )
    ).lower()
    return any(
        marker in searchable_text
        for marker in (
            "barrierefrei",
            "rollstuhlgerecht",
            "wheelchair accessible",
            "step-free",
            "stufenlos",
            "behindertengerecht",
        )
    )


