def _property_tour_compare_links(tour_url: str) -> dict[str, str]:
    normalized = str(tour_url or "").strip()
    if not normalized:
        return {}
    links: dict[str, str] = {}
    if _hosted_property_tour_has_matterport_export(normalized):
        matterport_url = _telegram_safe_url_button_target(_property_tour_control_link(normalized, viewer="matterport"))
        if matterport_url:
            links["matterport"] = matterport_url
    if _hosted_property_tour_has_3dvista_export(normalized):
        threedvista_url = _telegram_safe_url_button_target(_property_tour_control_link(normalized, viewer="3dvista"))
        if threedvista_url:
            links["3dvista"] = threedvista_url
    if _hosted_property_tour_has_pano2vr_export(normalized):
        pano2vr_url = _telegram_safe_url_button_target(_property_tour_control_link(normalized, viewer="pano2vr"))
        if pano2vr_url:
            links["pano2vr"] = pano2vr_url
    return links


def _property_walkthrough_scene_video_context(
    tour_url: str,
    *,
    tour_result: dict[str, object] | None = None,
) -> dict[str, object]:
    normalized_tour_url = str(tour_url or "").strip()
    if not normalized_tour_url:
        return {}
    manifest = _hosted_property_tour_manifest(normalized_tour_url)
    compare_links = dict(_property_tour_compare_links(normalized_tour_url))
    if _hosted_property_tour_has_krpano_control(normalized_tour_url):
        krpano_url = _property_tour_control_link(normalized_tour_url, viewer="krpano")
        if krpano_url:
            compare_links.setdefault("krpano", krpano_url)
    route_labels: list[str] = []
    walkable_scene = dict(manifest.get("walkable_scene") or {}) if isinstance(manifest.get("walkable_scene"), dict) else {}
    for collection_key in ("route", "rooms"):
        for raw_item in list(walkable_scene.get(collection_key) or []):
            if not isinstance(raw_item, dict):
                continue
            label = compact_text(
                str(raw_item.get("label") or raw_item.get("room") or raw_item.get("name") or "").strip(),
                fallback="",
                limit=80,
            )
            if label and label.lower() not in {item.lower() for item in route_labels}:
                route_labels.append(label)
    if not route_labels:
        for raw_label in list(manifest.get("covered_route_labels") or manifest.get("room_visit_plan") or []):
            label = compact_text(str(raw_label or "").strip(), fallback="", limit=80)
            if label and label.lower() not in {item.lower() for item in route_labels}:
                route_labels.append(label)
    generated_reconstruction: dict[str, str] = {}
    for asset_key, output_key in (
        ("viewer_relpath", "viewer_url"),
        ("model_relpath", "model_url"),
        ("glb_model_relpath", "glb_model_url"),
        ("walkthrough_video_relpath", "walkthrough_video_url"),
    ):
        asset_url = _hosted_property_tour_generated_reconstruction_asset_url(
            normalized_tour_url,
            asset_key=asset_key,
        )
        if asset_url:
            generated_reconstruction[output_key] = asset_url
    verified_provider = _hosted_property_tour_verified_provider(normalized_tour_url)
    verified_open_url = _hosted_property_tour_verified_open_url(normalized_tour_url)
    payload = {
        "tour_url": normalized_tour_url,
        "vendor_tour_url": str(dict(tour_result or {}).get("vendor_tour_url") or "").strip(),
        "direct_360_url": _hosted_property_tour_direct_360_url(normalized_tour_url),
        "source_virtual_tour_url": _first_non_empty_text(
            manifest.get("source_virtual_tour_url"),
            dict(tour_result or {}).get("source_virtual_tour_url"),
        ),
        "verified_provider": verified_provider,
        "verified_open_url": verified_open_url,
        "control_url": verified_open_url or _property_tour_control_link(normalized_tour_url),
        "control_urls": compare_links,
        "provider_exports": list(_hosted_property_tour_provider_export_keys(normalized_tour_url)),
        "control_mode": str(manifest.get("control_mode") or "").strip(),
        "scene_strategy": str(manifest.get("scene_strategy") or "").strip(),
        "scene_count": int(manifest.get("scene_count") or 0),
        "title": compact_text(
            str(manifest.get("display_title") or manifest.get("title") or manifest.get("tour_title") or "").strip(),
            fallback="",
            limit=180,
        ),
        "preview_image_url": _hosted_property_tour_preview_image_url(normalized_tour_url),
        "route_labels": route_labels,
        "generated_reconstruction": generated_reconstruction,
    }
    return dict(_json_safe_product_payload(payload))


def _property_walkthrough_context_route_labels(tour_context_json: dict[str, object] | None) -> list[str]:
    route_labels: list[str] = []
    context_payload = dict(tour_context_json or {}) if isinstance(tour_context_json, dict) else {}
    for raw_label in list(context_payload.get("route_labels") or []):
        label = compact_text(str(raw_label or "").strip(), fallback="", limit=80)
        if label and label.lower() not in {item.lower() for item in route_labels}:
            route_labels.append(label)
    return route_labels


def _property_walkthrough_context_reference_text(tour_context_json: dict[str, object] | None) -> str:
    context_payload = dict(tour_context_json or {}) if isinstance(tour_context_json, dict) else {}
    verified_provider = str(context_payload.get("verified_provider") or "").strip().lower()
    provider_label = {
        "matterport": "Matterport",
        "3dvista": "3DVista",
        "pano2vr": "Pano2VR",
        "krpano": "krpano",
    }.get(verified_provider, verified_provider)
    route_labels = _property_walkthrough_context_route_labels(context_payload)
    prompt_parts: list[str] = []
    if provider_label:
        prompt_parts.append(f"Spatial ground truth comes from the prepared {provider_label} tour.")
    if route_labels:
        prompt_parts.append(
            "Respect this room order and adjacency from the tour reference: "
            + ", ".join(route_labels[:10])
            + "."
        )
    if str(context_payload.get("verified_open_url") or context_payload.get("control_url") or "").strip():
        prompt_parts.append(
            "Keep room geometry, doorway order, window orientation, and balcony placement consistent with that tour reference."
        )
    generated_reconstruction = dict(context_payload.get("generated_reconstruction") or {})
    if str(generated_reconstruction.get("viewer_url") or "").strip():
        prompt_parts.append("A generated geometry viewer is also available as a secondary cross-check.")
    return compact_text(" ".join(prompt_parts), fallback="", limit=420)


def _property_walkthrough_enrich_facts_with_context(
    property_facts: dict[str, object] | None,
    *,
    tour_context_json: dict[str, object] | None,
) -> dict[str, object]:
    enriched = dict(property_facts or {}) if isinstance(property_facts, dict) else {}
    context_payload = dict(tour_context_json or {}) if isinstance(tour_context_json, dict) else {}
    route_labels = _property_walkthrough_context_route_labels(context_payload)
    if route_labels:
        enriched.setdefault("magicfit_route_labels", route_labels)
        enriched.setdefault("room_visit_plan", route_labels)
        enriched.setdefault("room_count", len(route_labels))
        enriched.setdefault("tour_scene_count", len(route_labels))
    verified_provider = str(context_payload.get("verified_provider") or "").strip().lower()
    if verified_provider:
        enriched.setdefault("tour_control_provider", verified_provider)
    control_mode = str(context_payload.get("control_mode") or "").strip().lower()
    if control_mode:
        enriched.setdefault("tour_control_mode", control_mode)
    control_url = str(context_payload.get("verified_open_url") or context_payload.get("control_url") or "").strip()
    if control_url:
        enriched.setdefault("tour_control_url", control_url)
    direct_360_url = str(context_payload.get("direct_360_url") or context_payload.get("source_virtual_tour_url") or "").strip()
    if direct_360_url:
        enriched.setdefault("source_virtual_tour_url", direct_360_url)
    return enriched


def _property_3d_provider_rule_exit_gate(
    tour_url: str,
    *,
    expected_providers: tuple[str, ...] | list[str] | set[str] | None = None,
) -> tuple[bool, str, dict[str, object]]:
    normalized = str(tour_url or "").strip()
    metrics: dict[str, object] = {"tour_url": normalized, "expected_providers": [], "selected_links": {}}
    if not normalized:
        return False, "tour_url_missing", metrics
    aliases = {
        "metaport": "matterport",
        "matterport": "matterport",
        "3d_tour": "3dvista",
        "3d-tour": "3dvista",
        "3dtour": "3dvista",
        "3dvista": "3dvista",
        "3d_vista": "3dvista",
        "three_d_vista": "3dvista",
        "panorama": "pano2vr",
        "pano2vr": "pano2vr",
        "pano_2_vr": "pano2vr",
        "pano-2-vr": "pano2vr",
        "krpano": "krpano",
        "kr_pano": "krpano",
        "kr-pano": "krpano",
    }
    if expected_providers is None:
        expected = list(_hosted_property_tour_provider_export_keys(normalized))
    else:
        expected = []
        for raw_provider in list(expected_providers or []):
            provider = aliases.get(str(raw_provider or "").strip().lower())
            if provider and provider not in expected:
                expected.append(provider)
    links = _property_tour_compare_links(normalized)
    declared_provider_controls = {
        "3dvista": _hosted_property_tour_has_3dvista_export(normalized),
        "pano2vr": _hosted_property_tour_has_pano2vr_export(normalized),
        "krpano": _hosted_property_tour_has_krpano_control(normalized),
    }
    metrics["expected_providers"] = list(expected)
    metrics["available_links"] = dict(links)
    metrics["selected_links"] = {provider: links[provider] for provider in expected if links.get(provider)}
    if not expected:
        metrics["skipped"] = "no_provider_export_rule"
        return True, "", metrics
    for provider in expected:
        if provider == "matterport" and not _hosted_property_tour_has_matterport_export(normalized):
            return False, "matterport_export_missing_for_rule", metrics
        if provider == "3dvista" and not _hosted_property_tour_has_3dvista_export(normalized):
            return False, "3dvista_export_missing_for_rule", metrics
        if provider == "pano2vr" and not _hosted_property_tour_has_pano2vr_export(normalized):
            return False, "pano2vr_export_missing_for_rule", metrics
        if provider == "krpano" and not _hosted_property_tour_has_krpano_control(normalized):
            return False, "krpano_control_missing_for_rule", metrics
        link = str(
            links.get(provider)
            or (
                _property_tour_control_link(normalized, viewer=provider)
                if provider in {"3dvista", "pano2vr", "krpano"} and declared_provider_controls.get(provider)
                else ""
            )
        ).strip()
        if link and provider not in metrics["selected_links"]:
            metrics["selected_links"] = {**dict(metrics.get("selected_links") or {}), provider: link}
        if link and provider not in metrics["available_links"]:
            metrics["available_links"] = {**dict(metrics.get("available_links") or {}), provider: link}
        metrics[f"{provider}_link"] = link
        if not link:
            return False, f"{provider}_control_link_missing_for_rule", metrics
        expected_suffix = f"/control/{provider}"
        try:
            path = str(urllib.parse.urlparse(link).path or "").rstrip("/")
        except Exception:
            path = ""
        if not path.endswith(expected_suffix):
            return False, f"{provider}_control_link_wrong_for_rule", metrics
    unexpected = sorted(key for key in links if key not in expected)
    if unexpected:
        metrics["unexpected_provider_links"] = unexpected
        return False, "unexpected_provider_control_link_selected", metrics
    return True, "", metrics


def _pdf_embedded_image_count(pdf_path: str) -> int:
    normalized_path = str(pdf_path or "").strip()
    if not normalized_path:
        return 0
    try:
        pdf_bytes = Path(normalized_path).read_bytes()
    except Exception:
        return 0
    object_starts = list(re.finditer(rb"(?m)(\d+)\s+\d+\s+obj\b", pdf_bytes))
    if not object_starts:
        return len(re.findall(rb"/Subtype\s*/Image", pdf_bytes))
    embedded_image_ids: set[int] = set()
    total_chunks = len(object_starts)
    for index, obj_match in enumerate(object_starts):
        try:
            object_id = int(obj_match.group(1))
        except Exception:
            continue
        object_start = obj_match.start()
        object_end = object_starts[index + 1].start() if index + 1 < total_chunks else len(pdf_bytes)
        object_slice = pdf_bytes[object_start:object_end]
        endobj_offset = object_slice.find(b"endobj")
        if endobj_offset < 0:
            continue
        object_head = object_slice[:endobj_offset]
        if b"stream" in object_head:
            object_head = object_head.split(b"stream", 1)[0]
        if (
            re.search(rb"/Subtype\s*/Image\b", object_head, re.MULTILINE) is None
            or re.search(rb"/Width\s+\d+", object_head, re.MULTILINE) is None
            or re.search(rb"/Height\s+\d+", object_head, re.MULTILINE) is None
            or re.search(rb"/Type\s*/XObject\b", object_head, re.MULTILINE) is None
        ):
            continue
        embedded_image_ids.add(object_id)
    if embedded_image_ids:
        return len(embedded_image_ids)
    return len(re.findall(rb"/Subtype\s*/Image", pdf_bytes))


def _required_pdf_embedded_media_count(
    media_ref_count: int,
    *,
    required_ratio: float = 0.6,
) -> int:
    normalized_media_ref_count = max(0, int(media_ref_count or 0))
    normalized_required_ratio = max(0.0, min(1.0, float(required_ratio)))
    if normalized_required_ratio <= 0.0:
        return 0
    if normalized_media_ref_count <= 1:
        return normalized_media_ref_count
    required_count = math.ceil(normalized_media_ref_count * normalized_required_ratio)
    if required_count < 1:
        required_count = 1
    if required_count > normalized_media_ref_count:
        required_count = normalized_media_ref_count
    return required_count


def _pdf_media_gate_passed(
    pdf_path: str,
    *,
    media_ref_count: int,
    required_ratio: float = 0.6,
) -> tuple[bool, int, int]:
    normalized_count = max(0, int(media_ref_count or 0))
    if normalized_count <= 0:
        return True, 0, 0
    embedded_images = _pdf_embedded_image_count(pdf_path)
    required_images = _required_pdf_embedded_media_count(
        normalized_count,
        required_ratio=required_ratio,
    )
    return embedded_images >= required_images, embedded_images, required_images


def _video_duration_seconds(video_ref: str) -> float:
    normalized_ref = str(video_ref or "").strip()
    if not normalized_ref:
        return 0.0
    if not Path(normalized_ref).is_file():
        return 0.0
    ffprobe = shutil.which("ffprobe") or "/usr/bin/ffprobe"
    try:
        completed = subprocess.run(
            [
                ffprobe,
                "-v",
                "error",
                "-show_entries",
                "format=duration",
                "-of",
                "default=noprint_wrappers=1:nokey=1",
                normalized_ref,
            ],
            capture_output=True,
            text=True,
            timeout=20,
            check=False,
        )
    except Exception:
        return 0.0
    if completed.returncode != 0:
        return 0.0
    try:
        return max(0.0, float(str(completed.stdout or "").strip() or "0"))
    except ValueError:
        return 0.0


def _magicfit_flythrough_minimum_duration_seconds(*, title: str, property_facts: dict[str, object] | None) -> float:
    room_count, _visit_plan = _magicfit_property_room_visit_plan(
        title=title,
        property_facts=dict(property_facts or {}),
    )
    try:
        seconds_per_stop = float(os.getenv("PROPERTYQUARRY_FLYTHROUGH_SECONDS_PER_ROUTE_STOP") or "10")
    except Exception:
        seconds_per_stop = 10.0
    seconds_per_stop = max(5.0, min(30.0, seconds_per_stop))
    return float(max(1, min(25, int(room_count or 1))) * seconds_per_stop)


def _magicfit_normalized_route_label(value: object) -> str:
    text = compact_text(str(value or "").strip().lower(), fallback="", limit=80)
    if not text:
        return ""
    text = re.sub(r"[^a-z0-9äöüß]+", " ", text)
    text = re.sub(r"\s+", " ", text).strip()
    aliases = {
        "entry hall": "hall",
        "vorraum": "hall",
        "flur": "hall",
        "storage room": "storage",
        "abstellraum": "storage",
        "bath wc": "bath toilet",
        "bad wc": "bath toilet",
        "separate toilet": "toilet",
        "wc": "toilet",
        "wohnkuche": "living kitchen",
        "wohnküche": "living kitchen",
        "zimmer schlafzimmer": "bedroom",
        "balcony terrace": "balcony terrace",
        "balkon": "balcony terrace",
        "terrace": "balcony terrace",
    }
    return aliases.get(text, text)


def _magicfit_route_coverage_gate(
    video_delivery: dict[str, object],
    *,
    title: str,
    property_facts: dict[str, object] | None,
) -> tuple[bool, str, dict[str, object]]:
    _room_count, expected_labels = _magicfit_property_room_visit_plan(
        title=title,
        property_facts=dict(property_facts or {}),
    )
    expected = [
        _magicfit_normalized_route_label(label)
        for label in expected_labels
        if _magicfit_normalized_route_label(label)
    ]
    expected = list(dict.fromkeys(expected))
    if len(expected) <= 1:
        return True, "", {"expected": expected, "covered": [], "missing": []}
    coverage_proof = str(video_delivery.get("coverage_proof") or "").strip()
    if coverage_proof != "boundary_verified_frame_continuation":
        return False, "flythrough_route_coverage_proof_missing", {
            "expected": expected,
            "covered": [],
            "missing": expected,
            "coverage_proof": coverage_proof,
        }
    covered_labels: list[str] = []
    for key in ("covered_route_labels", "magicfit_route_labels", "room_visit_plan", "route_labels", "walkthrough_route_labels"):
        raw_labels = video_delivery.get(key)
        if not isinstance(raw_labels, (list, tuple)):
            continue
        for raw_label in raw_labels:
            label = _magicfit_normalized_route_label(raw_label)
            if label and label not in covered_labels:
                covered_labels.append(label)
    missing = [label for label in expected if label not in covered_labels]
    metrics = {"expected": expected, "covered": covered_labels, "missing": missing}
    if missing:
        if not covered_labels:
            return False, "flythrough_route_coverage_unverified", metrics
        return False, "flythrough_route_coverage_missing:" + ",".join(missing), metrics
    return True, "", metrics


def _magicfit_flythrough_duration_gate(
    video_delivery: dict[str, object],
    *,
    title: str,
    property_facts: dict[str, object] | None,
) -> tuple[bool, str, float, float]:
    gate_facts = dict(property_facts or {})
    for key in ("tour_scene_count", "scene_count", "panorama_scene_count"):
        if video_delivery.get(key) is not None and not gate_facts.get(key):
            gate_facts[key] = video_delivery.get(key)
    required_seconds = _magicfit_flythrough_minimum_duration_seconds(title=title, property_facts=gate_facts)
    raw_duration = video_delivery.get("duration_seconds")
    actual_seconds = 0.0
    if isinstance(raw_duration, (int, float)):
        actual_seconds = max(0.0, float(raw_duration))
    if actual_seconds <= 0:
        probe_ref = str(video_delivery.get("video_file_path") or video_delivery.get("audio_probe_ref") or "").strip()
        if not probe_ref:
            return False, "flythrough_duration_unverified", 0.0, required_seconds
        actual_seconds = _video_duration_seconds(probe_ref)
    if actual_seconds <= 0:
        return False, "flythrough_duration_unverified", actual_seconds, required_seconds
    if actual_seconds + 0.25 < required_seconds:
        return False, f"flythrough_too_short:{actual_seconds:.3f}s<{required_seconds:.3f}s", actual_seconds, required_seconds
    coverage_ok, coverage_reason, _coverage_metrics = _magicfit_route_coverage_gate(
        video_delivery,
        title=title,
        property_facts=gate_facts,
    )
    if not coverage_ok:
        return False, coverage_reason, actual_seconds, required_seconds
    probe_ref = str(video_delivery.get("video_file_path") or video_delivery.get("audio_probe_ref") or "").strip()
    if probe_ref:
        continuity_ok, continuity_reason, _continuity_metrics = _video_continuous_shot_gate(Path(probe_ref))
        if not continuity_ok:
            return False, continuity_reason, actual_seconds, required_seconds
    return True, "", actual_seconds, required_seconds


def _video_continuous_shot_gate(
    video_path: Path,
    *,
    scene_threshold: float = 0.18,
    max_scene_cuts: int = 0,
) -> tuple[bool, str, dict[str, object]]:
    normalized_path = Path(video_path).resolve()
    if not normalized_path.is_file():
        return False, "continuous_shot_video_missing", {"scene_cuts": 0, "cut_times": []}
    ffmpeg_bin = _pocket_audio_enhance_ffmpeg_bin()
    command = [
        ffmpeg_bin,
        "-hide_banner",
        "-i",
        str(normalized_path),
        "-filter:v",
        f"select='gt(scene,{float(scene_threshold):.4f})',showinfo",
        "-f",
        "null",
        "-",
    ]
    try:
        completed = subprocess.run(
            command,
            capture_output=True,
            text=True,
            timeout=90,
            check=False,
        )
    except Exception as exc:
        return False, compact_text(str(exc or ""), fallback="continuous_shot_probe_failed", limit=180), {"scene_cuts": 0, "cut_times": []}
    output = f"{completed.stdout or ''}\n{completed.stderr or ''}"
    cut_times: list[float] = []
    for match in re.finditer(r"pts_time:(?P<time>\d+(?:\.\d+)?)", output):
        try:
            cut_times.append(round(float(match.group("time")), 3))
        except Exception:
            continue
    deduped: list[float] = []
    for timestamp in cut_times:
        if not deduped or abs(timestamp - deduped[-1]) >= 0.25:
            deduped.append(timestamp)
    metrics = {
        "scene_threshold": float(scene_threshold),
        "max_scene_cuts": int(max_scene_cuts),
        "scene_cuts": len(deduped),
        "cut_times": deduped[:40],
    }
    if len(deduped) > max_scene_cuts:
        return False, f"continuous_shot_scene_cuts:{len(deduped)}>{max_scene_cuts}", metrics
    return True, "", metrics


def _extract_video_boundary_frame(video_path: Path, frame_path: Path, *, position: str) -> None:
    ffmpeg_bin = _pocket_audio_enhance_ffmpeg_bin()
    command = [ffmpeg_bin, "-y"]
    if position == "last":
        command.extend(["-sseof", "-0.20"])
    command.extend(["-i", str(video_path), "-frames:v", "1", "-q:v", "2", str(frame_path)])
    subprocess.run(
        command,
        capture_output=True,
        text=True,
        timeout=60,
        check=True,
    )


def _image_rms_delta(first_path: Path, second_path: Path) -> float:
    if Image is None:
        raise RuntimeError("pillow_unavailable")
    from PIL import ImageChops, ImageStat

    with Image.open(first_path) as first_image, Image.open(second_path) as second_image:
        first = first_image.convert("RGB").resize((320, 180), Image.Resampling.BILINEAR)
        second = second_image.convert("RGB").resize((320, 180), Image.Resampling.BILINEAR)
        diff = ImageChops.difference(first, second)
        stat = ImageStat.Stat(diff)
    squared = sum(float(value) ** 2 for value in stat.rms) / max(len(stat.rms), 1)
    return math.sqrt(squared)


def _image_similarity_score(first_path: Path, second_path: Path) -> float:
    if Image is None:
        raise RuntimeError("pillow_unavailable")
    from PIL import ImageChops, ImageStat

    with Image.open(first_path) as first_image, Image.open(second_path) as second_image:
        first = first_image.convert("L").resize((320, 180), Image.Resampling.BILINEAR)
        second = second_image.convert("L").resize((320, 180), Image.Resampling.BILINEAR)
        diff = ImageChops.difference(first, second)
        stat = ImageStat.Stat(diff)
    mean_abs = float(stat.mean[0]) if stat.mean else 255.0
    return max(0.0, min(1.0, 1.0 - (mean_abs / 255.0)))


def _video_segment_boundary_gate(
    segment_paths: list[Path],
    *,
    max_rms_delta: float = 1.5,
    codec_drift_max_rms_delta: float = 5.0,
    min_similarity_score: float = 0.98,
) -> tuple[bool, str, list[dict[str, object]]]:
    normalized_segments = [Path(path).resolve() for path in segment_paths if Path(path).is_file()]
    if len(normalized_segments) <= 1:
        return True, "", []
    metrics: list[dict[str, object]] = []
    with tempfile.TemporaryDirectory(prefix="pq-boundary-gate-") as tmp_dir:
        tmp_path = Path(tmp_dir)
        for index in range(len(normalized_segments) - 1):
            previous_frame = tmp_path / f"segment-{index + 1:03d}-last.jpg"
            next_frame = tmp_path / f"segment-{index + 2:03d}-first.jpg"
            try:
                _extract_video_boundary_frame(normalized_segments[index], previous_frame, position="last")
                _extract_video_boundary_frame(normalized_segments[index + 1], next_frame, position="first")
                rms_delta = _image_rms_delta(previous_frame, next_frame)
                similarity_score = _image_similarity_score(previous_frame, next_frame)
            except Exception as exc:
                return False, compact_text(str(exc or ""), fallback="segment_boundary_probe_failed", limit=180), metrics
            row = {
                "boundary_index": index + 1,
                "previous_segment": str(normalized_segments[index]),
                "next_segment": str(normalized_segments[index + 1]),
                "rms_delta": round(rms_delta, 4),
                "max_rms_delta": float(max_rms_delta),
                "codec_drift_max_rms_delta": float(codec_drift_max_rms_delta),
                "similarity_score": round(similarity_score, 6),
                "min_similarity_score": float(min_similarity_score),
            }
            metrics.append(row)
            if rms_delta > max_rms_delta and not (rms_delta <= codec_drift_max_rms_delta and similarity_score >= min_similarity_score):
                return False, f"segment_boundary_frame_mismatch:{index + 1}:{rms_delta:.4f}>{max_rms_delta:.4f}", metrics
    return True, "", metrics


def _video_boundary_bridge_enabled() -> bool:
    return str(os.getenv("PROPERTYQUARRY_MAGICFIT_BOUNDARY_BRIDGE_ENABLED") or "1").strip().lower() not in {
        "0",
        "false",
        "no",
        "off",
    }


def _render_video_boundary_bridge(
    previous_segment: Path,
    next_segment: Path,
    output_path: Path,
    *,
    duration_seconds: float = 0.75,
) -> list[dict[str, object]]:
    previous_segment = Path(previous_segment).resolve()
    next_segment = Path(next_segment).resolve()
    output_path = Path(output_path).resolve()
    if not previous_segment.is_file() or not next_segment.is_file():
        raise RuntimeError("boundary_bridge_segment_missing")
    output_path.parent.mkdir(parents=True, exist_ok=True)
    duration = max(0.25, min(2.0, float(duration_seconds or 0.75)))
    ffmpeg_bin = _pocket_audio_enhance_ffmpeg_bin()
    with tempfile.TemporaryDirectory(prefix="pq-boundary-bridge-") as tmp_dir:
        tmp_path = Path(tmp_dir)
        previous_frame = tmp_path / "previous-last.jpg"
        next_frame = tmp_path / "next-first.jpg"
        _extract_video_boundary_frame(previous_segment, previous_frame, position="last")
        _extract_video_boundary_frame(next_segment, next_frame, position="first")
        if Image is None:
            raise RuntimeError("boundary_bridge_pillow_missing")
        bridge_frames = tmp_path / "frames"
        bridge_frames.mkdir(parents=True, exist_ok=True)
        frame_count = max(18, int(round(duration * 24)))
        hold_frames = max(6, int(round(0.25 * 24)))
        with Image.open(previous_frame) as previous_image, Image.open(next_frame) as next_image:
            previous_rgb = previous_image.convert("RGB").resize((1920, 1080), Image.Resampling.BILINEAR)
            next_rgb = next_image.convert("RGB").resize((1920, 1080), Image.Resampling.BILINEAR)
            for frame_index in range(frame_count):
                if frame_index < hold_frames:
                    frame = previous_rgb
                elif frame_index >= frame_count - hold_frames:
                    frame = next_rgb
                else:
                    blend_index = frame_index - hold_frames
                    blend_count = max(1, frame_count - (hold_frames * 2) - 1)
                    alpha = blend_index / float(blend_count)
                    frame = Image.blend(previous_rgb, next_rgb, alpha)
                frame.save(bridge_frames / f"frame-{frame_index:04d}.png")
        command = [
            ffmpeg_bin,
            "-y",
            "-framerate",
            "24",
            "-i",
            str(bridge_frames / "frame-%04d.png"),
            "-vf",
            "fps=24,format=yuv420p",
            "-an",
            "-c:v",
            "libx264",
            "-preset",
            "medium",
            "-crf",
            "18",
            "-movflags",
            "+faststart",
            str(output_path),
        ]
        completed = subprocess.run(
            command,
            capture_output=True,
            text=True,
            timeout=120,
            check=False,
        )
        if completed.returncode != 0 or not output_path.is_file():
            detail = compact_text(str(completed.stderr or completed.stdout or ""), fallback="", limit=240)
            raise RuntimeError(f"boundary_bridge_render_failed:{detail}")
    boundary_ok, boundary_reason, boundary_metrics = _video_segment_boundary_gate(
        [previous_segment, output_path, next_segment],
        codec_drift_max_rms_delta=15.0,
        min_similarity_score=0.975,
    )
    if not boundary_ok:
        raise RuntimeError(boundary_reason or "boundary_bridge_gate_failed")
    return boundary_metrics


def _concat_video_segments(
    segment_paths: list[Path],
    output_path: Path,
    *,
    require_boundary_continuity: bool = True,
    boundary_codec_drift_max_rms_delta: float = 5.0,
    boundary_min_similarity_score: float = 0.98,
) -> list[dict[str, object]]:
    normalized_segments = [Path(path).resolve() for path in segment_paths if Path(path).is_file()]
    if not normalized_segments:
        raise RuntimeError("video_concat_segments_missing")
    boundary_metrics: list[dict[str, object]] = []
    if require_boundary_continuity:
        boundary_ok, boundary_reason, boundary_metrics = _video_segment_boundary_gate(
            normalized_segments,
            codec_drift_max_rms_delta=boundary_codec_drift_max_rms_delta,
            min_similarity_score=boundary_min_similarity_score,
        )
        if not boundary_ok:
            raise RuntimeError(boundary_reason or "segment_boundary_frame_mismatch")
    output_path.parent.mkdir(parents=True, exist_ok=True)
    ffmpeg_bin = _pocket_audio_enhance_ffmpeg_bin()
    with tempfile.TemporaryDirectory(prefix="pq-video-concat-") as tmp_dir:
        tmp_path = Path(tmp_dir)
        normalized_paths: list[Path] = []
        for index, segment_path in enumerate(normalized_segments, start=1):
            normalized_path = tmp_path / f"segment-{index:03d}.mp4"
            subprocess.run(
                [
                    ffmpeg_bin,
                    "-y",
                    "-i",
                    str(segment_path),
                    "-vf",
                    "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2,fps=24,format=yuv420p",
                    "-an",
                    "-c:v",
                    "libx264",
                    "-preset",
                    "medium",
                    "-crf",
                    "20",
                    "-movflags",
                    "+faststart",
                    str(normalized_path),
                ],
                capture_output=True,
                text=True,
                timeout=180,
                check=True,
            )
            normalized_paths.append(normalized_path)
        concat_file = tmp_path / "concat.txt"
        concat_file.write_text(
            "\n".join(f"file '{str(path).replace(chr(39), chr(39) + chr(92) + chr(39) + chr(39))}'" for path in normalized_paths) + "\n",
            encoding="utf-8",
        )
        subprocess.run(
            [
                ffmpeg_bin,
                "-y",
                "-f",
                "concat",
                "-safe",
                "0",
                "-i",
                str(concat_file),
                "-c",
                "copy",
                "-movflags",
                "+faststart",
                str(output_path),
            ],
            capture_output=True,
            text=True,
            timeout=240,
            check=True,
        )
    return boundary_metrics


def _pdf_appendix_exit_gate_passed(pdf_path: str) -> tuple[bool, str, dict[str, object]]:
    normalized_path = str(pdf_path or "").strip()
    if not normalized_path or not Path(normalized_path).is_file():
        return False, "appendix_pdf_missing", {}
    try:
        from pypdf import PdfReader

        reader = PdfReader(normalized_path)
        page_count = len(reader.pages)
        image_count = 0
        link_count = 0
        text_parts: list[str] = []
        for page in reader.pages:
            with contextlib.suppress(Exception):
                text_parts.append(str(page.extract_text() or ""))
            annots = page.get("/Annots") or []
            link_count += len(annots)
            resources = page.get("/Resources") or {}
            xobjects = resources.get("/XObject") or {}
            for obj in xobjects.values():
                with contextlib.suppress(Exception):
                    resolved = obj.get_object()
                    if str(resolved.get("/Subtype") or "") == "/Image":
                        image_count += 1
        text = " ".join(" ".join(text_parts).split())
        metrics = {
            "page_count": page_count,
            "embedded_image_count": image_count,
            "link_annotation_count": link_count,
            "text_chars": len(text),
        }
    except ImportError:
        try:
            pdf_bytes = Path(normalized_path).read_bytes()
        except Exception as exc:
            return False, compact_text(str(exc or ""), fallback="appendix_pdf_gate_failed", limit=160), {}
        page_count = len(re.findall(rb"/Type\s*/Page\b", pdf_bytes))
        image_count = len(re.findall(rb"/Subtype\s*/Image\b", pdf_bytes))
        link_count = len(re.findall(rb"/Subtype\s*/Link\b", pdf_bytes))
        rough_text_chars = len(re.findall(rb"\((?:\\.|[^\\)])+\)\s*Tj", pdf_bytes))
        metrics = {
            "page_count": page_count,
            "embedded_image_count": image_count,
            "link_annotation_count": link_count,
            "text_chars": rough_text_chars,
        }
    except Exception as exc:
        return False, compact_text(str(exc or ""), fallback="appendix_pdf_gate_failed", limit=160), {}
    if page_count < 1 or page_count > 3:
        return False, "appendix_page_count_invalid", metrics
    if image_count < 1:
        return False, "appendix_hero_poster_missing", metrics
    if link_count < 2:
        return False, "appendix_links_missing", metrics
    if int(metrics["text_chars"]) < 450:
        return False, "appendix_too_sparse", metrics
    if int(metrics["text_chars"]) > 5200:
        return False, "appendix_too_long", metrics
    return True, "", metrics


def _download_pdf_for_appendix(source_pdf_url: str, target_path: Path) -> None:
    normalized_url = str(source_pdf_url or "").strip()
    if not normalized_url:
        raise RuntimeError("source_pdf_url_missing")
    request = urllib.request.Request(normalized_url, headers={"User-Agent": _PROPERTY_SCOUT_USER_AGENT})
    max_bytes = max(int(os.getenv("PROPERTYQUARRY_TELEGRAM_SOURCE_PDF_MAX_BYTES") or "52428800"), 1)
    with urllib.request.urlopen(request, timeout=120) as response:
        content_type = str(response.headers.get("Content-Type") or "").split(";", 1)[0].strip().lower()
        data = response.read(max_bytes + 1)
    if len(data) > max_bytes:
        raise RuntimeError("source_pdf_too_large")
    if not data.startswith(b"%PDF") and content_type not in {"application/pdf", "application/octet-stream"}:
        raise RuntimeError("source_pdf_not_pdf")
    target_path.parent.mkdir(parents=True, exist_ok=True)
    target_path.write_bytes(data)


def _append_propertyquarry_pdf_to_source_pdf(
    *,
    source_pdf_url: str,
    appendix_pdf_path: str,
    target_path: Path,
) -> str:
    normalized_appendix = str(appendix_pdf_path or "").strip()
    if not normalized_appendix or not Path(normalized_appendix).is_file():
        return ""
    try:
        from pypdf import PdfReader, PdfWriter
    except Exception:
        return ""
    with tempfile.TemporaryDirectory(prefix="propertyquarry-source-pdf-") as tmp_dir:
        source_path = Path(tmp_dir) / "source.pdf"
        _download_pdf_for_appendix(source_pdf_url, source_path)
        writer = PdfWriter()
        for path in (source_path, Path(normalized_appendix)):
            reader = PdfReader(str(path))
            if getattr(reader, "is_encrypted", False):
                with contextlib.suppress(Exception):
                    reader.decrypt("")
            for page in reader.pages:
                writer.add_page(page)
        target_path.parent.mkdir(parents=True, exist_ok=True)
        with target_path.open("wb") as handle:
            writer.write(handle)
    return str(target_path)


def _telegram_safe_url_button_target(value: str, *, max_length: int = 256) -> str:
    normalized = str(value or "").strip()
    if not normalized:
        return ""
    if len(normalized) > max(int(max_length or 256), 1):
        return ""
    return normalized


def _workspace_relative_target_from_public_url(value: str) -> str:
    normalized = str(value or "").strip()
    if not normalized:
        return ""
    if normalized.startswith("/"):
        return normalized
    parsed = urllib.parse.urlparse(normalized)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc:
        return ""
    public_base = _public_app_base_url()
    public_host = urllib.parse.urlparse(public_base).netloc.lower()
    if not public_host or parsed.netloc.lower() != public_host:
        return ""
    target = parsed.path or "/"
    if parsed.query:
        target = f"{target}?{parsed.query}"
    return target


def _willhaben_property_packet_script_path() -> Path:
    explicit = str(os.getenv("EA_WILLHABEN_PROPERTY_PACKET_SCRIPT") or "").strip()
    if explicit:
        return Path(explicit).expanduser()
    resolved = Path(__file__).resolve()
    for parent in resolved.parents:
        candidate = parent / "scripts" / "willhaben_property_packet.py"
        if candidate.exists():
            return candidate
    return (_repo_root() / "scripts" / "willhaben_property_packet.py").resolve()


def _load_json_dict(path: Path) -> dict[str, object]:
    try:
        loaded = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, ValueError, json.JSONDecodeError):
        return {}
    return dict(loaded) if isinstance(loaded, dict) else {}


def _crezlo_property_tour_state_root() -> Path:
    explicit = str(os.getenv("EA_CREZLO_PROPERTY_TOUR_STATE_ROOT") or "").strip()
    if explicit:
        return Path(explicit).expanduser()
    return Path("/docker/fleet/state/browseract_bootstrap/runtime")


def _crezlo_property_tour_bootstrap_metadata() -> dict[str, object]:
    root = _crezlo_property_tour_state_root()
    metadata: dict[str, object] = {}

    def _merge_workspace_metadata(loaded: dict[str, object]) -> bool:
        login_email = _first_non_empty_text(loaded.get("login_email"), loaded.get("crezlo_login_email"))
        login_password = _first_non_empty_text(loaded.get("login_password"), loaded.get("crezlo_login_password"))
        workspace_id = _first_non_empty_text(
            loaded.get("workspace_id"),
            loaded.get("browseract_crezlo_workspace_id"),
        )
        workspace_domain = _first_non_empty_text(
            loaded.get("workspace_domain"),
            loaded.get("browseract_crezlo_workspace_domain"),
        )
        workspace_base_url = _first_non_empty_text(
            loaded.get("workspace_base_url"),
            loaded.get("browseract_crezlo_workspace_base_url"),
        )
        workspace_tours_url = _first_non_empty_text(
            loaded.get("workspace_tours_url"),
            loaded.get("browseract_crezlo_workspace_tours_url"),
        )
        if login_email:
            metadata["crezlo_login_email"] = login_email
        if login_password:
            metadata["crezlo_login_password"] = login_password
        if workspace_id:
            metadata["crezlo_workspace_id"] = workspace_id
            metadata["browseract_crezlo_workspace_id"] = workspace_id
        if workspace_domain:
            metadata["crezlo_workspace_domain"] = workspace_domain
            metadata["browseract_crezlo_workspace_domain"] = workspace_domain
        if workspace_base_url:
            metadata["crezlo_workspace_base_url"] = workspace_base_url
            metadata["browseract_crezlo_workspace_base_url"] = workspace_base_url
        if workspace_tours_url:
            metadata["crezlo_workspace_tours_url"] = workspace_tours_url
            metadata["browseract_crezlo_workspace_tours_url"] = workspace_tours_url
        return bool(workspace_id or workspace_domain or workspace_base_url or workspace_tours_url)

    publish_result = _load_json_dict(root / "crezlo_property_tour_operator_publish" / "result.json")
    workflow_id = _first_non_empty_text(
        publish_result.get("workflow_id"),
        publish_result.get("browseract_crezlo_property_tour_workflow_id"),
        publish_result.get("crezlo_property_tour_workflow_id"),
    )
    if workflow_id:
        metadata["crezlo_property_tour_workflow_id"] = workflow_id
        metadata["browseract_crezlo_property_tour_workflow_id"] = workflow_id

    try:
        worker_inputs = sorted(
            root.glob("crezlo_property_tour_runs_*/*.worker_input.json"),
            key=lambda path: path.stat().st_mtime,
            reverse=True,
        )
    except OSError:
        worker_inputs = []
    for candidate in worker_inputs:
        loaded = _load_json_dict(candidate)
        if not loaded:
            continue
        if _merge_workspace_metadata(loaded):
            break

    if not any(str(metadata.get(key) or "").strip() for key in ("crezlo_workspace_id", "crezlo_workspace_domain", "crezlo_workspace_base_url")):
        try:
            runtime_results = sorted(
                root.glob("crezlo_property_tour_runs_*/*.json"),
                key=lambda path: path.stat().st_mtime,
                reverse=True,
            )
        except OSError:
            runtime_results = []
        for candidate in runtime_results:
            loaded = _load_json_dict(candidate)
            if not loaded:
                continue
            execution = dict(loaded.get("execution") or {})
            structured_output = dict(execution.get("structured_output_json") or {})
            receipt = dict(execution.get("receipt_json") or {})
            merged = {
                **structured_output,
                **receipt,
                **loaded,
            }
            if _merge_workspace_metadata(merged):
                break
    return metadata


def _load_willhaben_property_packet(property_url: str, *, timeout_seconds: int = 180) -> dict[str, object]:
    normalized_url = urllib.parse.urldefrag(str(property_url or "").strip())[0]
    if not _is_willhaben_property_url(normalized_url):
        raise RuntimeError("willhaben_property_url_invalid")
    script_path = _willhaben_property_packet_script_path()
    if not script_path.exists():
        raise RuntimeError(f"willhaben_property_packet_script_missing:{script_path}")
    try:
        completed = subprocess.run(
            ["python3", str(script_path), normalized_url],
            check=False,
            capture_output=True,
            text=True,
            timeout=max(1, int(timeout_seconds)),
        )
    except FileNotFoundError as exc:
        raise RuntimeError("python3_missing:willhaben_property_packet") from exc
    except subprocess.TimeoutExpired as exc:
        raise RuntimeError("willhaben_property_packet_timeout") from exc
    if completed.returncode != 0:
        detail = (completed.stderr or completed.stdout or "").strip()
        raise RuntimeError(f"willhaben_property_packet_failed:{detail[:400]}")
    try:
        payload = json.loads(str(completed.stdout or "").strip() or "[]")
    except json.JSONDecodeError as exc:
        raise RuntimeError("willhaben_property_packet_invalid") from exc
    if not isinstance(payload, list) or not payload or not isinstance(payload[0], dict):
        raise RuntimeError("willhaben_property_packet_invalid")
    return dict(payload[0])


def _load_willhaben_property_packet_compat(property_url: str, *, timeout_seconds: int = 180) -> dict[str, object]:
    try:
        return _load_willhaben_property_packet(property_url, timeout_seconds=timeout_seconds)
    except TypeError as exc:
        detail = str(exc)
        if "unexpected keyword argument" not in detail and "positional argument" not in detail:
            raise
        return _load_willhaben_property_packet(property_url)


def _load_optional_json_dict(path: Path) -> dict[str, object] | None:
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError):
        return None
    return payload if isinstance(payload, dict) else None


def _load_yaml_dict(path: Path) -> dict[str, object] | None:
    payload = load_design_yaml_dict(path)
    return payload or None


def _design_product_root() -> Path:
    raw = str(os.getenv("CHUMMER6_DESIGN_PRODUCT_ROOT") or "").strip()
    if raw:
        return Path(raw)
    local_root = _repo_root() / ".codex-design/product"
    if local_root.exists():
        return local_root
    return _DEFAULT_DESIGN_PRODUCT_ROOT


def _design_source_path(key: str, fallback: str) -> Path:
    root = _design_product_root()
    manifest = _load_yaml_dict(root / "PUBLIC_GUIDE_EXPORT_MANIFEST.yaml") or {}
    sources = dict(manifest.get("sources") or {}) if isinstance(manifest.get("sources"), dict) else {}
    raw = str(sources.get(key) or "").strip()
    if raw.startswith("products/chummer/"):
        raw = raw[len("products/chummer/") :]
    relative = raw or fallback
    candidate = root / relative
    if candidate.exists():
        return candidate
    local_root = (_repo_root() / ".codex-design/product").resolve()
    try:
        root_resolved = root.resolve()
    except Exception:
        root_resolved = root
    if root_resolved == local_root and _DEFAULT_DESIGN_PRODUCT_ROOT.exists():
        fallback_candidate = _DEFAULT_DESIGN_PRODUCT_ROOT / relative
        if fallback_candidate.exists():
            return fallback_candidate
    return candidate


def _design_manifest_path(filename: str) -> Path:
    root = _design_product_root()
    candidate = root / filename
    if candidate.exists():
        return candidate
    local_root = (_repo_root() / ".codex-design/product").resolve()
    try:
        root_resolved = root.resolve()
    except Exception:
        root_resolved = root
    if root_resolved == local_root and _DEFAULT_DESIGN_PRODUCT_ROOT.exists():
        fallback_candidate = _DEFAULT_DESIGN_PRODUCT_ROOT / filename
        if fallback_candidate.exists():
            return fallback_candidate
    return candidate


def _design_string_list(value: object) -> list[str]:
    if isinstance(value, list):
        return [str(entry).strip() for entry in value if str(entry).strip()]
    normalized = str(value or "").strip()
    return [normalized] if normalized else []


def _grounding_actions(rows: object) -> list[dict[str, str]]:
    actions: list[dict[str, str]] = []
    if not isinstance(rows, list):
        return actions
    for row in rows:
        if not isinstance(row, dict):
            continue
        label = str(row.get("label") or "").strip()
        href = str(row.get("href") or "").strip()
        if not label or not href:
            continue
        actions.append(
            {
                "label": label,
                "href": href,
                "method": str(row.get("method") or "get").strip().lower() or "get",
            }
        )
    return actions


def _grounding_source(*, label: str, path: Path | str, as_of: str = "") -> dict[str, str]:
    normalized_path = str(path or "").strip()
    payload = {"label": str(label or "").strip(), "path": normalized_path}
    if as_of:
        payload["as_of"] = str(as_of).strip()
    return payload


def _artifact_age_seconds(value: str | None) -> int | None:
    parsed = _parse_iso(value)
    if parsed is None:
        return None
    return max(int((_utcnow() - parsed).total_seconds()), 0)


def _path_mtime_iso(path: Path) -> str:
    try:
        return datetime.fromtimestamp(path.stat().st_mtime, tz=timezone.utc).isoformat()
    except OSError:
        return ""


def _freshness_state_from_age(age_seconds: int | None) -> str:
    if age_seconds is None:
        return "watch"
    if age_seconds <= _PRODUCT_PULSE_FRESH_SECONDS:
        return "fresh"
    if age_seconds <= _PRODUCT_PULSE_STALE_SECONDS:
        return "watch"
    return "stale"


def _freshness_label(state: str) -> str:
    return str(state or "watch").replace("_", " ")


def _journey_freshness_summary(payload: dict[str, object]) -> tuple[str, str]:
    freshness = dict(payload.get("artifact_freshness") or {})
    if not freshness:
        generated_at = str(payload.get("generated_at") or "").strip()
        state = _freshness_state_from_age(_artifact_age_seconds(generated_at))
        detail = (
            f"Published journey gates generated at {generated_at}."
            if generated_at
            else "Journey-gate freshness metadata is missing."
        )
        return state, detail
    severity = {"fresh": 0, "watch": 1, "stale": 2, "missing": 3}
    worst_state = "fresh"
    detail_parts: list[str] = []
    for key, value in freshness.items():
        item = dict(value or {}) if isinstance(value, dict) else {}
        available = bool(item.get("available"))
        raw_state = str(item.get("state") or "").strip().lower()
        state = "missing" if not available else raw_state or _freshness_state_from_age(int(item.get("age_seconds") or 0))
        if state not in severity:
            state = "watch"
        if severity[state] > severity[worst_state]:
            worst_state = state
        detail_parts.append(f"{str(key).replace('_', ' ')} {_freshness_label(state)}")
    return worst_state, "; ".join(detail_parts[:3])


def _public_guide_freshness_projection() -> dict[str, object]:
    severity = {"fresh": 0, "watch": 1, "stale": 2, "missing": 3}

    manifest_path = _default_public_guide_manifest_path()
    manifest_payload = _load_optional_json_dict(manifest_path)
    if manifest_payload is not None:
        guide_root = manifest_path.parent
        required_files = ("README.md", "STATUS.md", "DOWNLOAD.md", "HELP.md", "FAQ.md", "CONTACT.md")
        required_dirs = ("PARTS", "HORIZONS", "TRUST", "assets")
        missing_items = [
            *[name for name in required_files if not (guide_root / name).is_file()],
            *[name for name in required_dirs if not (guide_root / name).is_dir()],
        ]
        generated_at = _path_mtime_iso(manifest_path)
        age_seconds = _artifact_age_seconds(generated_at)
        state = _freshness_state_from_age(age_seconds)
        manifest_status = str(manifest_payload.get("status") or "").strip().lower()
        if manifest_status and manifest_status != "ok":
            state = "watch" if severity.get(state, 1) < severity["watch"] else state
        if missing_items:
            state = "missing"
            missing_label = ", ".join(missing_items[:4])
            if len(missing_items) > 4:
                missing_label = f"{missing_label}, and {len(missing_items) - 4} more"
            detail = f"Public guide repo is incomplete on this host: missing {missing_label}."
        else:
            page_count = int(manifest_payload.get("page_count") or 0)
            active_wave = dict(manifest_payload.get("active_wave") or {})
            wave_title = str(active_wave.get("title") or "").strip()
            wave_status = str(active_wave.get("status") or "").strip().replace("_", " ")
            detail_parts = [
                f"Public guide mirror updated at {generated_at}." if generated_at else "Public guide mirror is available on this host.",
                f"{page_count} pages mirrored." if page_count else "",
                f"Wave {wave_title} is {wave_status}." if wave_title and wave_status else "",
                f"Manifest status: {manifest_status}." if manifest_status and manifest_status != "ok" else "",
            ]
            detail = " ".join(part for part in detail_parts if part)
        return {
            "origin": "downstream_public_guide",
            "state": state,
            "detail": compact_text(detail, fallback="Public-guide freshness is not available.", limit=220),
            "generated_at": generated_at,
            "path": str(manifest_path),
            "status": manifest_status or "ok",
        }

    export_manifest_path = _design_manifest_path("PUBLIC_GUIDE_EXPORT_MANIFEST.yaml")
    export_payload = _load_yaml_dict(export_manifest_path) or {}
    sources = dict(export_payload.get("sources") or {}) if isinstance(export_payload.get("sources"), dict) else {}
    mirrored_count = 0
    missing_sources: list[str] = []
    for key, raw_value in sources.items():
        normalized = str(raw_value or "").strip()
        fallback = normalized.removeprefix("products/chummer/") or normalized
        source_path = _design_source_path(str(key), fallback)
        if source_path.exists():
            mirrored_count += 1
        else:
            missing_sources.append(str(key))

    generated_at = _path_mtime_iso(export_manifest_path)
    age_seconds = _artifact_age_seconds(generated_at)
    state = _freshness_state_from_age(age_seconds)
    if severity.get(state, 1) < severity["watch"]:
        state = "watch"
    if not sources or mirrored_count == 0:
        state = "missing"

    missing_label = ", ".join(missing_sources[:3])
    if len(missing_sources) > 3:
        missing_label = f"{missing_label}, and {len(missing_sources) - 3} more"
    detail_parts = [
        "Downstream public guide manifest is not available on this host; using mirrored design export sources.",
        f"{mirrored_count}/{len(sources)} mapped public-guide sources are mirrored." if sources else "",
        f"Export manifest updated at {generated_at}." if generated_at else "",
        f"Missing source mappings: {missing_label}." if missing_label else "",
    ]
    return {
        "origin": "design_mirror_fallback",
        "state": state,
        "detail": compact_text(
            " ".join(part for part in detail_parts if part),
            fallback="Public-guide freshness is not available.",
            limit=220,
        ),
        "generated_at": generated_at,
        "path": str(export_manifest_path),
        "status": "fallback",
    }


def _journey_highlights(payload: dict[str, object]) -> list[dict[str, object]]:
    candidates: list[dict[str, object]] = []
    for value in list(payload.get("journeys") or []):
        row = dict(value or {}) if isinstance(value, dict) else {}
        signals = dict(row.get("signals") or {})
        state = str(row.get("state") or "unknown").strip().lower()
        blocking_reasons = [str(item) for item in list(row.get("blocking_reasons") or []) if str(item).strip()]
        warning_reasons = [str(item) for item in list(row.get("warning_reasons") or []) if str(item).strip()]
        support_waiting = int(signals.get("support_closure_waiting_count") or 0)
        needs_human = int(signals.get("support_needs_human_response_count") or 0)
        candidates.append(
            {
                "id": str(row.get("id") or "").strip(),
                "title": str(row.get("title") or row.get("id") or "Journey").strip() or "Journey",
                "state": state or "unknown",
                "recommended_action": str(row.get("recommended_action") or "").strip(),
                "blocking_reasons": blocking_reasons[:2],
                "warning_reasons": warning_reasons[:2],
                "support_closure_waiting_count": support_waiting,
                "support_needs_human_response_count": needs_human,
            }
        )
    if not candidates:
        return []
    priority = {"blocked": 2, "warning": 1, "watch": 1, "ready": 0, "clear": 0}
    candidates.sort(
        key=lambda row: (
            -priority.get(str(row.get("state") or "").strip().lower(), 0),
            -int(row.get("support_closure_waiting_count") or 0),
            -int(row.get("support_needs_human_response_count") or 0),
            str(row.get("title") or ""),
        )
    )
    non_ready = [row for row in candidates if str(row.get("state") or "").strip().lower() not in {"ready", "clear"}]
    return non_ready[:3] if non_ready else candidates[:2]


def _support_fallout_projection(
    *,
    queue_health: dict[str, object],
    support_verification: dict[str, object],
    journey_highlights: list[dict[str, object]] | None = None,
) -> dict[str, object]:
    highlight_rows = [dict(value) for value in list(journey_highlights or []) if isinstance(value, dict)]
    support_closures_waiting = sum(int(row.get("support_closure_waiting_count") or 0) for row in highlight_rows)
    support_human_responses = sum(int(row.get("support_needs_human_response_count") or 0) for row in highlight_rows)
    delivery_errors = int(queue_health.get("delivery_errors") or 0)
    retrying_delivery = int(queue_health.get("retrying_delivery") or 0)
    sla_breaches = int(queue_health.get("sla_breaches") or 0)
    verification_state = str(support_verification.get("state") or "not_requested").strip().lower() or "not_requested"
    verification_summary = compact_text(str(support_verification.get("summary") or "").strip(), fallback="", limit=180)
    verification_action = compact_text(str(support_verification.get("recommended_action") or "").strip(), fallback="", limit=180)

    if verification_state == "blocked" or delivery_errors or sla_breaches:
        state = "critical"
    elif (
        support_closures_waiting
        or support_human_responses
        or retrying_delivery
        or verification_state in {"sent", "opened", "waiting"}
    ):
        state = "watch"
    else:
        state = "clear"

    detail_parts = []
    if support_closures_waiting:
        detail_parts.append(f"{support_closures_waiting} support closures waiting")
    if support_human_responses:
        detail_parts.append(f"{support_human_responses} human responses needed")
    if delivery_errors:
        detail_parts.append(f"{delivery_errors} delivery errors in the queue")
    if retrying_delivery:
        detail_parts.append(f"{retrying_delivery} retrying deliveries")
    if verification_summary and verification_state in {"blocked", "sent", "opened", "waiting"}:
        detail_parts.append(verification_summary)

    detail = (
        " ".join(detail_parts)
        if detail_parts
        else "No active support fallout is blocking the release or public-guide posture."
    )

    recommended_action = verification_action
    if not recommended_action and state != "clear":
        recommended_action = (
            "Close support fallout before advancing the release and public-guide posture."
            if support_closures_waiting or support_human_responses
            else "Stabilize delivery and support confirmation before advancing the release and public-guide posture."
        )

    return {
        "state": state,
        "detail": compact_text(detail, fallback="Support fallout posture is not available.", limit=220),
        "recommended_action": compact_text(recommended_action, fallback="No support fallout action is recommended.", limit=220),
        "support_closures_waiting": support_closures_waiting,
        "support_human_responses": support_human_responses,
        "verification_state": verification_state,
    }


def _operator_id_from_email(value: str) -> str:
    normalized = str(value or "").strip().lower()
    local = normalized.split("@", 1)[0] if "@" in normalized else normalized
    slug = _COMMITMENT_KEY_RE.sub("-", local).strip("-")
    return f"operator-{slug or uuid4().hex[:6]}"


def _principal_email_hint(principal_id: str) -> str:
    normalized = str(principal_id or "").strip()
    if normalized.startswith("cf-email:"):
        candidate = normalized.partition(":")[2].strip().lower()
        if "@" in candidate:
            return candidate
    return ""


def _display_name_from_email(value: str) -> str:
    normalized = str(value or "").strip().lower()
    local = normalized.split("@", 1)[0] if "@" in normalized else normalized
    parts = [part for part in re.split(r"[._+-]+", local) if part]
    return " ".join(part[:1].upper() + part[1:] for part in parts)


def _property_market_bootstrap_eta_hours() -> int:
    try:
        return max(1, min(72, int(os.getenv("EA_PROPERTY_MARKET_BOOTSTRAP_ETA_HOURS") or "3")))
    except Exception:
        return 3


def _property_market_label(value: object) -> str:
    resolved = resolve_country_code(value)
    if resolved:
        return country_label(resolved)
    normalized = compact_text(str(value or "").strip(), fallback="", limit=80)
    return normalized or "Requested market"


def _counterparty_label(*, counterparty: str, email: str) -> str:
    normalized = str(counterparty or "").strip()
    return normalized or _display_name_from_email(email) or str(email or "").strip().lower()


def _first_name(value: str) -> str:
    normalized = str(value or "").strip()
    if not normalized:
        return ""
    return normalized.split(" ", 1)[0].strip(" ,.:;")


def _trim_counterparty_suffix(value: str, *, counterparty: str) -> str:
    normalized = str(value or "").strip()
    target = str(counterparty or "").strip()
    if not normalized or not target:
        return normalized
    lowered = normalized.lower()
    variants = {target.lower()}
    if "@" in target:
        local = target.split("@", 1)[0].strip().lower()
        if local:
            variants.add(local)
            variants.add(" ".join(part for part in re.split(r"[._+-]+", local) if part))
    for variant in sorted((value for value in variants if value), key=len, reverse=True):
        for prefix in (f" to {variant}", f" for {variant}", f" with {variant}"):
            if lowered.endswith(prefix):
                return normalized[: -len(prefix)].strip(" .,:;")
    return normalized


def _reply_timing_phrase(value: str | None) -> str:
    when = _parse_iso(value)
    if when is None:
        return "shortly"
    target = when.astimezone(timezone.utc).date()
    today = _utcnow().date()
    if target == today:
        return "today"
    if target == today + timedelta(days=1):
        return "tomorrow"
    return f"by {target.isoformat()}"


def _sign_channel_payload(*, secret: str, payload: dict[str, object]) -> str:
    payload_bytes = json.dumps(payload, separators=(",", ":"), sort_keys=True).encode("utf-8")
    payload_b64 = base64.urlsafe_b64encode(payload_bytes).decode("ascii").rstrip("=")
    signature = hmac.new(secret.encode("utf-8"), payload_b64.encode("utf-8"), hashlib.sha256).hexdigest()
    return f"{payload_b64}.{signature}"


def _verify_channel_payload(*, secret: str, token: str) -> dict[str, object] | None:
    normalized = str(token or "").strip()
    if not normalized or "." not in normalized:
        return None
    payload_b64, signature = normalized.rsplit(".", 1)
    expected = hmac.new(secret.encode("utf-8"), payload_b64.encode("utf-8"), hashlib.sha256).hexdigest()
    if not hmac.compare_digest(signature, expected):
        return None
    padding = "=" * ((4 - len(payload_b64) % 4) % 4)
    try:
        payload_bytes = base64.urlsafe_b64decode(f"{payload_b64}{padding}".encode("ascii"))
        payload = json.loads(payload_bytes.decode("utf-8"))
    except (ValueError, UnicodeDecodeError, json.JSONDecodeError):
        return None
    if not isinstance(payload, dict):
        return None
    expires_at = _parse_iso(str(payload.get("expires_at") or "").strip())
    if expires_at is not None and expires_at <= datetime.now(timezone.utc):
        return None
    return payload


def _first_non_empty_text(*values: object) -> str:
    for value in values:
        normalized = str(value or "").strip()
        if normalized:
            return normalized
    return ""


def _tag_summary_text(value: object) -> str:
    if isinstance(value, dict):
        parts: list[str] = []
        for key, item in value.items():
            label = ""
            if isinstance(item, dict):
                label = _first_non_empty_text(item.get("tag"), item.get("label"), item.get("name"))
            if not label:
                label = str(key or "").strip()
            if label:
                parts.append(label)
        return ", ".join(parts)
    if isinstance(value, (list, tuple, set)):
        parts = [str(item).strip() for item in value if str(item).strip()]
        return ", ".join(parts)
    return str(value or "").strip()


def _property_profile_import_gmail_query(*, lookback_days: int) -> str:
    normalized_days = max(7, min(int(lookback_days or 365), 3650))
    return (
        f"newer_than:{normalized_days}d "
        "("
        "\"wohnung\" OR \"immobilie\" OR \"besichtigung\" OR \"vormerk\" OR "
        "\"warteliste\" OR \"genossenschaft\" OR \"suchagent\" OR \"willhaben\" OR "
        "\"immoscout\" OR \"immmo\" OR \"miete\" OR \"kauf\""
        ")"
    )


def _property_profile_provider_from_text(value: str) -> str:
    lowered = str(value or "").strip().lower()
    for provider, markers in _PROPERTY_PROFILE_IMPORT_PROVIDER_MARKERS.items():
        if any(marker in lowered for marker in markers):
            return provider
    return ""


def _property_profile_detect_location_hint(value: str) -> str:
    lowered = str(value or "").strip().lower()
    if not lowered:
        return ""
    for marker in _PROPERTY_PROFILE_IMPORT_DISTRICT_MARKERS:
        if marker in lowered:
            return marker.replace("ae", "ä").replace("oe", "ö").replace("ue", "ü").title()
    postal_match = re.search(r"\b(1[0-2][0-9]{2}|3[0-4][0-9]{2})\b", lowered)
    if postal_match:
        return postal_match.group(1)
    return ""


def _property_profile_detect_price_eur(value: str) -> float | None:
    match = re.search(r"(?:€|eur)\s*([0-9][0-9\.\s]{2,}(?:,[0-9]{2})?)|([0-9][0-9\.\s]{2,}(?:,[0-9]{2})?)\s*(?:€|eur)", str(value or ""), re.IGNORECASE)
    raw = ""
    if match is not None:
        raw = str(match.group(1) or match.group(2) or "").strip()
    if not raw:
        return None
    normalized = raw.replace(" ", "").replace(".", "").replace(",", ".")
    try:
        return float(normalized)
    except Exception:
        return None


def _property_profile_detect_area_sqm(value: str) -> float | None:
    match = re.search(r"\b([0-9]{2,3}(?:[.,][0-9])?)\s*(?:m²|m2|qm)\b", str(value or ""), re.IGNORECASE)
    if match is None:
        return None
    try:
        return float(str(match.group(1) or "").replace(",", "."))
    except Exception:
        return None


def _property_profile_detect_rooms(value: str) -> float | None:
    match = re.search(r"\b([1-9](?:[.,][0-9])?)\s*(?:zimmer|zi\b|rooms?)", str(value or ""), re.IGNORECASE)
    if match is None:
        return None
    try:
        return float(str(match.group(1) or "").replace(",", "."))
    except Exception:
        return None


def _property_profile_detect_activity_kind(value: str) -> str:
    lowered = str(value or "").strip().lower()
    if not lowered:
        return ""
    if any(marker in lowered for marker in ("vormerk", "warteliste", "vorangemeldet", "angemeldet", "registriert", "pre-registration", "vorgemerkt")):
        return "preregistration"
    if any(marker in lowered for marker in ("besichtigung", "viewing", "tour", "termin")):
        return "viewing"
    if any(marker in lowered for marker in ("nachgefragt", "anfrage", "interesse", "rueckfrage", "rückfrage", "reply", "antwort")):
        return "inquiry"
    if any(marker in lowered for marker in ("exposé", "expose", "unterlagen", "grundriss")):
        return "follow_up"
    return ""


def _property_profile_detect_features(value: str) -> list[str]:
    found: list[str] = []
    for key, pattern in _PROPERTY_PROFILE_IMPORT_FEATURE_PATTERNS.items():
        if pattern.search(str(value or "")):
            found.append(key)
    return found


class ProductService:
    def __init__(self, container: AppContainer) -> None:
        self._container = container
        self._preference_profiles = container.preference_profiles

    def get_preference_profile(
        self,
        *,
        principal_id: str,
        person_id: str = "self",
    ) -> dict[str, object]:
        normalized_person_id = str(person_id or "").strip() or "self"
        return self._preference_profiles.get_profile_bundle(
            principal_id=principal_id,
            person_id=normalized_person_id,
        )

    def upsert_preference_profile(
        self,
        *,
        principal_id: str,
        person_id: str = "self",
        display_name: str | None = None,
        profile_scope: str | None = None,
        consent_mode: str | None = None,
        learning_enabled: bool | None = None,
        high_stakes_domains_enabled: bool | None = None,
    ) -> dict[str, object]:
        normalized_person_id = str(person_id or "").strip() or "self"
        if normalized_person_id == "self" and not str(display_name or "").strip():
            display_name = _principal_email_hint(principal_id) or "Principal"
        return self._preference_profiles.ensure_profile(
            principal_id=principal_id,
            person_id=normalized_person_id,
            display_name=str(display_name or "").strip() or None,
            profile_scope=profile_scope,
            consent_mode=consent_mode,
            learning_enabled=learning_enabled,
            high_stakes_domains_enabled=high_stakes_domains_enabled,
        )

    def upsert_preference_node(
        self,
        *,
        principal_id: str,
        person_id: str = "self",
        domain: str,
        category: str,
        key: str,
        value_json: object,
        strength: str = "medium",
        confidence: float = 0.5,
        source_mode: str = "explicit",
        status: str = "active",
        decay_policy: str = "reinforce_only",
    ) -> dict[str, object]:
        normalized_person_id = str(person_id or "").strip() or "self"
        return self._preference_profiles.upsert_preference_node(
            principal_id=principal_id,
            person_id=normalized_person_id,
            domain=domain,
            category=category,
            key=key,
            value_json=value_json,
            strength=strength,
            confidence=confidence,
            source_mode=source_mode,
            status=status,
            decay_policy=decay_policy,
        )

    def import_property_mailbox_preferences(
        self,
        *,
        principal_id: str,
        person_id: str = "self",
        actor: str = "",
        account_email: str = "",
        consent_note: str = "",
        email_limit: int = 80,
        lookback_days: int = 365,
    ) -> dict[str, object]:
        normalized_person_id = str(person_id or "").strip() or "self"
        normalized_actor = str(actor or "").strip() or "mailbox_import"
        normalized_account_email = str(account_email or "").strip().lower()
        if normalized_person_id == "self":
            display_name = _principal_email_hint(principal_id) or "Principal"
        else:
            display_name = normalized_person_id.replace("_", " ").replace("-", " ").strip().title() or normalized_person_id
        self.upsert_preference_profile(
            principal_id=principal_id,
            person_id=normalized_person_id,
            display_name=display_name,
        )
        if normalized_person_id != "self":
            try:
                onboarding_preferences = dict(
                    self._container.onboarding.status(principal_id=principal_id).get("property_search_preferences") or {}
                )
                onboarding_preferences["preference_person_id"] = normalized_person_id
                self._container.onboarding.upsert_property_search_preferences(
                    principal_id=principal_id,
                    property_search_preferences_json=onboarding_preferences,
                )
            except Exception:
                pass
        packet = google_oauth_service.list_recent_workspace_signals(
            container=self._container,
            principal_id=principal_id,
            email_limit=max(1, min(int(email_limit or 80), 250)),
            calendar_limit=0,
            account_email_filter=normalized_account_email,
            gmail_query=_property_profile_import_gmail_query(lookback_days=lookback_days),
        )
        activities: list[dict[str, object]] = []
        for signal in packet.signals:
            activity = self._property_mailbox_import_activity_from_signal(signal=signal)
            if not activity:
                continue
            activities.append(activity)
            self.record_preference_evidence(
                principal_id=principal_id,
                person_id=normalized_person_id,
                domain="property",
                event_type="document_pattern_detected",
                object_type="property_search",
                object_id=str(activity.get("object_id") or activity.get("thread_id") or activity.get("source_ref") or uuid4().hex).strip(),
                source_ref=str(activity.get("source_ref") or "").strip(),
                raw_signal_json=dict(activity),
                interpreted_signal_json={
                    "source": "gmail_property_history_import",
                    "activity_kind": str(activity.get("activity_kind") or "").strip(),
                    "provider": str(activity.get("provider") or "").strip(),
                },
                signal_strength=0.75,
                reversible=True,
            )
        preference_hints = self._property_mailbox_preference_hints_from_activities(activities=activities)
        evidence_result = self.record_preference_evidence(
            principal_id=principal_id,
            person_id=normalized_person_id,
            domain="property",
            event_type="document_pattern_detected",
            object_type="profile",
            object_id=f"gmail-mailbox-import:{normalized_person_id}",
            source_ref=f"gmail-mailbox-import:{normalized_account_email or normalized_person_id}",
            raw_signal_json={
                "account_email": normalized_account_email or packet.account_email,
                "account_emails": list(packet.account_emails or ()),
                "actor": normalized_actor,
                "consent_note": compact_text(consent_note, fallback="", limit=500),
                "lookback_days": max(7, min(int(lookback_days or 365), 3650)),
                "activities": [dict(item) for item in activities[:50]],
            },
            interpreted_signal_json={
                "source": "gmail_property_history_import",
                "preference_hints": preference_hints,
                "activity_total": len(activities),
            },
            signal_strength=0.95 if activities else 0.4,
            reversible=True,
        )
        teable_sync = self.request_preference_teable_sync(
            principal_id=principal_id,
            person_id=normalized_person_id,
        )
        snapshot = self.get_preference_profile(
            principal_id=principal_id,
            person_id=normalized_person_id,
        )
        return {
            "status": "imported",
            "person_id": normalized_person_id,
            "account_email": normalized_account_email or packet.account_email,
            "consent_confirmed": True,
            "consent_note": compact_text(consent_note, fallback="", limit=500),
            "imported_thread_total": len({str(item.get("source_ref") or "").strip() for item in activities if str(item.get("source_ref") or "").strip()}),
            "activity_total": len(activities),
            "preregistration_total": sum(1 for item in activities if str(item.get("activity_kind") or "") == "preregistration"),
            "inquiry_total": sum(1 for item in activities if str(item.get("activity_kind") or "") == "inquiry"),
            "viewing_total": sum(1 for item in activities if str(item.get("activity_kind") or "") == "viewing"),
            "applied_nodes": list(evidence_result.get("applied_nodes") or []),
            "activities": [dict(item) for item in activities[:25]],
            "preference_snapshot": snapshot,
            "teable_sync_status": str(teable_sync.get("sync_result") or teable_sync.get("status") or "").strip(),
            "teable_blocked_reason": str(teable_sync.get("blocked_reason") or "").strip(),
        }

    def _property_mailbox_import_activity_from_signal(
        self,
        *,
        signal: google_oauth_service.GoogleWorkspaceSignal,
    ) -> dict[str, object]:
        payload = dict(signal.payload or {})
        subject = str(signal.title or "").strip()
        summary = str(signal.summary or "").strip()
        body_text = str(payload.get("body_text_excerpt") or signal.text or "").strip()
        sender = " ".join(
            part for part in (
                str(payload.get("from_name") or "").strip(),
                str(payload.get("from_email") or "").strip().lower(),
                str(signal.counterparty or "").strip(),
            )
            if part
        ).strip()
        combined = " \n ".join(part for part in (subject, summary, body_text, sender) if part)
        activity_kind = _property_profile_detect_activity_kind(combined)
        provider = _property_profile_provider_from_text(combined)
        if not activity_kind and not provider:
            return {}
        features = _property_profile_detect_features(combined)
        lower_text = combined.lower()
        inferred_listing_mode = "buy" if any(marker in lower_text for marker in ("kauf", "eigentum", "purchase")) else "rent"
        inferred_property_type = "house" if any(marker in lower_text for marker in ("haus", "house", "reihenhaus")) else "apartment"
        thread_id = str(payload.get("thread_id") or "").strip()
        return {
            "object_id": thread_id or str(signal.source_ref or "").strip() or uuid4().hex,
            "source_ref": str(signal.source_ref or "").strip(),
            "thread_id": thread_id,
            "account_email": str(payload.get("account_email") or "").strip().lower(),
            "activity_kind": activity_kind or "property_signal",
            "provider": provider,
            "subject": compact_text(subject, fallback="Property mailbox activity", limit=240),
            "location_hint": _property_profile_detect_location_hint(combined),
            "price_eur": _property_profile_detect_price_eur(combined),
            "area_sqm": _property_profile_detect_area_sqm(combined),
            "rooms": _property_profile_detect_rooms(combined),
            "detected_features": features,
            "inferred_listing_mode": inferred_listing_mode,
            "inferred_property_type": inferred_property_type,
        }

    def _property_mailbox_preference_hints_from_activities(
        self,
        *,
        activities: list[dict[str, object]],
    ) -> list[dict[str, object]]:
        hints: list[dict[str, object]] = []
        if not activities:
            return hints
        districts: list[str] = []
        areas: list[float] = []
        rooms: list[float] = []
        prices: list[float] = []
        feature_counts: dict[str, int] = {}
        listing_modes: list[str] = []
        property_types: list[str] = []
        for item in activities:
            location_hint = str(item.get("location_hint") or "").strip()
            if location_hint:
                districts.append(location_hint)
            area_value = item.get("area_sqm")
            if isinstance(area_value, (int, float)) and float(area_value) > 0:
                areas.append(float(area_value))
            rooms_value = item.get("rooms")
            if isinstance(rooms_value, (int, float)) and float(rooms_value) > 0:
                rooms.append(float(rooms_value))
            price_value = item.get("price_eur")
            if isinstance(price_value, (int, float)) and float(price_value) > 0:
                prices.append(float(price_value))
            for feature in list(item.get("detected_features") or []):
                normalized_feature = str(feature or "").strip()
                if normalized_feature:
                    feature_counts[normalized_feature] = feature_counts.get(normalized_feature, 0) + 1
            listing_mode = str(item.get("inferred_listing_mode") or "").strip()
            if listing_mode:
                listing_modes.append(listing_mode)
            property_type = str(item.get("inferred_property_type") or "").strip()
            if property_type:
                property_types.append(property_type)
        unique_areas: list[str] = []
        seen_areas: set[str] = set()
        for item in districts:
            marker = item.lower()
            if marker in seen_areas:
                continue
            seen_areas.add(marker)
            unique_areas.append(item)
        if unique_areas:
            hints.append(
                {
                    "domain": "willhaben",
                    "category": "soft_preference",
                    "key": "preferred_areas",
                    "value_json": unique_areas[:12],
                    "strength": "high",
                    "merge_mode": "append_unique",
                    "source_mode": "behavioral_inference",
                    "confidence": 0.88,
                }
            )
        if areas:
            hints.append(
                {
                    "domain": "willhaben",
                    "category": "soft_preference",
                    "key": "min_area_sqm_preference",
                    "value_json": max(1, int(round(statistics.median(areas)))),
                    "strength": "medium",
                    "source_mode": "behavioral_inference",
                    "confidence": 0.76,
                }
            )
        if rooms:
            hints.append(
                {
                    "domain": "willhaben",
                    "category": "constraint",
                    "key": "min_rooms",
                    "value_json": max(1, int(math.floor(min(rooms)))),
                    "strength": "medium",
                    "source_mode": "behavioral_inference",
                    "confidence": 0.72,
                }
            )
        if prices:
            hints.append(
                {
                    "domain": "willhaben",
                    "category": "soft_preference",
                    "key": "prefer_lower_total_rent_eur",
                    "value_json": max(1, int(round(statistics.median(prices)))),
                    "strength": "medium",
                    "source_mode": "behavioral_inference",
                    "confidence": 0.68,
                }
            )
        total = max(len(activities), 1)
        feature_key_map = {
            "balcony": ("soft_preference", "prefer_balcony"),
            "outdoor_space": ("soft_preference", "prefer_outdoor_space"),
            "lift": ("soft_preference", "prefer_lift"),
            "floorplan": ("soft_preference", "requires_floorplan_for_remote_review"),
            "tour_360": ("soft_preference", "prefer_360_for_remote_review"),
            "playground": ("soft_preference", "prefer_playgrounds_nearby"),
            "library": ("soft_preference", "prefer_libraries_nearby"),
            "market": ("soft_preference", "prefer_markets_nearby"),
            "hardware": ("soft_preference", "prefer_hardware_store_nearby"),
            "medical": ("soft_preference", "prefer_medical_care_nearby"),
            "subway": ("soft_preference", "prefer_subway_nearby"),
            "quiet": ("soft_preference", "prefer_quiet_micro_location"),
        }
        for feature, count in feature_counts.items():
            if count / total < 0.45:
                continue
            category_key = feature_key_map.get(feature)
            if category_key is None:
                continue
            hints.append(
                {
                    "domain": "willhaben",
                    "category": category_key[0],
                    "key": category_key[1],
                    "value_json": True,
                    "strength": "medium" if count / total < 0.7 else "high",
                    "source_mode": "behavioral_inference",
                    "confidence": 0.6 if count / total < 0.7 else 0.82,
                }
            )
        if listing_modes and listing_modes.count("buy") >= listing_modes.count("rent"):
            hints.append(
                {
                    "domain": "general",
                    "category": "workflow_preference",
                    "key": "prefers_direct_followups",
                    "value_json": True,
                    "strength": "low",
                    "source_mode": "behavioral_inference",
                    "confidence": 0.55,
                }
            )
        if property_types and property_types.count("house") >= max(1, property_types.count("apartment")):
            hints.append(
                {
                    "domain": "general",
                    "category": "decision_style",
                    "key": "needs_side_by_side_comparison",
                    "value_json": True,
                    "strength": "low",
                    "source_mode": "behavioral_inference",
                    "confidence": 0.45,
                }
            )
        return hints

