    def record_property_feedback(
        self,
        *,
        principal_id: str,
        property_slug: str,
        property_url: str,
        property_title: str,
        property_facts: dict[str, object],
        reaction: str,
        reason_keys: tuple[str, ...] = (),
        note: str = "",
        person_id: str = "self",
        actor: str = "",
    ) -> dict[str, object]:
        normalized_person_id = str(person_id or "").strip() or "self"
        normalized_reaction = str(reaction or "").strip().lower()
        if normalized_reaction not in {"like", "dislike", "maybe", "hide"}:
            raise ValueError("invalid_property_feedback_reaction")
        normalized_reason_keys = tuple(
            str(item or "").strip().lower()
            for item in reason_keys
            if str(item or "").strip()
        )
        existing_bundle = self.get_preference_profile(
            principal_id=principal_id,
            person_id=normalized_person_id,
        )
        existing_profile = dict(existing_bundle.get("profile") or {}) if isinstance(existing_bundle.get("profile"), dict) else {}
        if not existing_profile:
            self.upsert_preference_profile(
                principal_id=principal_id,
                person_id=normalized_person_id,
            )
        hints = _property_feedback_inferred_hints(
            reaction=normalized_reaction,
            reason_keys=normalized_reason_keys,
            property_facts=property_facts,
        )
        event_type = {
            "like": "listing_feedback_like",
            "dislike": "listing_feedback_dislike",
            "maybe": "listing_feedback_maybe",
            "hide": "listing_feedback_hide",
        }[normalized_reaction]
        raw_signal_json = {
            "reaction": normalized_reaction,
            "reason_keys": list(normalized_reason_keys),
            "reason_labels": [
                str(_property_feedback_reason_detail(key).get("label") or key)
                for key in normalized_reason_keys
            ],
            "note": compact_text(note, fallback="", limit=500),
            "district": str(property_facts.get("postal_name") or property_facts.get("district") or property_facts.get("location") or "").strip(),
            "heating_type": str(property_facts.get("heating") or property_facts.get("heating_type") or "").strip(),
            "total_rent_eur": property_facts.get("total_rent_eur"),
            "area_sqm": property_facts.get("area_sqm"),
            "property_url": str(property_url or "").strip(),
            "property_title": compact_text(property_title, fallback="", limit=180),
            "property_slug": str(property_slug or "").strip(),
            "actor": compact_text(actor, fallback="", limit=80),
        }
        evidence = self.record_preference_evidence(
            principal_id=principal_id,
            person_id=normalized_person_id,
            domain="willhaben",
            event_type=event_type,
            object_type="listing",
            object_id=str(property_url or property_slug or property_title or "listing").strip(),
            source_ref=f"public_tour:{str(property_slug or '').strip()}",
            raw_signal_json=raw_signal_json,
            interpreted_signal_json={
                "preference_hints": hints,
                "feedback_kind": "property_reaction",
                "feedback_reason_keys": list(normalized_reason_keys),
            },
            signal_strength=0.95 if normalized_reaction in {"like", "dislike"} else 0.7,
            reversible=True,
        )
        updated_assessment = self.assess_preference_candidate(
            principal_id=principal_id,
            person_id=normalized_person_id,
            domain="willhaben",
            object_type="listing",
            object_id=str(property_url or property_slug or property_title or "listing").strip(),
            object_payload=dict(property_facts or {}),
        ) or {}
        profile_bundle = self.get_preference_profile(
            principal_id=principal_id,
            person_id=normalized_person_id,
        )
        decision_loop = build_property_decision_loop_snapshot(
            property_ref=str(property_url or property_slug or property_title or "property").strip(),
            reaction=normalized_reaction,
            reason_keys=list(normalized_reason_keys),
            note=note,
            source="workbench",
            actor=actor,
            property_facts=property_facts,
            learning_applied=True,
            aggregate_candidate=normalized_reaction in {"dislike", "hide"},
        )
        decision_persistence = self._persist_property_decision_loop(
            principal_id=principal_id,
            person_id=normalized_person_id,
            snapshot=decision_loop,
        )
        return {
            "status": "recorded",
            "reaction": normalized_reaction,
            "reason_keys": list(normalized_reason_keys),
            "evidence": evidence,
            "updated_assessment": updated_assessment,
            "learning_summary": _property_feedback_learning_summary(profile_bundle, domain="willhaben"),
            "preference_snapshot": {
                "profile": dict(profile_bundle.get("profile") or {}),
                "preference_nodes": list(profile_bundle.get("preference_nodes") or []),
            },
            "decision_ledger": decision_loop.decision.model_dump(),
            "evidence_graph": [claim.model_dump() for claim in decision_loop.evidence_claims],
            "agent_question_tasks": [task.model_dump() for task in decision_loop.agent_question_tasks],
            "document_intake": [document.model_dump() for document in decision_loop.document_records],
            "suppression_explanation": list(decision_loop.suppression_explanation),
            "decision_persistence": decision_persistence,
        }

    def _persist_property_decision_loop(
        self,
        *,
        principal_id: str,
        person_id: str,
        snapshot: PropertyDecisionLoopSnapshot,
    ) -> dict[str, object]:
        database_url = _property_search_run_database_url()
        if not database_url:
            return {"persisted": False, "reason": "database_url_missing"}
        try:
            from app.repositories.property_decision_loop_postgres import PostgresPropertyDecisionLoopRepository

            return PostgresPropertyDecisionLoopRepository(database_url).persist_snapshot(
                principal_id=principal_id,
                person_id=person_id,
                snapshot=snapshot,
            )
        except Exception as exc:
            return {"persisted": False, "reason": "decision_loop_persistence_failed", "detail": str(exc)[:240]}

    def property_decision_loop_state(
        self,
        *,
        principal_id: str,
        property_ref: str = "",
        limit: int = 50,
    ) -> dict[str, object]:
        normalized_principal = str(principal_id or "").strip()
        normalized_property_ref = str(property_ref or "").strip()
        database_url = _property_search_run_database_url()
        if not normalized_principal:
            return {
                "status": "blocked",
                "property_ref": normalized_property_ref,
                "decisions": [],
                "evidence_claims": [],
                "agent_question_tasks": [],
                "document_intake": [],
                "latest_decision": {},
                "next_actions": [],
                "persistence": {"available": False, "reason": "principal_id_missing"},
            }
        if not database_url:
            return {
                "status": "blocked",
                "property_ref": normalized_property_ref,
                "decisions": [],
                "evidence_claims": [],
                "agent_question_tasks": [],
                "document_intake": [],
                "latest_decision": {},
                "next_actions": [],
                "persistence": {"available": False, "reason": "database_url_missing"},
            }
        try:
            from app.repositories.property_decision_loop_postgres import PostgresPropertyDecisionLoopRepository

            rows = PostgresPropertyDecisionLoopRepository(database_url).export_teable_projection_rows(
                principal_id=normalized_principal,
                limit=max(int(limit or 50), 50),
            )
        except Exception as exc:
            return {
                "status": "blocked",
                "property_ref": normalized_property_ref,
                "decisions": [],
                "evidence_claims": [],
                "agent_question_tasks": [],
                "document_intake": [],
                "latest_decision": {},
                "next_actions": [],
                "persistence": {
                    "available": False,
                    "reason": "decision_loop_read_failed",
                    "detail": compact_text(str(exc or ""), fallback="decision loop read failed", limit=180),
                },
            }

        def _matches(row: dict[str, object]) -> bool:
            return not normalized_property_ref or str(row.get("property_ref") or "").strip() == normalized_property_ref

        decisions = [dict(row) for row in list(rows.get("propertyquarry_decision_ledger") or []) if isinstance(row, dict) and _matches(row)]
        evidence_claims = [dict(row) for row in list(rows.get("propertyquarry_evidence_claims") or []) if isinstance(row, dict) and _matches(row)]
        agent_questions = [dict(row) for row in list(rows.get("propertyquarry_agent_questions") or []) if isinstance(row, dict) and _matches(row)]
        documents = [dict(row) for row in list(rows.get("propertyquarry_documents") or []) if isinstance(row, dict) and _matches(row)]
        latest_decision = dict(decisions[0]) if decisions else {}
        next_actions: list[str] = []
        drafted_questions = [row for row in agent_questions if str(row.get("status") or "").strip().lower() == "drafted"]
        if drafted_questions:
            next_actions.append("Send the drafted agent question.")
        missing_documents = [
            row
            for row in documents
            if str(row.get("verification_state") or "").strip().lower() in {"missing", "rejected"}
        ]
        if missing_documents:
            next_actions.append("Upload or request the missing document.")
        if latest_decision and str(latest_decision.get("decision_state") or "").strip() in {"rejected", "archived"}:
            next_actions.append("Keep the raw reason private and use the normalized reason for future ranking.")
        if not next_actions and latest_decision:
            next_actions.append("Review the latest decision state before changing the search rules.")
        return {
            "status": "ready",
            "property_ref": normalized_property_ref,
            "decisions": decisions[: max(1, min(int(limit or 50), 200))],
            "evidence_claims": evidence_claims[: max(1, min(int(limit or 50), 200))],
            "agent_question_tasks": agent_questions[: max(1, min(int(limit or 50), 200))],
            "document_intake": documents[: max(1, min(int(limit or 50), 200))],
            "latest_decision": latest_decision,
            "next_actions": next_actions,
            "persistence": {"available": True, "source": "postgres"},
        }

    def _property_saved_shortlist_property_ref(self, candidate: dict[str, object]) -> str:
        facts = dict(candidate.get("property_facts") or {}) if isinstance(candidate.get("property_facts"), dict) else {}
        for value in (
            candidate.get("property_ref"),
            candidate.get("property_url"),
            candidate.get("source_url"),
            candidate.get("review_url"),
            facts.get("listing_url"),
            facts.get("canonical_url"),
            candidate.get("source_ref"),
            candidate.get("candidate_ref"),
        ):
            normalized = urllib.parse.urldefrag(str(value or "").strip())[0]
            if normalized:
                return normalized
        return ""

    def _property_saved_shortlist_decision_states(
        self,
        *,
        principal_id: str,
        property_refs: list[str] | tuple[str, ...] | None = None,
        limit: int = 500,
    ) -> dict[str, str]:
        normalized_principal = str(principal_id or "").strip()
        database_url = _property_search_run_database_url()
        if not normalized_principal or not database_url:
            return {}
        refs = tuple(
            dict.fromkeys(
                urllib.parse.urldefrag(str(ref or "").strip())[0]
                for ref in list(property_refs or [])
                if str(ref or "").strip()
            )
        )
        if property_refs is not None and not refs:
            return {}
        try:
            from app.repositories.property_decision_loop_postgres import PostgresPropertyDecisionLoopRepository

            repository = PostgresPropertyDecisionLoopRepository(database_url)
            if refs:
                states = repository.latest_decision_states_for_property_refs(
                    principal_id=normalized_principal,
                    property_refs=refs,
                    limit=max(len(refs), min(int(limit or 500), 1000)),
                )
                return {
                    str(ref or "").strip(): str(state or "").strip().lower()
                    for ref, state in states.items()
                    if str(ref or "").strip()
                }
            rows = repository.export_teable_projection_rows(
                principal_id=normalized_principal,
                limit=max(int(limit or 500), 100),
            )
        except Exception:
            return {}
        latest: dict[str, str] = {}
        for row in list(rows.get("propertyquarry_decision_ledger") or []):
            if not isinstance(row, dict):
                continue
            property_ref = str(row.get("property_ref") or "").strip()
            if not property_ref or property_ref in latest:
                continue
            latest[property_ref] = str(row.get("decision_state") or "").strip().lower()
        return latest

    def list_property_saved_shortlist_candidates(
        self,
        *,
        principal_id: str,
        status: dict[str, object] | None = None,
    ) -> list[dict[str, object]]:
        normalized_principal = str(principal_id or "").strip()
        if not normalized_principal:
            return []
        status_payload = (
            dict(status or {})
            if isinstance(status, dict)
            else self._container.onboarding.status(principal_id=normalized_principal)
        )
        preferences = dict(status_payload.get("property_search_preferences") or {})
        raw_candidates = list(preferences.get("saved_shortlist_candidates") or [])
        candidate_rows: list[tuple[str, dict[str, object]]] = []
        for item in raw_candidates:
            if not isinstance(item, dict):
                continue
            row = dict(item)
            property_ref = str(row.get("property_ref") or self._property_saved_shortlist_property_ref(row)).strip()
            if not property_ref:
                continue
            candidate_rows.append((property_ref, row))
        decision_states = self._property_saved_shortlist_decision_states(
            principal_id=normalized_principal,
            property_refs=tuple(property_ref for property_ref, _row in candidate_rows),
        )
        visible: list[dict[str, object]] = []
        seen: set[str] = set()
        for property_ref, row in candidate_rows:
            if property_ref in seen:
                continue
            seen.add(property_ref)
            state = decision_states.get(property_ref, "")
            if state in {"archived", "rejected"}:
                continue
            row["property_ref"] = property_ref
            visible.append(row)
        return visible[:200]

    def persist_property_saved_shortlist_candidates(
        self,
        *,
        principal_id: str,
        run_id: str = "",
        candidates: list[dict[str, object]] | tuple[dict[str, object], ...],
    ) -> list[dict[str, object]]:
        normalized_principal = str(principal_id or "").strip()
        if not normalized_principal:
            return []
        status = self._container.onboarding.status(principal_id=normalized_principal)
        preferences = dict(status.get("property_search_preferences") or {})
        existing_rows = [
            dict(item)
            for item in list(preferences.get("saved_shortlist_candidates") or [])
            if isinstance(item, dict)
        ]
        candidate_refs = [
            str(row.get("property_ref") or self._property_saved_shortlist_property_ref(row)).strip()
            for row in existing_rows
        ]
        candidate_refs.extend(
            str(candidate.get("property_ref") or self._property_saved_shortlist_property_ref(candidate)).strip()
            for candidate in list(candidates or [])
            if isinstance(candidate, dict)
        )
        decision_states = self._property_saved_shortlist_decision_states(
            principal_id=normalized_principal,
            property_refs=tuple(ref for ref in candidate_refs if ref),
        )
        blocked_refs = {
            property_ref
            for property_ref, state in decision_states.items()
            if state in {"archived", "rejected"}
        }
        by_ref: dict[str, dict[str, object]] = {}
        for row in existing_rows:
            property_ref = str(row.get("property_ref") or self._property_saved_shortlist_property_ref(row)).strip()
            if not property_ref or property_ref in blocked_refs:
                continue
            normalized_row = dict(row)
            normalized_row["property_ref"] = property_ref
            by_ref[property_ref] = normalized_row
        saved_at = _now_iso()
        for candidate in list(candidates or []):
            if not isinstance(candidate, dict):
                continue
            property_ref = str(candidate.get("property_ref") or self._property_saved_shortlist_property_ref(candidate)).strip()
            if not property_ref or property_ref in blocked_refs:
                continue
            previous = dict(by_ref.get(property_ref) or {})
            merged = {
                **previous,
                **dict(candidate),
                "property_ref": property_ref,
                "saved_from_run_id": str(run_id or previous.get("saved_from_run_id") or "").strip(),
                "saved_at": saved_at,
                "first_saved_at": str(previous.get("first_saved_at") or saved_at).strip() or saved_at,
            }
            by_ref[property_ref] = merged
        merged_rows = sorted(
            by_ref.values(),
            key=lambda item: (
                str(item.get("saved_at") or ""),
                -(int(item.get("rank") or 9999) if str(item.get("rank") or "").strip() else 9999),
            ),
            reverse=True,
        )[:200]
        preferences["saved_shortlist_candidates"] = merged_rows
        preferences["saved_shortlist_share_slug"] = str(
            preferences.get("saved_shortlist_share_slug")
            or f"shortlist-{hashlib.sha256(normalized_principal.encode('utf-8')).hexdigest()[:16]}"
        ).strip()
        saved = self._container.onboarding.upsert_property_search_preferences(
            principal_id=normalized_principal,
            property_search_preferences_json=preferences,
        )
        return [
            dict(item)
            for item in list(dict(saved.get("property_search_preferences") or {}).get("saved_shortlist_candidates") or [])
            if isinstance(item, dict)
        ]

