    def preference_teable_sync_preview(
        self,
        *,
        principal_id: str,
        person_id: str = "self",
    ) -> dict[str, object]:
        normalized_person_id = str(person_id or "").strip() or "self"
        records = self.preference_teable_projection_records(
            principal_id=principal_id,
            person_id=normalized_person_id,
        )
        sync_tables = {
            "preference_review_queue": [dict(row) for row in records.get("preference_review_queue") or []],
        }
        summary = self.preference_teable_projection_summary(
            principal_id=principal_id,
            person_id=normalized_person_id,
        )
        provider_state = self._container.provider_registry.binding_state("teable", principal_id=principal_id)
        teable_base_url = str(os.environ.get("TEABLE_BASE_URL") or "https://app.teable.ai").strip().rstrip("/")
        table_sync_config_raw = str(os.environ.get("TEABLE_TABLE_SYNC_CONFIG_JSON") or "").strip()
        table_sync_configured = False
        if table_sync_config_raw:
            try:
                parsed_table_sync = json.loads(table_sync_config_raw)
            except Exception:
                parsed_table_sync = {}
            table_sync_configured = isinstance(parsed_table_sync, dict) and "preference_review_queue" in parsed_table_sync
        candidate_routes = tuple(
            route
            for route in self._container.provider_registry.candidate_routes_by_capability_with_context(
                capability_key="table_sync",
                principal_id=principal_id,
                require_executable=False,
            )
            if str(route.provider_key or "").strip().lower() == "teable"
        )
        provider_state_value = str(getattr(provider_state, "state", "") or "catalog_only").strip().lower() or "catalog_only"
        provider_routable = provider_state_value not in {"catalog_only", "unconfigured", "disabled", "maintenance"}
        runtime_reachable = False
        runtime_blocked_reason = ""
        if provider_routable and table_sync_configured and bool(getattr(provider_state, "secret_configured", False)):
            runtime_reachable, runtime_blocked_reason = self._teable_sync_runtime_available(base_url=teable_base_url)
        executable_route = next(
            (
                route
                for route in candidate_routes
                if bool(route.executable) and provider_routable and table_sync_configured and runtime_reachable
            ),
            None,
        )
        total_records = sum(len(rows) for rows in sync_tables.values())
        sync_payload = {
            "projection_scope": "preference_profile",
            "person_id": normalized_person_id,
            "tables_json": sync_tables,
        }
        return {
            "status": "ready" if executable_route is not None else "blocked",
            "blocked_reason": (
                ""
                if executable_route is not None
                else (
                    "teable_table_sync_config_missing"
                    if not table_sync_configured
                    else (runtime_blocked_reason or "teable_table_sync_unavailable")
                )
            ),
            "provider": {
                "provider_key": "teable",
                "display_name": str(getattr(provider_state, "display_name", "") or "Teable").strip() or "Teable",
                "binding_state": provider_state_value,
                "enabled": bool(getattr(provider_state, "enabled", False)),
                "executable": bool(getattr(provider_state, "executable", False)),
                "binding_id": str(getattr(provider_state, "binding_id", "") or "").strip(),
                "secret_configured": bool(getattr(provider_state, "secret_configured", False)),
                "table_sync_configured": table_sync_configured,
                "runtime_reachable": runtime_reachable,
                "base_url": teable_base_url,
                "updated_at": str(getattr(provider_state, "updated_at", "") or "").strip(),
            },
            "route": {
                "capability_key": "table_sync",
                "tool_name": str(getattr(executable_route, "tool_name", "") or "provider.teable.table_sync").strip(),
                "candidate_count": len(candidate_routes),
                "candidate_tools": [str(route.tool_name or "").strip() for route in candidate_routes],
                "executable": executable_route is not None,
            },
            "projection_summary": summary,
            "projected_table_count": len(sync_tables),
            "projected_record_count": total_records,
            "records_preview": {
                table_name: [dict(row) for row in rows[:3]]
                for table_name, rows in sync_tables.items()
            },
            "sync_payload_json": sync_payload,
            "generated_at": datetime.now(timezone.utc).isoformat(),
        }

    def _teable_sync_runtime_available(self, *, base_url: str) -> tuple[bool, str]:
        normalized_base_url = str(base_url or "").strip().rstrip("/")
        if not normalized_base_url:
            return False, "teable_runtime_unreachable"
        api_key = str(os.environ.get("TEABLE_API_KEY") or "").strip()
        if not api_key:
            return False, "teable_runtime_unreachable"
        health_url = f"{normalized_base_url}/healthz"
        request_headers = {
            "Authorization": f"Bearer {api_key}",
            "Accept": "application/json, text/plain, */*",
            "Accept-Language": "en-US,en;q=0.9",
            "Origin": "https://app.teable.ai",
            "Referer": "https://app.teable.ai/",
            "User-Agent": (
                "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 "
                "(KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36"
            ),
        }
        try:
            request = urllib.request.Request(health_url, method="GET")
            for key, value in request_headers.items():
                request.add_header(key, value)
            with urllib.request.urlopen(request, timeout=10) as response:
                payload = response.read().decode("utf-8")
                data = json.loads(payload or "{}")
            if int(getattr(response, "status", 0) or 0) == 200 and str(data.get("status") or "").strip().lower() == "ok":
                return True, ""
        except urllib.error.HTTPError as exc:
            if int(getattr(exc, "code", 0) or 0) not in {404, 405}:
                return False, "teable_runtime_unreachable"
        except Exception:
            return False, "teable_runtime_unreachable"
        try:
            request = urllib.request.Request(f"{normalized_base_url}/api/auth/user", method="GET")
            for key, value in request_headers.items():
                request.add_header(key, value)
            with urllib.request.urlopen(request, timeout=15) as response:
                payload = response.read().decode("utf-8")
                data = json.loads(payload or "{}")
            if int(getattr(response, "status", 0) or 0) == 200 and str(data.get("email") or data.get("id") or "").strip():
                return True, ""
        except Exception:
            return False, "teable_runtime_unreachable"
        return False, "teable_runtime_unreachable"

    def request_preference_teable_sync(
        self,
        *,
        principal_id: str,
        person_id: str = "self",
    ) -> dict[str, object]:
        preview = self.preference_teable_sync_preview(
            principal_id=principal_id,
            person_id=person_id,
        )
        if str(preview.get("status") or "").strip().lower() != "ready":
            return {
                **preview,
                "sync_attempted": False,
                "sync_result": "blocked",
            }
        route = dict(preview.get("route") or {})
        tool_name = str(route.get("tool_name") or "").strip()
        payload_json = dict(preview.get("sync_payload_json") or {})
        invocation = ToolInvocationRequest(
            session_id=f"product-teable-sync:{uuid4()}",
            step_id=f"product-teable-sync-step:{uuid4()}",
            tool_name=tool_name,
            action_kind="table.sync",
            payload_json=payload_json,
            context_json={"principal_id": principal_id},
        )
        result = self._container.tool_execution.execute_invocation(invocation)
        return {
            **preview,
            "sync_attempted": True,
            "sync_result": "sent",
            "tool_execution": {
                "tool_name": result.tool_name,
                "action_kind": result.action_kind,
                "target_ref": result.target_ref,
                "output_json": dict(result.output_json or {}),
                "receipt_json": dict(result.receipt_json or {}),
            },
        }

    def _propertyquarry_teable_table_config(self) -> dict[str, dict[str, object]]:
        raw = str(os.environ.get("PROPERTYQUARRY_TEABLE_TABLE_SYNC_CONFIG_JSON") or "").strip()
        if not raw:
            raw = str(os.environ.get("TEABLE_TABLE_SYNC_CONFIG_JSON") or "").strip()
        if raw:
            try:
                loaded = json.loads(raw)
            except Exception:
                loaded = {}
            if isinstance(loaded, dict):
                config = {
                    str(table_name or "").strip(): dict(table_config or {})
                    for table_name, table_config in dict(loaded or {}).items()
                    if str(table_name or "").strip() and isinstance(table_config, dict)
                }
                if config:
                    return config
        return discover_propertyquarry_teable_table_config(
            base_url=str(os.environ.get("TEABLE_BASE_URL") or "https://app.teable.ai").strip().rstrip("/"),
            api_key=str(os.environ.get("TEABLE_API_KEY") or "").strip(),
            base_id=str(os.environ.get("PROPERTYQUARRY_TEABLE_BASE_ID") or os.environ.get("TEABLE_BASE_ID") or "").strip(),
            base_name=str(os.environ.get("PROPERTYQUARRY_TEABLE_TENANT_NAME") or "PropertyQuarry").strip(),
        )

    def _propertyquarry_teable_missing_table_mappings(self, config: dict[str, dict[str, object]]) -> list[str]:
        missing: list[str] = []
        for table_name in PROPERTYQUARRY_TEABLE_TABLE_NAMES:
            table_config = dict(config.get(table_name) or {})
            if not str(table_config.get("table_id") or "").strip():
                missing.append(table_name)
        return missing

    def propertyquarry_teable_projection_records(
        self,
        *,
        principal_id: str,
        run_id: str = "",
        limit: int = 20,
    ) -> dict[str, list[dict[str, object]]]:
        normalized_principal = str(principal_id or "").strip()
        normalized_run_id = str(run_id or "").strip()
        onboarding_status = self._container.onboarding.status(principal_id=normalized_principal) if normalized_principal else {}
        runs: list[dict[str, object]] = []
        if normalized_run_id:
            snapshot = self.get_property_search_run_status(
                principal_id=normalized_principal,
                run_id=normalized_run_id,
            )
            if isinstance(snapshot, dict):
                runs.append(dict(snapshot))
        elif normalized_principal:
            records = _list_property_search_run_records(
                limit=max(int(limit or 0), 1),
                principal_id=normalized_principal,
            )
            for record in records:
                run_record_id = str(record.get("run_id") or "").strip()
                snapshot = self.get_property_search_run_status(
                    principal_id=normalized_principal,
                    run_id=run_record_id,
                ) if run_record_id else None
                runs.append(dict(snapshot or record))
        decision_loop_rows: dict[str, list[dict[str, object]]] = {}
        database_url = _property_search_run_database_url()
        if normalized_principal and database_url:
            try:
                from app.repositories.property_decision_loop_postgres import PostgresPropertyDecisionLoopRepository

                decision_loop_rows = PostgresPropertyDecisionLoopRepository(database_url).export_teable_projection_rows(
                    principal_id=normalized_principal,
                    limit=max(int(limit or 20), 20),
                )
            except Exception:
                decision_loop_rows = {}
        return build_propertyquarry_teable_projection_records(
            principal_id=normalized_principal,
            onboarding_status=dict(onboarding_status or {}),
            search_runs=tuple(runs),
            decision_loop_rows=decision_loop_rows,
        )

    def propertyquarry_teable_projection_summary(
        self,
        *,
        principal_id: str,
        run_id: str = "",
        limit: int = 20,
    ) -> dict[str, object]:
        records = self.propertyquarry_teable_projection_records(
            principal_id=principal_id,
            run_id=run_id,
            limit=limit,
        )
        return build_propertyquarry_teable_projection_summary(records)

    def propertyquarry_teable_sync_preview(
        self,
        *,
        principal_id: str,
        run_id: str = "",
        limit: int = 20,
    ) -> dict[str, object]:
        records = self.propertyquarry_teable_projection_records(
            principal_id=principal_id,
            run_id=run_id,
            limit=limit,
        )
        summary = build_propertyquarry_teable_projection_summary(records)
        table_config = self._propertyquarry_teable_table_config()
        missing_tables = self._propertyquarry_teable_missing_table_mappings(table_config)
        table_sync_configured = not missing_tables
        provider_state = self._container.provider_registry.binding_state("teable", principal_id=principal_id)
        teable_base_url = str(os.environ.get("TEABLE_BASE_URL") or "https://app.teable.ai").strip().rstrip("/")
        candidate_routes = tuple(
            route
            for route in self._container.provider_registry.candidate_routes_by_capability_with_context(
                capability_key="table_sync",
                principal_id=principal_id,
                require_executable=False,
            )
            if str(route.provider_key or "").strip().lower() == "teable"
        )
        provider_state_value = str(getattr(provider_state, "state", "") or "catalog_only").strip().lower() or "catalog_only"
        provider_routable = provider_state_value not in {"catalog_only", "unconfigured", "disabled", "maintenance"}
        runtime_reachable = False
        runtime_blocked_reason = ""
        if provider_routable and table_sync_configured and bool(getattr(provider_state, "secret_configured", False)):
            runtime_reachable, runtime_blocked_reason = self._teable_sync_runtime_available(base_url=teable_base_url)
        executable_route = next(
            (
                route
                for route in candidate_routes
                if bool(route.executable) and provider_routable and table_sync_configured and runtime_reachable
            ),
            None,
        )
        if executable_route is not None:
            blocked_reason = ""
        elif not table_sync_configured:
            blocked_reason = "propertyquarry_teable_table_sync_config_missing"
        elif not provider_routable:
            blocked_reason = "teable_provider_unconfigured"
        else:
            blocked_reason = runtime_blocked_reason or "teable_table_sync_unavailable"
        sync_payload = {
            "projection_scope": "propertyquarry",
            "person_id": propertyquarry_teable_tenant_key(),
            "tables_json": records,
            "table_config_json": table_config,
        }
        return {
            "status": "ready" if executable_route is not None else "blocked",
            "blocked_reason": blocked_reason,
            "provider": {
                "provider_key": "teable",
                "display_name": str(getattr(provider_state, "display_name", "") or "Teable").strip() or "Teable",
                "binding_state": provider_state_value,
                "enabled": bool(getattr(provider_state, "enabled", False)),
                "executable": bool(getattr(provider_state, "executable", False)),
                "binding_id": str(getattr(provider_state, "binding_id", "") or "").strip(),
                "secret_configured": bool(getattr(provider_state, "secret_configured", False)),
                "table_sync_configured": table_sync_configured,
                "missing_tables": missing_tables,
                "runtime_reachable": runtime_reachable,
                "base_url": teable_base_url,
                "updated_at": str(getattr(provider_state, "updated_at", "") or "").strip(),
            },
            "route": {
                "capability_key": "table_sync",
                "tool_name": str(getattr(executable_route, "tool_name", "") or "provider.teable.table_sync").strip(),
                "candidate_count": len(candidate_routes),
                "candidate_tools": [str(route.tool_name or "").strip() for route in candidate_routes],
                "executable": executable_route is not None,
            },
            "projection_summary": summary,
            "projected_table_count": len(records),
            "projected_record_count": sum(len(rows) for rows in records.values()),
            "records_preview": {
                table_name: [dict(row) for row in rows[:2]]
                for table_name, rows in records.items()
            },
            "sync_payload_json": sync_payload,
            "generated_at": datetime.now(timezone.utc).isoformat(),
        }

    def request_propertyquarry_teable_sync(
        self,
        *,
        principal_id: str,
        run_id: str = "",
        limit: int = 20,
    ) -> dict[str, object]:
        preview = self.propertyquarry_teable_sync_preview(
            principal_id=principal_id,
            run_id=run_id,
            limit=limit,
        )
        if str(preview.get("status") or "").strip().lower() != "ready":
            return {
                **preview,
                "sync_attempted": False,
                "sync_result": "blocked",
            }
        route = dict(preview.get("route") or {})
        tool_name = str(route.get("tool_name") or "provider.teable.table_sync").strip()
        payload_json = dict(preview.get("sync_payload_json") or {})
        invocation = ToolInvocationRequest(
            session_id=f"propertyquarry-teable-sync:{uuid4()}",
            step_id=f"propertyquarry-teable-sync-step:{uuid4()}",
            tool_name=tool_name,
            action_kind="table.sync",
            payload_json=payload_json,
            context_json={"principal_id": principal_id, "run_id": str(run_id or "").strip()},
        )
        result = self._container.tool_execution.execute_invocation(invocation)
        return {
            **preview,
            "sync_attempted": True,
            "sync_result": "sent",
            "tool_execution": {
                "tool_name": result.tool_name,
                "action_kind": result.action_kind,
                "target_ref": result.target_ref,
                "output_json": dict(result.output_json or {}),
                "receipt_json": dict(result.receipt_json or {}),
            },
        }

    def _propertyquarry_teable_auto_sync_enabled(self) -> bool:
        raw = str(os.environ.get("PROPERTYQUARRY_TEABLE_AUTO_SYNC") or "0").strip().lower()
        return raw not in {"0", "false", "no", "off", "disabled"}

    def _best_effort_propertyquarry_teable_sync(
        self,
        *,
        principal_id: str,
        run_id: str = "",
        reason: str = "",
    ) -> None:
        if not self._propertyquarry_teable_auto_sync_enabled():
            return
        table_config = self._propertyquarry_teable_table_config()
        if self._propertyquarry_teable_missing_table_mappings(table_config):
            return

        def _run() -> None:
            try:
                self.request_propertyquarry_teable_sync(
                    principal_id=principal_id,
                    run_id=run_id,
                    limit=20,
                )
            except Exception as exc:
                try:
                    self._record_product_event(
                        principal_id=principal_id,
                        event_type="propertyquarry_teable_sync_failed",
                        payload={
                            "run_id": str(run_id or "").strip(),
                            "reason": compact_text(str(reason or "auto_sync"), fallback="auto_sync", limit=120),
                            "error": compact_text(str(exc or "teable sync failed"), fallback="teable sync failed", limit=240),
                        },
                        source_id=str(run_id or principal_id or "propertyquarry-teable-sync"),
                    )
                except Exception:
                    pass

        try:
            threading.Thread(target=_run, daemon=True).start()
        except Exception:
            _run()

    def _support_fix_verification_contact(
        self,
        *,
        principal_id: str,
    ) -> dict[str, str]:
        status = self._container.onboarding.status(principal_id=principal_id)
        workspace = dict(status.get("workspace") or {})
        delivery_preferences = dict(status.get("delivery_preferences") or {})
        morning_memo = dict(delivery_preferences.get("morning_memo") or {})
        google_accounts = google_oauth_service.list_google_accounts(container=self._container, principal_id=principal_id)
        primary_google_account = next(
            (
                account
                for account in google_accounts
                if str(account.binding.status or "").strip().lower() == "enabled"
                and str(account.token_status or "").strip().lower() != "revoked"
            ),
            google_accounts[0] if google_accounts else None,
        )
        recipient_email = str(
            morning_memo.get("resolved_recipient_email")
            or getattr(primary_google_account, "google_email", "")
            or ""
        ).strip().lower()
        display_name = str(workspace.get("name") or recipient_email or "PropertyQuarry account").strip()
        return {
            "recipient_email": recipient_email,
            "display_name": display_name,
            "role": "principal",
            "operator_id": "",
        }

    def _support_fix_verification_projection(
        self,
        *,
        principal_id: str,
        event_rows: tuple[object, ...] | None = None,
    ) -> dict[str, object]:
        rows = list(event_rows or ())
        if not rows:
            rows = [
                row
                for row in self._container.channel_runtime.list_recent_observations(limit=400, principal_id=principal_id)
                if str(row.channel or "").strip().lower() == "product"
            ]
        rows.sort(key=lambda row: (str(getattr(row, "created_at", "") or ""), str(getattr(row, "observation_id", "") or "")))
        contact = self._support_fix_verification_contact(principal_id=principal_id)
        recipient_email = str(contact.get("recipient_email") or "").strip().lower()
        request_row = next((row for row in reversed(rows) if str(getattr(row, "event_type", "") or "").strip() == "support_fix_verification_requested"), None)
        request_payload = dict(getattr(request_row, "payload", {}) or {}) if request_row is not None else {}
        request_id = str(request_payload.get("request_id") or getattr(request_row, "source_id", "") or "").strip()
        requested_at = str(getattr(request_row, "created_at", "") or request_payload.get("requested_at") or "").strip()
        if request_payload.get("recipient_email"):
            recipient_email = str(request_payload.get("recipient_email") or "").strip().lower()
        delivery_id = str(request_payload.get("delivery_id") or "").strip()
        access_session_id = str(request_payload.get("access_session_id") or "").strip()
        delivery_url = str(request_payload.get("delivery_url") or "").strip()
        access_url = str(request_payload.get("access_url") or "").strip()
        delivery_channel = str(request_payload.get("delivery_channel") or "").strip().lower()
        confirmed_row = next(
            (
                row
                for row in reversed(rows)
                if str(getattr(row, "event_type", "") or "").strip() == "support_fix_verification_confirmed"
                and str(dict(getattr(row, "payload", {}) or {}).get("request_id") or getattr(row, "source_id", "") or "").strip() == request_id
            ),
            None,
        )
        confirmed_at = str(getattr(confirmed_row, "created_at", "") or "").strip()
        delivery_opened = next(
            (
                row
                for row in reversed(rows)
                if str(getattr(row, "event_type", "") or "").strip() == "channel_digest_delivery_opened"
                and str(dict(getattr(row, "payload", {}) or {}).get("delivery_id") or getattr(row, "source_id", "") or "").strip() == delivery_id
            ),
            None,
        )
        delivery_sent = next(
            (
                row
                for row in reversed(rows)
                if str(getattr(row, "event_type", "") or "").strip() == "channel_digest_delivery_email_sent"
                and str(dict(getattr(row, "payload", {}) or {}).get("delivery_id") or getattr(row, "source_id", "") or "").strip() == delivery_id
            ),
            None,
        )
        delivery_failed = next(
            (
                row
                for row in reversed(rows)
                if str(getattr(row, "event_type", "") or "").strip() == "channel_digest_delivery_email_failed"
                and str(dict(getattr(row, "payload", {}) or {}).get("delivery_id") or getattr(row, "source_id", "") or "").strip() == delivery_id
            ),
            None,
        )
        access_opened = next(
            (
                row
                for row in reversed(rows)
                if str(getattr(row, "event_type", "") or "").strip() == "workspace_access_session_opened"
                and str(dict(getattr(row, "payload", {}) or {}).get("session_id") or getattr(row, "source_id", "") or "").strip() == access_session_id
            ),
            None,
        )
        channel_receipt_state = "not_requested"
        channel_receipt_detail = "No support verification link has been issued yet."
        if request_id:
            if delivery_opened is not None:
                channel_receipt_state = "received"
                channel_receipt_detail = "Recipient opened the support verification digest."
            elif delivery_failed is not None:
                failed_payload = dict(getattr(delivery_failed, "payload", {}) or {})
                channel_receipt_state = "failed"
                channel_receipt_detail = compact_text(
                    str(failed_payload.get("error") or "Support verification delivery failed.").strip(),
                    fallback="Support verification delivery failed.",
                    limit=180,
                )
            elif delivery_sent is not None or delivery_id:
                channel_receipt_state = "waiting"
                channel_receipt_detail = (
                    "Support verification email was sent and is waiting to be opened."
                    if delivery_channel == "email" and delivery_sent is not None
                    else "Support verification link was issued and is waiting to be opened."
                )
        install_receipt_state = "not_requested"
        install_receipt_detail = "No workspace install receipt has been requested yet."
        if request_id:
            if access_opened is not None:
                install_receipt_state = "opened"
                install_receipt_detail = "Recipient opened the workspace link attached to the verification request."
            elif access_session_id:
                install_receipt_state = "waiting"
                install_receipt_detail = "Workspace access link was issued and is waiting to be opened."
        confirmation_state = "not_requested"
        confirmation_detail = "No explicit confirmation has been requested yet."
        if request_id:
            if confirmed_at:
                confirmation_state = "confirmed"
                confirmation_detail = "Recipient explicitly confirmed the fix from the support verification link."
            else:
                confirmation_state = "waiting"
                confirmation_detail = "Waiting for the recipient to confirm the fix."
        state = "not_requested"
        summary = "No support verification request is active."
        if request_id and confirmed_at:
            state = "confirmed"
            summary = "Support verification is confirmed on the current channel."
        elif request_id and channel_receipt_state == "failed":
            state = "blocked"
            summary = "Support verification is blocked because the current channel delivery failed."
        elif request_id:
            state = "waiting"
            summary = "Support verification is waiting on receipt or explicit confirmation."
        elif not recipient_email:
            summary = "Support verification needs a recipient email before it can be requested."
        request_action_label = "Request confirmation" if recipient_email else "Recipient missing"
        if request_id and confirmation_state != "confirmed":
            request_action_label = "Reissue confirmation"
        recommended_action = (
            "Send a fresh support verification link and wait for channel receipt."
            if recipient_email and not request_id
            else "Set a memo recipient or connect Google before asking for support confirmation."
            if not recipient_email
            else "Open the current verification link or ask the recipient to confirm the fix."
            if state == "waiting"
            else "Use the support page to recover delivery before asking for confirmation again."
            if state == "blocked"
            else "Confirmation is already recorded."
        )
        confirm_action_href = (
            self.channel_action_href(
                principal_id=principal_id,
                object_kind="support_verification",
                object_ref=request_id,
                action="confirm",
                return_to="/app/channel-loop/memo",
                reason="Confirmed from support verification link.",
            )
            if request_id and confirmation_state != "confirmed"
            else ""
        )
        return {
            "state": state,
            "summary": summary,
            "recipient_email": recipient_email,
            "request_id": request_id,
            "requested_at": requested_at,
            "confirmed_at": confirmed_at,
            "delivery_channel": delivery_channel or ("email" if email_delivery_enabled() else "link_only"),
            "delivery_id": delivery_id,
            "delivery_url": delivery_url,
            "access_session_id": access_session_id,
            "access_url": access_url,
            "channel_receipt_state": channel_receipt_state,
            "channel_receipt_detail": channel_receipt_detail,
            "install_receipt_state": install_receipt_state,
            "install_receipt_detail": install_receipt_detail,
            "confirmation_state": confirmation_state,
            "confirmation_detail": confirmation_detail,
            "can_request": bool(recipient_email),
            "request_action_href": "/app/actions/support/fix-verification/request" if recipient_email else "",
            "request_action_method": "post",
            "request_action_label": request_action_label if recipient_email else "",
            "request_api_href": "/app/api/support/fix-verification/request" if recipient_email else "",
            "request_api_method": "post" if recipient_email else "",
            "recommended_action": recommended_action,
            "confirm_action_href": confirm_action_href,
            "display_name": str(contact.get("display_name") or "").strip(),
        }

    def request_support_fix_verification(
        self,
        *,
        principal_id: str,
        actor: str,
        base_url: str = "",
    ) -> dict[str, object]:
        contact = self._support_fix_verification_contact(principal_id=principal_id)
        recipient_email = str(contact.get("recipient_email") or "").strip().lower()
        if not recipient_email:
            raise ValueError("support_fix_verification_recipient_missing")
        delivery = self.issue_channel_digest_delivery(
            principal_id=principal_id,
            digest_key="memo",
            recipient_email=recipient_email,
            role=str(contact.get("role") or "principal").strip() or "principal",
            display_name=str(contact.get("display_name") or "").strip(),
            operator_id=str(contact.get("operator_id") or "").strip(),
            delivery_channel="email" if email_delivery_enabled() else "link_only",
            base_url=base_url,
        )
        if delivery is None:
            raise RuntimeError("support_fix_verification_delivery_not_available")
        request_id = f"support_verify_{uuid4().hex[:10]}"
        payload = {
            "request_id": request_id,
            "recipient_email": recipient_email,
            "delivery_channel": str(delivery.get("delivery_channel") or "").strip(),
            "delivery_id": str(delivery.get("delivery_id") or "").strip(),
            "delivery_url": str(delivery.get("delivery_url") or "").strip(),
            "access_session_id": str(delivery.get("access_session_id") or "").strip(),
            "access_url": str(delivery.get("access_url") or "").strip(),
            "requested_at": _now_iso(),
            "requested_by": str(actor or "").strip() or "support",
        }
        self._record_product_event(
            principal_id=principal_id,
            event_type="support_fix_verification_requested",
            payload=payload,
            source_id=request_id,
            dedupe_key=f"{principal_id}|{request_id}",
        )
        return payload

    def confirm_support_fix_verification(
        self,
        *,
        principal_id: str,
        request_id: str,
        actor: str,
    ) -> dict[str, object] | None:
        normalized_request_id = str(request_id or "").strip()
        if not normalized_request_id:
            return None
        payload = {
            "request_id": normalized_request_id,
            "confirmed_at": _now_iso(),
            "confirmed_by": str(actor or "").strip() or "support",
        }
        self._record_product_event(
            principal_id=principal_id,
            event_type="support_fix_verification_confirmed",
            payload=payload,
            source_id=normalized_request_id,
            dedupe_key=f"{principal_id}|{normalized_request_id}|confirmed",
        )
        return payload

    def _product_control_projection(self) -> dict[str, object]:
        pulse_path = _weekly_product_pulse_path()
        pulse_payload = _load_optional_json_dict(pulse_path)
        pulse_generated_at = str((pulse_payload or {}).get("generated_at") or "").strip()
        pulse_age_seconds = _artifact_age_seconds(pulse_generated_at)
        pulse_freshness_state = "missing" if pulse_payload is None else _freshness_state_from_age(pulse_age_seconds)

        supporting_signals = dict((pulse_payload or {}).get("supporting_signals") or {})
        configured_journey_source = str(supporting_signals.get("journey_gate_source") or "").strip()
        journey_path = _resolve_repo_path(configured_journey_source, default=_default_journey_gates_path())
        journey_payload = _load_optional_json_dict(journey_path)
        journey_generated_at = str((journey_payload or {}).get("generated_at") or "").strip()
        journey_summary = dict((journey_payload or {}).get("summary") or {})
        pulse_journey_health = dict((pulse_payload or {}).get("journey_gate_health") or {})
        journey_freshness_state = "missing"
        journey_freshness_detail = "Published journey gates are not available on this host."
        if journey_payload is not None:
            journey_freshness_state, journey_freshness_detail = _journey_freshness_summary(journey_payload)

        journey_state = (
            str(pulse_journey_health.get("state") or "").strip()
            or str(journey_summary.get("overall_state") or "").strip()
            or ("missing" if journey_payload is None else "watch")
        )
        journey_reason = (
            str(pulse_journey_health.get("reason") or "").strip()
            or str(journey_summary.get("recommended_action") or "").strip()
            or "Journey-gate posture is not available."
        )
        journey_highlights = _journey_highlights(journey_payload or {})
        governor_decision = next(
            (
                dict(value)
                for value in list((pulse_payload or {}).get("governor_decisions") or [])
                if isinstance(value, dict)
            ),
            {},
        )
        route_stewardship = dict(supporting_signals.get("provider_route_stewardship") or {})
        launch_readiness = str(supporting_signals.get("launch_readiness") or "").strip()
        public_guide_freshness = _public_guide_freshness_projection()
        summary = str((pulse_payload or {}).get("summary") or "").strip()
        if not summary:
            summary = str(journey_summary.get("recommended_action") or "").strip() or "Product-control pulse is not available."
        available = pulse_payload is not None or journey_payload is not None
        return {
            "available": available,
            "state": str(journey_state or "watch").strip().lower() or "watch",
            "summary": compact_text(summary, fallback="Product-control pulse is not available.", limit=220),
            "projection_note": "Mirrors weekly pulse, published journey gates, support fallout, and public-guide freshness; it does not replace design, Fleet, or Hub ownership.",
            "active_wave": str((pulse_payload or {}).get("active_wave") or "").strip(),
            "active_wave_status": str((pulse_payload or {}).get("active_wave_status") or "").strip(),
            "next_checkpoint_question": str((pulse_payload or {}).get("next_checkpoint_question") or "").strip(),
            "launch_readiness": launch_readiness,
            "provider_route_stewardship": {
                "default_status": str(route_stewardship.get("default_status") or "").strip(),
                "canary_status": str(route_stewardship.get("canary_status") or "").strip(),
                "review_due": str(route_stewardship.get("review_due") or "").strip(),
                "next_decision": str(route_stewardship.get("next_decision") or "").strip(),
            },
            "governor_decision": {
                "decision_id": str(governor_decision.get("decision_id") or "").strip(),
                "action": str(governor_decision.get("action") or "").strip(),
                "reason": compact_text(str(governor_decision.get("reason") or "").strip(), fallback="", limit=220),
            },
            "journey_gate_health": {
                "state": str(journey_state or "watch").strip().lower() or "watch",
                "reason": compact_text(journey_reason, fallback="Journey-gate posture is not available.", limit=220),
                "ready_count": int(journey_summary.get("ready_count") or 0),
                "warning_count": int(pulse_journey_health.get("warning_count") or journey_summary.get("warning_count") or 0),
                "blocked_count": int(pulse_journey_health.get("blocked_count") or journey_summary.get("blocked_count") or 0),
                "recommended_action": compact_text(
                    str(journey_summary.get("recommended_action") or journey_reason).strip(),
                    fallback="Journey-gate posture is not available.",
                    limit=220,
                ),
            },
            "journey_gate_freshness": {
                "state": journey_freshness_state,
                "detail": compact_text(journey_freshness_detail, fallback="Journey-gate freshness is not available.", limit=220),
                "generated_at": journey_generated_at,
            },
            "public_guide_freshness": public_guide_freshness,
            "pulse_freshness": {
                "state": pulse_freshness_state,
                "generated_at": pulse_generated_at,
                "age_seconds": pulse_age_seconds,
            },
            "journey_highlights": journey_highlights,
            "sources": {
                "pulse_path": str(pulse_path),
                "journey_gates_path": str(journey_path),
                "pulse_generated_at": pulse_generated_at,
                "journey_gates_generated_at": journey_generated_at,
                "public_guide_path": str(public_guide_freshness.get("path") or "").strip(),
                "public_guide_generated_at": str(public_guide_freshness.get("generated_at") or "").strip(),
            },
        }

    def _public_help_grounding_pack(self, *, product_control: dict[str, object] | None = None) -> dict[str, object]:
        trust_path = _design_source_path("public_trust_content", "PUBLIC_TRUST_CONTENT.yaml")
        release_path = _design_source_path("public_release_experience", "PUBLIC_RELEASE_EXPERIENCE.yaml")
        trust_payload = _load_yaml_dict(trust_path) or {}
        release_payload = _load_yaml_dict(release_path) or {}
        help_page = next(
            (
                dict(value)
                for value in list(trust_payload.get("trust_pages") or [])
                if isinstance(value, dict) and str(value.get("id") or "").strip() == "help"
            ),
            {},
        )
        launch_readiness = str(dict(product_control or {}).get("launch_readiness") or "").strip()
        summary_parts = [
            str(help_page.get("intro") or "").strip(),
            str(release_payload.get("release_notes_summary") or "").strip(),
        ]
        bullets = _design_string_list(help_page.get("summary_points"))[:3]
        update_posture = compact_text(str(release_payload.get("update_posture_summary") or "").strip(), fallback="", limit=180)
        if update_posture:
            bullets.append(update_posture)
        if launch_readiness:
            bullets.append(f"Current launch posture: {launch_readiness}")
        actions = _grounding_actions(help_page.get("actions"))
        install_help_label = str(release_payload.get("install_help_label") or "").strip()
        install_help_href = str(release_payload.get("install_help_href") or "").strip()
        if install_help_label and install_help_href and all(str(item.get("href") or "").strip() != install_help_href for item in actions):
            actions.append({"label": install_help_label, "href": install_help_href, "method": "get"})
        return {
            "id": "public_help",
            "title": str(help_page.get("heading") or "Get help without guessing").strip() or "Get help without guessing",
            "summary": compact_text(
                " ".join(part for part in summary_parts if part),
                fallback="Use the first-party help path before deeper technical material.",
                limit=220,
            ),
            "bullets": bullets[:5],
            "actions": actions[:4],
            "sources": [
                _grounding_source(
                    label="PUBLIC_TRUST_CONTENT.yaml",
                    path=trust_path,
                    as_of=str(help_page.get("updated_date") or trust_payload.get("version") or "").strip(),
                ),
                _grounding_source(
                    label="PUBLIC_RELEASE_EXPERIENCE.yaml",
                    path=release_path,
                    as_of=str(release_payload.get("version") or "").strip(),
                ),
            ],
        }

    def _support_assistant_grounding_pack(self, *, diagnostics: dict[str, object]) -> dict[str, object]:
        trust_path = _design_source_path("public_trust_content", "PUBLIC_TRUST_CONTENT.yaml")
        scorecard_path = _design_source_path("product_health_scorecard", "PRODUCT_HEALTH_SCORECARD.yaml")
        trust_payload = _load_yaml_dict(trust_path) or {}
        scorecard_payload = _load_yaml_dict(scorecard_path) or {}
        contact_page = next(
            (
                dict(value)
                for value in list(trust_payload.get("trust_pages") or [])
                if isinstance(value, dict) and str(value.get("id") or "").strip() == "contact"
            ),
            {},
        )
        support_scorecard = next(
            (
                dict(value)
                for value in list(scorecard_payload.get("scorecards") or [])
                if isinstance(value, dict) and str(value.get("id") or "").strip() == "support_and_feedback_closure"
            ),
            {},
        )
        support_verification = dict(diagnostics.get("support_verification") or {})
        product_control = dict(diagnostics.get("product_control") or {})
        readiness = dict(diagnostics.get("readiness") or {})
        providers = dict(diagnostics.get("providers") or {})
        queue_health = dict(diagnostics.get("queue_health") or {})
        metric_lines: list[str] = []
        for metric in list(support_scorecard.get("metrics") or [])[:2]:
            if not isinstance(metric, dict):
                continue
            name = str(metric.get("name") or "").strip()
            target = str(metric.get("target") or "").strip()
            if name and target:
                metric_lines.append(f"{name} target {target}.")
        bullets: list[str] = []
        recommended_action = compact_text(
            str(support_verification.get("recommended_action") or "").strip(),
            fallback="",
            limit=180,
        )
        if recommended_action:
            bullets.append(recommended_action)
        if str(support_verification.get("state") or "").strip() in {"waiting", "blocked"}:
            bullets.append(
                compact_text(
                    " ".join(
                        part
                        for part in (
                            str(support_verification.get("channel_receipt_detail") or "").strip(),
                            str(support_verification.get("install_receipt_detail") or "").strip(),
                            str(support_verification.get("confirmation_detail") or "").strip(),
                        )
                        if part
                    ),
                    fallback="Support verification is active.",
                    limit=180,
                )
            )
        if metric_lines:
            bullets.extend(metric_lines)
        provider_detail = compact_text(str(providers.get("risk_detail") or "").strip(), fallback="", limit=160)
        if provider_detail:
            bullets.append(f"Provider posture: {provider_detail}")
        elif int(queue_health.get("delivery_errors") or 0):
            bullets.append(f"Delivery backlog: {int(queue_health.get('delivery_errors') or 0)} active queue delivery errors.")
        readiness_detail = compact_text(str(readiness.get("detail") or "").strip(), fallback="", limit=160)
        if readiness_detail:
            bullets.append(f"Workspace readiness: {readiness_detail}")
        actions: list[dict[str, str]] = []
        request_api_href = str(support_verification.get("request_api_href") or "").strip()
        request_action_label = str(support_verification.get("request_action_label") or "Request confirmation").strip()
        request_api_method = str(support_verification.get("request_api_method") or "post").strip().lower() or "post"
        if request_api_href and request_action_label:
            actions.append({"label": request_action_label, "href": request_api_href, "method": request_api_method})
        actions.append({"label": "Open support diagnostics", "href": "/app/api/support", "method": "get"})
        access_url = str(support_verification.get("access_url") or "").strip()
        if access_url:
            actions.append({"label": "Open access link", "href": access_url, "method": "get"})
        for action in _grounding_actions(contact_page.get("actions")):
            if len(actions) >= 4:
                break
            if all(str(item.get("href") or "").strip() != str(action.get("href") or "").strip() for item in actions):
                actions.append(action)
        control_sources = dict(product_control.get("sources") or {})
        sources = [
            _grounding_source(
                label="PUBLIC_TRUST_CONTENT.yaml",
                path=trust_path,
                as_of=str(contact_page.get("updated_date") or trust_payload.get("version") or "").strip(),
            ),
            _grounding_source(
                label="PRODUCT_HEALTH_SCORECARD.yaml",
                path=scorecard_path,
                as_of=str(scorecard_payload.get("last_reviewed") or "").strip(),
            ),
        ]
        pulse_path = str(control_sources.get("pulse_path") or "").strip()
        if pulse_path:
            sources.append(
                _grounding_source(
                    label="WEEKLY_PRODUCT_PULSE.generated.json",
                    path=pulse_path,
                    as_of=str(control_sources.get("pulse_generated_at") or "").strip(),
                )
            )
        return {
            "id": "support_assistant",
            "title": "Support closure grounding",
            "summary": compact_text(
                " ".join(
                    part
                    for part in (
                        str(support_verification.get("summary") or "").strip(),
                        str(contact_page.get("intro") or "").strip(),
                        str(support_scorecard.get("question") or "").strip(),
                    )
                    if part
                ),
                fallback="Support guidance should stay grounded in mirrored trust and release signals.",
                limit=220,
            ),
            "bullets": bullets[:5],
            "actions": actions[:4],
            "sources": sources[:4],
        }

    def _operator_memo_grounding_pack(
        self,
        *,
        diagnostics: dict[str, object],
        lanes: list[dict[str, object]] | None = None,
        next_actions: list[dict[str, object]] | None = None,
    ) -> dict[str, object]:
        scorecard_path = _design_source_path("product_health_scorecard", "PRODUCT_HEALTH_SCORECARD.yaml")
        journey_gates_path = _design_source_path("golden_journey_release_gates", "GOLDEN_JOURNEY_RELEASE_GATES.yaml")
        scorecard_payload = _load_yaml_dict(scorecard_path) or {}
        journey_gates_payload = _load_yaml_dict(journey_gates_path) or {}
        cadence = dict(scorecard_payload.get("cadence") or {})
        product_control = dict(diagnostics.get("product_control") or {})
        route_stewardship = dict(product_control.get("provider_route_stewardship") or {})
        journey_health = dict(product_control.get("journey_gate_health") or {})
        public_guide_freshness = dict(product_control.get("public_guide_freshness") or {})
        support_fallout = dict(product_control.get("support_fallout") or {})
        lane_rows = [dict(value) for value in list(lanes or []) if isinstance(value, dict)]
        severity = {"critical": 2, "watch": 1, "clear": 0}
        active_lane = next(
            (
                row
                for row in sorted(
                    lane_rows,
                    key=lambda row: (
                        severity.get(str(row.get("state") or "").strip(), 0),
                        int(row.get("count") or 0),
                    ),
                    reverse=True,
                )
                if severity.get(str(row.get("state") or "").strip(), 0) > 0
            ),
            {},
        )
        bullets: list[str] = []
        review = str(cadence.get("review") or "").strip()
        owner = str(cadence.get("snapshot_owner") or "").strip()
        if review or owner:
            bullets.append(f"Review cadence: {review or 'weekly'} by {owner or 'product_governor'}.")
        recommended_action = compact_text(
            str(journey_health.get("recommended_action") or journey_health.get("reason") or "").strip(),
            fallback="",
            limit=180,
        )
        if recommended_action:
            bullets.append(f"Journey gates: {recommended_action}")
        launch_readiness = str(product_control.get("launch_readiness") or "").strip()
        if launch_readiness:
            bullets.append(f"Launch readiness: {launch_readiness}")
        route_detail = " · ".join(
            part
            for part in (
                f"default {str(route_stewardship.get('default_status') or '').strip()}" if str(route_stewardship.get("default_status") or "").strip() else "",
                f"canary {str(route_stewardship.get('canary_status') or '').strip()}" if str(route_stewardship.get("canary_status") or "").strip() else "",
                f"next {str(route_stewardship.get('next_decision') or '').strip()}" if str(route_stewardship.get("next_decision") or "").strip() else "",
                f"review due {str(route_stewardship.get('review_due') or '').strip()}" if str(route_stewardship.get("review_due") or "").strip() else "",
            )
            if part
        )
        if route_detail:
            bullets.append(f"Provider-route stewardship: {route_detail}")
        support_fallout_action = compact_text(
            str(support_fallout.get("recommended_action") or support_fallout.get("detail") or "").strip(),
            fallback="",
            limit=180,
        )
        if support_fallout_action and str(support_fallout.get("state") or "clear").strip().lower() != "clear":
            bullets.append(f"Support fallout: {support_fallout_action}")
        guide_detail = compact_text(str(public_guide_freshness.get("detail") or "").strip(), fallback="", limit=180)
        if guide_detail:
            bullets.append(f"Public guide: {guide_detail}")
        if active_lane:
            bullets.append(
                compact_text(
                    f"Current lane pressure: {str(active_lane.get('label') or '').strip()}. {str(active_lane.get('detail') or '').strip()}",
                    fallback="",
                    limit=180,
                )
            )
        elif next_actions:
            first_action = dict(next_actions[0] or {})
            bullets.append(
                compact_text(
                    f"Next operator move: {str(first_action.get('label') or '').strip()}. {str(first_action.get('detail') or '').strip()}",
                    fallback="",
                    limit=180,
                )
            )
        actions: list[dict[str, str]] = []
        for item in list(next_actions or [])[:3]:
            row = dict(item or {})
            label = str(row.get("action_label") or row.get("label") or "").strip()
            href = str(row.get("action_href") or row.get("href") or "").strip()
            if not label or not href:
                continue
            actions.append(
                {
                    "label": label,
                    "href": href,
                    "method": str(row.get("action_method") or "get").strip().lower() or "get",
                }
            )
        if not actions and active_lane and str(active_lane.get("href") or "").strip():
            actions.append(
                {
                    "label": f"Open {str(active_lane.get('label') or 'operator lane').strip()}",
                    "href": str(active_lane.get("href") or "").strip(),
                    "method": "get",
                }
            )
        control_sources = dict(product_control.get("sources") or {})
        sources = [
            _grounding_source(
                label="PRODUCT_HEALTH_SCORECARD.yaml",
                path=scorecard_path,
                as_of=str(scorecard_payload.get("last_reviewed") or "").strip(),
            ),
            _grounding_source(
                label="GOLDEN_JOURNEY_RELEASE_GATES.yaml",
                path=journey_gates_path,
                as_of=str(journey_gates_payload.get("last_reviewed") or "").strip(),
            ),
        ]
        pulse_path = str(control_sources.get("pulse_path") or "").strip()
        if pulse_path:
            sources.append(
                _grounding_source(
                    label="WEEKLY_PRODUCT_PULSE.generated.json",
                    path=pulse_path,
                    as_of=str(control_sources.get("pulse_generated_at") or "").strip(),
                )
            )
        generated_journey_path = str(control_sources.get("journey_gates_path") or "").strip()
        if generated_journey_path:
            sources.append(
                _grounding_source(
                    label="JOURNEY_GATES.generated.json",
                    path=generated_journey_path,
                    as_of=str(control_sources.get("journey_gates_generated_at") or "").strip(),
                )
            )
        public_guide_path = str(control_sources.get("public_guide_path") or "").strip()
        if public_guide_path:
            sources.append(
                _grounding_source(
                    label="manifest.generated.json",
                    path=public_guide_path,
                    as_of=str(control_sources.get("public_guide_generated_at") or "").strip(),
                )
            )
        return {
            "id": "operator_memo",
            "title": "Operator memo grounding",
            "summary": compact_text(
                " ".join(
                    part
                    for part in (
                        str(product_control.get("summary") or "").strip(),
                        str(scorecard_payload.get("purpose") or "").strip(),
                    )
                    if part
                ),
                fallback="Operator memos should stay grounded in weekly product control and journey gate evidence.",
                limit=220,
            ),
            "bullets": [item for item in bullets[:5] if str(item or "").strip()],
            "actions": actions[:4],
            "sources": sources[:5],
        }

    def _gmail_signal_labels(
        self,
        *,
        signal: google_oauth_service.GoogleWorkspaceSignal,
    ) -> set[str]:
        payload = dict(signal.payload or {})
        return {
            str(value or "").strip().upper()
            for value in list(payload.get("labels") or [])
            if str(value or "").strip()
        }

    def _curate_google_workspace_signals(
        self,
        *,
        signals: tuple[google_oauth_service.GoogleWorkspaceSignal, ...],
    ) -> tuple[
        tuple[google_oauth_service.GoogleWorkspaceSignal, ...],
        tuple[google_oauth_service.GoogleWorkspaceSignal, ...],
    ]:
        curated: list[google_oauth_service.GoogleWorkspaceSignal] = []
        suppressed: list[google_oauth_service.GoogleWorkspaceSignal] = []
        seen_gmail_threads: set[str] = set()
        for signal in signals:
            normalized_channel = str(signal.channel or "").strip().lower()
            normalized_signal = str(signal.signal_type or "").strip().lower()
            normalized_source = str(signal.source_ref or "").strip()
            normalized_payload = dict(signal.payload or {})
            normalized_thread_ref = str(
                normalized_payload.get("thread_id")
                or normalized_payload.get("gmail_thread_id")
                or normalized_payload.get("thread_ref")
                or ""
            ).strip()
            if normalized_channel == "gmail" and normalized_signal == "email_thread":
                if self._gmail_signal_labels(signal=signal) & _LOW_SIGNAL_GMAIL_LABELS:
                    suppressed.append(signal)
                    continue
                thread_key = normalized_thread_ref or normalized_source
                if thread_key and thread_key in seen_gmail_threads:
                    suppressed.append(signal)
                    continue
                if thread_key:
                    seen_gmail_threads.add(thread_key)
            curated.append(signal)
        return tuple(curated), tuple(suppressed)

    def _channel_action_secret(self) -> str:
        return resolve_signing_secret(self._container.settings, purpose="channel-actions")

    def _workspace_access_secret(self) -> str:
        return resolve_signing_secret(self._container.settings, purpose="workspace-access")

    def _workspace_access_database_url(self) -> str:
        return str(getattr(self._container.settings, "database_url", "") or "").strip()

    def _sign_workspace_access_launch_token(self, *, session_id: str, expires_at: str) -> str:
        normalized_session_id = str(session_id or "").strip()
        normalized_expires_at = str(expires_at or "").strip()
        if not normalized_session_id or not normalized_expires_at:
            return ""
        try:
            expires_dt = datetime.fromisoformat(normalized_expires_at)
        except ValueError:
            return ""
        if expires_dt.tzinfo is None:
            expires_dt = expires_dt.replace(tzinfo=timezone.utc)
        launch_ttl_minutes_raw = str(os.getenv("PROPERTYQUARRY_WORKSPACE_ACCESS_LAUNCH_TTL_MINUTES") or "60").strip()
        try:
            launch_ttl_minutes = max(5, min(24 * 60, int(float(launch_ttl_minutes_raw))))
        except Exception:
            launch_ttl_minutes = 60
        launch_expires_dt = min(expires_dt, datetime.now(timezone.utc) + timedelta(minutes=launch_ttl_minutes))
        return _sign_channel_payload(
            secret=self._workspace_access_secret(),
            payload={
                "k": "wa",
                "s": normalized_session_id,
                "x": int(launch_expires_dt.timestamp()),
            },
        )

    def _workspace_access_session_token_from_record(self, session: dict[str, object]) -> str:
        session_id = str(session.get("session_id") or "").strip()
        principal_id = str(session.get("principal_id") or "").strip()
        expires_at = str(session.get("expires_at") or "").strip()
        if not session_id or not principal_id or not expires_at:
            return ""
        token_payload = {
            "token_kind": "workspace_access_session",
            "session_id": session_id,
            "principal_id": principal_id,
            "email": str(session.get("email") or "").strip().lower(),
            "role": str(session.get("role") or "principal").strip().lower() or "principal",
            "display_name": str(session.get("display_name") or "").strip(),
            "operator_id": str(session.get("operator_id") or "").strip(),
            "source_kind": str(session.get("source_kind") or "workspace_access").strip() or "workspace_access",
            "expires_at": expires_at,
        }
        return _sign_channel_payload(secret=self._workspace_access_secret(), payload=token_payload)

    def _resolve_workspace_access_session_principal(self, *, session_id: str, limit: int = 5000) -> str:
        normalized_session_id = str(session_id or "").strip()
        if not normalized_session_id:
            return ""
        stored = get_workspace_access_session_record_by_session_id(
            session_id=normalized_session_id,
            database_url=self._workspace_access_database_url(),
        )
        if stored:
            return str(stored.get("principal_id") or "").strip()
        for row in self._container.channel_runtime.list_recent_observations(limit=max(int(limit or 5000), 100)):
            if str(row.event_type or "").strip().lower() != "workspace_access_session_issued":
                continue
            payload = dict(row.payload or {})
            current_session_id = str(payload.get("session_id") or row.source_id or "").strip()
            if current_session_id != normalized_session_id:
                continue
            return str(row.principal_id or payload.get("principal_id") or "").strip()
        return ""

    def _signal_ingest_secret(self) -> str:
        return resolve_signing_secret(self._container.settings, purpose="signal-ingest")

    def _onedrive_document_secret(self) -> str:
        return resolve_signing_secret(self._container.settings, purpose="onedrive-documents")

    def _onedrive_attachment_root(self) -> Path:
        raw = str(os.getenv("EA_ONEDRIVE_ATTACHMENT_ROOT") or "/data/onedrive_attachments").strip()
        return Path(raw).expanduser()

    def _onedrive_scanned_document_roots(self) -> tuple[Path, ...]:
        configured: list[Path] = []
        for raw in (
            str(os.getenv("EA_ONEDRIVE_SCANNED_DOCUMENT_ROOT") or "").strip(),
            "/mnt/onedrive/Documents/Scanned Documents",
            "/mnt/onedrive/Scanned Documents",
        ):
            if not raw:
                continue
            path = Path(raw).expanduser()
            if path not in configured:
                configured.append(path)
        attachment_root = self._onedrive_attachment_root()
        if attachment_root not in configured:
            configured.append(attachment_root)
        return tuple(configured)

    def _normalize_onedrive_document_text(self, value: str) -> str:
        normalized = (
            str(value or "")
            .strip()
            .lower()
            .replace("ä", "ae")
            .replace("ö", "oe")
            .replace("ü", "ue")
            .replace("ß", "ss")
        )
        return re.sub(r"[^a-z0-9]+", " ", normalized).strip()

    def _onedrive_document_query_tokens(self, query: str) -> tuple[str, ...]:
        tokens: list[str] = []
        for token in self._normalize_onedrive_document_text(query).split():
            if len(token) < 2 or token in _ONEDRIVE_DOCUMENT_QUERY_STOPWORDS:
                continue
            if token not in tokens:
                tokens.append(token)
        return tuple(tokens)

    def _search_recent_onedrive_document_candidates(
        self,
        *,
        principal_id: str,
        answerly_source_ids: tuple[str, ...],
        query: str,
        limit: int,
    ) -> list[dict[str, object]]:
        tokens = self._onedrive_document_query_tokens(query)
        wanted_ids = {str(value or "").strip() for value in answerly_source_ids if str(value or "").strip()}
        candidates: list[dict[str, object]] = []
        seen_keys: set[str] = set()
        for row in self._container.channel_runtime.list_recent_observations(limit=4000, principal_id=principal_id):
            payload = dict(row.payload or {})
            path = str(payload.get("path") or "").strip()
            download_url = str(payload.get("download_url") or "").strip()
            filename = str(payload.get("filename") or "").strip()
            answerly_id = str(payload.get("answerly_data_item_id") or "").strip()
            if not filename and path:
                filename = Path(path).name
            if not filename:
                continue
            if not filename.lower().endswith(".pdf"):
                continue
            blob = self._normalize_onedrive_document_text(
                " ".join(
                    [
                        filename,
                        str(payload.get("relpath") or ""),
                        path,
                        str(payload.get("source_ref") or ""),
                        str(payload.get("external_id") or ""),
                    ]
                )
            )
            score = 0.0
            if answerly_id and answerly_id in wanted_ids:
                score += 100.0
            for token in tokens:
                if token in self._normalize_onedrive_document_text(filename):
                    score += 8.0
                elif token in blob:
                    score += 3.0
            if tokens and score <= 0 and not (answerly_id and answerly_id in wanted_ids):
                continue
            key = path or download_url or filename
            if not key or key in seen_keys:
                continue
            seen_keys.add(key)
            candidates.append(
                {
                    "source": "observation",
                    "score": score,
                    "filename": filename,
                    "path": path,
                    "download_url": download_url,
                    "answerly_data_item_id": answerly_id,
                    "created_at": str(row.created_at or ""),
                }
            )
        candidates.sort(
            key=lambda item: (
                -float(item.get("score") or 0.0),
                str(item.get("created_at") or ""),
                str(item.get("filename") or ""),
            )
        )
        return candidates[: max(1, int(limit or 10))]

    def _search_scanned_onedrive_filesystem_candidates(
        self,
        *,
        query: str,
        limit: int,
    ) -> list[dict[str, object]]:
        tokens = self._onedrive_document_query_tokens(query)
        if not tokens:
            return []
        candidates: list[dict[str, object]] = []
        seen_paths: set[str] = set()
        for root in self._onedrive_scanned_document_roots():
            if not root.is_dir():
                continue
            try:
                iterator = root.rglob("*.pdf")
            except Exception:
                continue
            for path in iterator:
                normalized_path = str(path.resolve())
                if normalized_path in seen_paths:
                    continue
                blob = self._normalize_onedrive_document_text(normalized_path)
                score = 0.0
                for token in tokens:
                    if token in self._normalize_onedrive_document_text(path.name):
                        score += 8.0
                    elif token in blob:
                        score += 3.0
                if score <= 0:
                    continue
                seen_paths.add(normalized_path)
                candidates.append(
                    {
                        "source": "filesystem",
                        "score": score,
                        "filename": path.name,
                        "path": normalized_path,
                        "download_url": "",
                        "answerly_data_item_id": "",
                        "created_at": "",
                    }
                )
                if len(candidates) >= max(int(limit or 10) * 10, 100):
                    break
            if len(candidates) >= max(int(limit or 10) * 10, 100):
                break
        candidates.sort(key=lambda item: (-float(item.get("score") or 0.0), str(item.get("filename") or "")))
        return candidates[: max(1, int(limit or 10))]

    def deliver_onedrive_document_search_to_telegram(
        self,
        *,
        principal_id: str,
        actor: str,
        query: str,
        answerly_source_ids: tuple[str, ...] = (),
        limit: int = 10,
    ) -> dict[str, object]:
        normalized_query = str(query or "").strip()
        if not normalized_query:
            raise RuntimeError("onedrive_document_query_missing")
        binding = resolve_primary_telegram_binding(self._container.tool_runtime, principal_id=principal_id)
        if binding is None:
            raise RuntimeError("telegram_binding_not_found")
        candidates = self._search_recent_onedrive_document_candidates(
            principal_id=principal_id,
            answerly_source_ids=answerly_source_ids,
            query=normalized_query,
            limit=limit,
        )
        if not candidates:
            candidates = self._search_scanned_onedrive_filesystem_candidates(query=normalized_query, limit=limit)
        if not candidates:
            raise RuntimeError("onedrive_document_search_match_not_found")
        selected = dict(candidates[0])
        document_ref = str(selected.get("path") or selected.get("download_url") or "").strip()
        if not document_ref:
            raise RuntimeError("onedrive_document_ref_missing")
        receipt = send_telegram_document_for_principal(
            self._container.tool_runtime,
            principal_id=principal_id,
            document_ref=document_ref,
            caption=str(selected.get("filename") or "").strip(),
        )
        self._record_product_event(
            principal_id=principal_id,
            event_type="onedrive_document_telegram_sent",
            payload={
                "query": normalized_query,
                "filename": str(selected.get("filename") or ""),
                "path": str(selected.get("path") or ""),
                "download_url": str(selected.get("download_url") or ""),
                "answerly_data_item_id": str(selected.get("answerly_data_item_id") or ""),
                "telegram_chat_ref": str(receipt.chat_id or ""),
                "telegram_message_ids": [str(item or "") for item in receipt.message_ids],
                "matched_total": len(candidates),
            },
            source_id=str(selected.get("answerly_data_item_id") or ""),
            external_id=str(selected.get("path") or selected.get("download_url") or ""),
            dedupe_key="",
        )
        return {
            "query": normalized_query,
            "matched_total": len(candidates),
            "filename": str(selected.get("filename") or ""),
            "document_path": str(selected.get("path") or ""),
            "document_download_url": str(selected.get("download_url") or ""),
            "answerly_data_item_id": str(selected.get("answerly_data_item_id") or ""),
            "telegram_delivery_status": "sent",
            "telegram_delivery_error": "",
            "telegram_message_ids": [str(item or "") for item in receipt.message_ids],
            "telegram_chat_ref": str(receipt.chat_id or ""),
        }

    def _onedrive_document_public_base_url(self) -> str:
        return str(os.getenv("EA_PUBLIC_APP_BASE_URL") or "https://myexternalbrain.com").strip().rstrip("/")

    def _onedrive_answerly_import_enabled(self) -> bool:
        return str(os.getenv("EA_ANSWERLY_AUTO_IMPORT_GMAIL_PDFS") or "1").strip().lower() not in {"0", "false", "no", "off"}

    def _onedrive_answerly_training_config(self) -> dict[str, str] | None:
        api_key = str(os.getenv("EA_ANSWERLY_ONEDRIVE_API_KEY") or "").strip()
        training_id = str(os.getenv("EA_ANSWERLY_ONEDRIVE_TRAINING_ID") or "").strip()
        if not api_key:
            return None
        return {
            "api_key": api_key,
            "training_id": training_id,
            "workspace_id": str(os.getenv("EA_ANSWERLY_ONEDRIVE_WORKSPACE_ID") or "").strip(),
            "base_url": str(os.getenv("EA_ANSWERLY_BASE_URL") or "https://ai.api.answerly.io").strip().rstrip("/"),
            "label": str(os.getenv("EA_ANSWERLY_ONEDRIVE_LABEL") or "OneDrive documents").strip() or "OneDrive documents",
        }

    def _answerly_backend_pending_reason(self, error_text: str) -> str:
        normalized = str(error_text or "").strip().lower()
        if not normalized:
            return ""
        if "task_not_found" in normalized:
            return "answerly_training_backend_unavailable"
        if "no available server" in normalized:
            return "answerly_ingest_backend_unavailable"
        if "503" in normalized and "server" in normalized:
            return "answerly_ingest_backend_unavailable"
        return ""

    def _encode_onedrive_document_token(
        self,
        *,
        relpath: str,
        filename: str,
        mime_type: str,
    ) -> str:
        payload = {
            "kind": "onedrive_document",
            "relpath": str(relpath or "").strip(),
            "filename": str(filename or "").strip(),
            "mime_type": str(mime_type or "").strip() or "application/octet-stream",
        }
        body = base64.urlsafe_b64encode(json.dumps(payload, separators=(",", ":"), sort_keys=True).encode("utf-8")).decode("ascii").rstrip("=")
        signature = hmac.new(
            self._onedrive_document_secret().encode("utf-8"),
            body.encode("utf-8"),
            hashlib.sha256,
        ).hexdigest()
        return f"{body}.{signature}"

    def onedrive_document_download_url(
        self,
        *,
        relpath: str,
        filename: str,
        mime_type: str,
    ) -> str:
        token = self._encode_onedrive_document_token(relpath=relpath, filename=filename, mime_type=mime_type)
        return f"{self._onedrive_document_public_base_url()}/documents/onedrive-mail/{urllib.parse.quote(token, safe='')}"

    def _sanitize_attachment_filename(self, value: str) -> str:
        normalized = str(value or "").strip() or "attachment.pdf"
        lowered = _ATTACHMENT_FILENAME_SANITIZE_RE.sub("-", normalized).strip(".-") or "attachment.pdf"
        if not lowered.lower().endswith(".pdf"):
            lowered = f"{lowered}.pdf"
        return lowered[:180]

    def _gmail_pdf_attachment_relpath(
        self,
        *,
        account_email: str,
        message_id: str,
        attachment: google_oauth_service.GoogleWorkspaceAttachment,
    ) -> str:
        normalized_account = re.sub(r"[^a-z0-9._-]+", "-", str(account_email or "unattributed").strip().lower()) or "unattributed"
        message_slug = re.sub(r"[^a-zA-Z0-9._-]+", "-", str(message_id or "").strip()) or uuid4().hex
        filename = self._sanitize_attachment_filename(attachment.filename)
        today = datetime.now(timezone.utc)
        return str(
            Path("gmail_pdf_imports")
            / normalized_account
            / today.strftime("%Y")
            / today.strftime("%m")
            / f"{message_slug}-{filename}"
        )

    def _save_gmail_pdf_attachment(
        self,
        *,
        account_email: str,
        message_id: str,
        attachment: google_oauth_service.GoogleWorkspaceAttachment,
    ) -> dict[str, object] | None:
        content_bytes = bytes(attachment.content_bytes or b"")
        if not content_bytes:
            return None
        relpath = self._gmail_pdf_attachment_relpath(
            account_email=account_email,
            message_id=message_id,
            attachment=attachment,
        )
        root = self._onedrive_attachment_root().resolve()
        path = (root / relpath).resolve()
        if path != root and root not in path.parents:
            raise RuntimeError("onedrive_attachment_path_escape")
        path.parent.mkdir(parents=True, exist_ok=True)
        if not path.exists():
            path.write_bytes(content_bytes)
        return {
            "relpath": relpath,
            "path": str(path),
            "filename": path.name,
            "mime_type": str(attachment.mime_type or "application/pdf").strip() or "application/pdf",
            "download_url": self.onedrive_document_download_url(
                relpath=relpath,
                filename=path.name,
                mime_type=str(attachment.mime_type or "application/pdf").strip() or "application/pdf",
            ),
            "size_bytes": len(content_bytes),
        }

    def _answerly_create_onedrive_data_item(
        self,
        *,
        config: dict[str, str],
        source_url: str,
    ) -> dict[str, object]:
        request = urllib.request.Request(
            f"{str(config.get('base_url') or '').rstrip('/')}/dataitem/create",
            data=json.dumps(
                {
                    "APIKey": str(config.get("api_key") or "").strip(),
                    "dataItem": {
                        "trainingId": str(config.get("training_id") or "").strip(),
                        "type": "PDF",
                        "source": source_url,
                        "content": "",
                        "properties": {},
                    },
                }
            ).encode("utf-8"),
            headers={"Content-Type": "application/json"},
            method="POST",
        )
        with urllib.request.urlopen(request, timeout=60) as response:
            payload = json.loads(response.read().decode("utf-8"))
        if not bool(payload.get("status")):
            raise RuntimeError(str(payload.get("data") or "answerly_dataitem_create_failed").strip() or "answerly_dataitem_create_failed")
        return dict(payload.get("data") or {})

    def _auto_import_gmail_pdf_attachments(
        self,
        *,
        principal_id: str,
        channel: str,
        signal_type: str,
        external_id: str,
        source_ref: str,
        payload: dict[str, object],
        attachments: tuple[google_oauth_service.GoogleWorkspaceAttachment, ...],
    ) -> list[dict[str, object]]:
        if str(channel or "").strip().lower() != "gmail" or str(signal_type or "").strip().lower() != "email_thread":
            return []
        if not attachments:
            return []
        normalized_external_id = str(external_id or source_ref or "").strip()
        account_email = str(payload.get("account_email") or "").strip().lower()
        message_id = str(payload.get("message_id") or "").strip()
        results: list[dict[str, object]] = []
        training_config = self._onedrive_answerly_training_config() if self._onedrive_answerly_import_enabled() else None
        for attachment in attachments:
            if str(attachment.mime_type or "").strip().lower() != "application/pdf":
                continue
            attachment_key = str(attachment.attachment_id or attachment.part_id or attachment.filename).strip()
            dedupe_key = f"{principal_id}|gmail-pdf|{normalized_external_id}|{attachment_key}"
            if self._container.channel_runtime.find_observation_by_dedupe(dedupe_key, principal_id=principal_id) is not None:
                continue
            saved = self._save_gmail_pdf_attachment(
                account_email=account_email,
                message_id=message_id or normalized_external_id,
                attachment=attachment,
            )
            if saved is None:
                self._record_product_event(
                    principal_id=principal_id,
                    event_type="gmail_pdf_attachment_skipped",
                    payload={
                        "source_ref": source_ref,
                        "external_id": normalized_external_id,
                        "account_email": account_email,
                        "attachment_id": attachment_key,
                        "filename": attachment.filename,
                        "reason": "attachment_bytes_unavailable",
                    },
                    source_id=normalized_external_id,
                    dedupe_key=f"{dedupe_key}|skipped",
                )
                continue
            saved_payload = {
                "source_ref": source_ref,
                "external_id": normalized_external_id,
                "account_email": account_email,
                "message_id": message_id,
                "attachment_id": attachment_key,
                "filename": str(saved["filename"] or ""),
                "mime_type": str(saved["mime_type"] or ""),
                "path": str(saved["path"] or ""),
                "relpath": str(saved["relpath"] or ""),
                "download_url": str(saved["download_url"] or ""),
                "size_bytes": int(saved["size_bytes"] or 0),
            }
            self._record_product_event(
                principal_id=principal_id,
                event_type="gmail_pdf_attachment_saved_to_onedrive",
                payload=saved_payload,
                source_id=normalized_external_id,
                dedupe_key=dedupe_key,
            )
            enrolled = False
            pending_answerly_import = False
            answerly_data_item_id = ""
            answerly_error = ""
            if training_config is not None:
                if not str(training_config.get("training_id") or "").strip():
                    pending_answerly_import = True
                    answerly_error = "answerly_training_id_missing"
                    self._record_product_event(
                        principal_id=principal_id,
                        event_type="answerly_onedrive_pdf_import_pending",
                        payload={
                            **saved_payload,
                            "training_id": "",
                            "workspace_id": str(training_config.get("workspace_id") or ""),
                            "answerly_scope": "onedrive",
                            "error": answerly_error,
                        },
                        source_id=normalized_external_id,
                        dedupe_key=f"{dedupe_key}|answerly-onedrive-pending",
                    )
                else:
                    try:
                        answerly_data = self._answerly_create_onedrive_data_item(
                            config=training_config,
                            source_url=str(saved["download_url"] or ""),
                        )
                        enrolled = True
                        answerly_data_item_id = str(answerly_data.get("id") or "").strip()
                        self._record_product_event(
                            principal_id=principal_id,
                            event_type="answerly_onedrive_pdf_enrolled",
                            payload={
                                **saved_payload,
                                "training_id": str(training_config.get("training_id") or ""),
                                "workspace_id": str(training_config.get("workspace_id") or ""),
                                "answerly_scope": "onedrive",
                                "answerly_data_item_id": answerly_data_item_id,
                            },
                            source_id=normalized_external_id,
                            dedupe_key=f"{dedupe_key}|answerly-onedrive",
                        )
                    except Exception as exc:
                        answerly_error = compact_text(str(exc or ""), fallback="answerly_onedrive_pdf_enroll_failed", limit=220)
                        pending_reason = self._answerly_backend_pending_reason(answerly_error)
                        pending_answerly_import = bool(pending_reason)
                        self._record_product_event(
                            principal_id=principal_id,
                            event_type="answerly_onedrive_pdf_import_pending" if pending_answerly_import else "answerly_onedrive_pdf_enroll_failed",
                            payload={
                                **saved_payload,
                                "training_id": str(training_config.get("training_id") or ""),
                                "workspace_id": str(training_config.get("workspace_id") or ""),
                                "answerly_scope": "onedrive",
                                "error": pending_reason or answerly_error,
                            },
                            source_id=normalized_external_id,
                            dedupe_key=(
                                f"{dedupe_key}|answerly-onedrive-pending"
                                if pending_answerly_import
                                else f"{dedupe_key}|answerly-onedrive-failed"
                            ),
                        )
            results.append(
                {
                    **saved_payload,
                    "enrolled": enrolled,
                    "pending_answerly_import": pending_answerly_import,
                    "answerly_data_item_id": answerly_data_item_id,
                    "answerly_error": answerly_error,
                }
            )
        return results

    def _record_product_event(
        self,
        *,
        principal_id: str,
        event_type: str,
        payload: dict[str, object] | None = None,
        source_id: str = "",
        dedupe_key: str = "",
    ) -> None:
        safe_payload = _json_safe_product_payload(dict(payload or {}))
        if not isinstance(safe_payload, dict):
            safe_payload = {"value": safe_payload}
        event = self._container.channel_runtime.ingest_observation(
            principal_id=principal_id,
            channel="product",
            event_type=event_type,
            payload=safe_payload,
            source_id=source_id,
            dedupe_key=dedupe_key,
        )
        normalized_type = str(event_type or "").strip().lower()
        if normalized_type and not normalized_type.startswith("webhook_"):
            self._queue_webhook_deliveries(
                principal_id=principal_id,
                matched_event_type=normalized_type,
                payload=safe_payload,
                source_id=str(source_id or event.observation_id or "").strip(),
            )

    def _property_search_notification_budget_state(
        self,
        *,
        principal_id: str,
        preferences: dict[str, object],
    ) -> dict[str, object]:
        limit, period = _property_search_notification_budget(preferences)
        now = datetime.now(timezone.utc)
        window_start = now - (timedelta(days=7) if period == "week" else timedelta(days=1))
        sent_in_window = 0
        for row in self.list_office_events(
            principal_id=principal_id,
            event_type="property_scout_hit_telegram_sent",
            channel="product",
            limit=1000,
        ):
            raw_created_at = str(row.get("created_at") or "").strip()
            try:
                created_at = datetime.fromisoformat(raw_created_at.replace("Z", "+00:00"))
            except Exception:
                continue
            if created_at.tzinfo is None:
                created_at = created_at.replace(tzinfo=timezone.utc)
            if created_at >= window_start:
                sent_in_window += 1
        remaining = max(0, limit - sent_in_window)
        return {
            "limit": limit,
            "period": period,
            "window_start": window_start.isoformat(),
            "sent_in_window": sent_in_window,
            "remaining": remaining,
        }

    def _property_public_preview_cache_index(self, *, limit: int = 4000) -> dict[str, dict[str, object]]:
        by_url: dict[str, dict[str, object]] = {}
        rows = self._container.channel_runtime.list_recent_observations(
            limit=max(100, min(int(limit or 4000), 8000)),
            principal_id=_PROPERTY_PUBLIC_CACHE_PRINCIPAL_ID,
        )
        for row in rows:
            if str(getattr(row, "channel", "") or "").strip() != "product":
                continue
            if str(getattr(row, "event_type", "") or "").strip() != _PROPERTY_PUBLIC_PREVIEW_CACHE_EVENT_TYPE:
                continue
            payload = dict(getattr(row, "payload", None) or {})
            preview = dict(payload.get("preview") or {}) if isinstance(payload.get("preview"), dict) else {}
            property_url = urllib.parse.urldefrag(
                str(preview.get("property_url") or payload.get("property_url") or "").strip()
            )[0]
            if not property_url or property_url in by_url:
                continue
            preview.setdefault("property_url", property_url)
            preview.setdefault("cached_at", str(getattr(row, "created_at", "") or "").strip())
            preview.setdefault("cache_key", str(payload.get("cache_key") or "").strip())
            by_url[property_url] = preview
        return by_url

    def _property_public_preview_cache_lookup(
        self,
        *,
        cache_index: dict[str, dict[str, object]],
        property_url: str,
    ) -> dict[str, object] | None:
        normalized_url = urllib.parse.urldefrag(str(property_url or "").strip())[0]
        if not normalized_url:
            return None
        cached = dict(cache_index.get(normalized_url) or {})
        if not cached:
            return None
        cached["property_url"] = normalized_url
        return cached

    def _property_public_preview_cache_store(
        self,
        *,
        cache_index: dict[str, dict[str, object]],
        property_url: str,
        preview: dict[str, object] | None,
    ) -> dict[str, object]:
        normalized_url = urllib.parse.urldefrag(str(property_url or "").strip())[0]
        normalized_preview = _property_public_preview_cache_payload(
            {
                **dict(preview or {}),
                "property_url": normalized_url,
            }
        )
        if not normalized_url or not normalized_preview:
            return {}
        normalized_preview["property_url"] = normalized_url
        cache_key = _property_public_preview_cache_key(
            property_url=normalized_url,
            listing_id=str(normalized_preview.get("listing_id") or "").strip(),
            property_facts=dict(normalized_preview.get("property_facts_json") or {}),
        )
        existing = dict(cache_index.get(normalized_url) or {})
        if existing and json.dumps(existing, sort_keys=True, default=str) == json.dumps(normalized_preview, sort_keys=True, default=str):
            return existing
        self._container.channel_runtime.ingest_observation(
            principal_id=_PROPERTY_PUBLIC_CACHE_PRINCIPAL_ID,
            channel="product",
            event_type=_PROPERTY_PUBLIC_PREVIEW_CACHE_EVENT_TYPE,
            payload={
                "cache_key": cache_key,
                "property_url": normalized_url,
                "preview": normalized_preview,
            },
            source_id=f"property-public-preview:{cache_key}",
            dedupe_key=f"property-public-preview:{cache_key}:{hashlib.sha256(json.dumps(normalized_preview, sort_keys=True, default=str).encode('utf-8', errors='ignore')).hexdigest()}",
        )
        normalized_preview["cache_key"] = cache_key
        cache_index[normalized_url] = normalized_preview
        return normalized_preview

    def _warm_property_public_preview_cache_for_sources(
        self,
        *,
        specs: list[dict[str, object]],
        prefetched_source_results: dict[tuple[str, str], dict[str, object]],
        cache_index: dict[str, dict[str, object]],
        plan_key: str = "free",
    ) -> dict[str, object]:
        warm_limit = _property_search_provider_worker_warm_limit()
        worker_cap = _property_search_provider_worker_concurrency_for_plan(plan_key)
        if warm_limit <= 0 or worker_cap <= 0 or not specs or not prefetched_source_results:
            return {"enabled": False, "warmed_total": 0, "sources_touched": 0}

        cache_lock = threading.Lock()
        lane_semaphores = {
            "provider": threading.Semaphore(worker_cap),
            "browser": threading.Semaphore(max(1, min(_property_search_browser_provider_concurrency(), worker_cap))),
            "official": threading.Semaphore(max(1, min(_property_search_official_evidence_concurrency(), worker_cap))),
        }
        tasks: list[tuple[dict[str, object], str]] = []
        for source_spec in specs:
            source_url = urllib.parse.urldefrag(str(source_spec.get("url") or "").strip())[0]
            platform = str(source_spec.get("platform") or "").strip().lower()
            prefetched_result = dict(prefetched_source_results.get((platform, source_url)) or {})
            listing_urls = [
                urllib.parse.urldefrag(str(url or "").strip())[0]
                for url in list(prefetched_result.get("listing_urls") or [])[:warm_limit]
                if str(url or "").strip()
            ]
            for property_url in listing_urls:
                tasks.append((dict(source_spec), property_url))
        if not tasks:
            return {"enabled": False, "warmed_total": 0, "sources_touched": 0}
        tasks = [
            (spec, property_url)
            for spec, property_url in (
                (grouped_spec, grouped_spec.get("__property_url__", ""))
                for grouped_spec in _property_search_interleave_by_provider_group(
                    [
                        {**dict(source_spec), "__property_url__": property_url}
                        for source_spec, property_url in tasks
                    ]
                )
            )
            if property_url
        ]

        touched_sources: set[str] = set()
        warmed_total = 0

        def _task(source_spec: dict[str, object], property_url: str) -> bool:
            lane = _property_search_source_fetch_lane(source_spec)
            sem = lane_semaphores.get(lane, lane_semaphores["provider"])
            with sem:
                with cache_lock:
                    if self._property_public_preview_cache_lookup(cache_index=cache_index, property_url=property_url):
                        return False
                try:
                    preview = _property_scout_page_preview_with_timeout(property_url, prefer_fast=True)
                except Exception:
                    return False
                with cache_lock:
                    stored = self._property_public_preview_cache_store(
                        cache_index=cache_index,
                        property_url=property_url,
                        preview=preview,
                    )
                if stored:
                    touched_sources.add(str(source_spec.get("label") or source_spec.get("platform") or "").strip())
                    return True
                return False

        with concurrent.futures.ThreadPoolExecutor(max_workers=max(1, min(worker_cap, len(tasks))), thread_name_prefix="property-source-worker") as executor:
            futures = [executor.submit(_task, source_spec, property_url) for source_spec, property_url in tasks]
            for future in concurrent.futures.as_completed(futures):
                try:
                    if future.result():
                        warmed_total += 1
                except Exception:
                    continue

        return {
            "enabled": True,
            "warmed_total": warmed_total,
            "sources_touched": len(touched_sources),
            "worker_concurrency": worker_cap,
            "warm_limit": warm_limit,
            "floorplan_worker_concurrency": _property_search_floorplan_worker_concurrency_for_plan(plan_key),
            "floorplan_recovery_limit": _property_search_floorplan_worker_limit(),
        }

    def _prefetch_property_public_previews_for_listing_urls(
        self,
        *,
        listing_urls: list[str],
        cache_index: dict[str, dict[str, object]],
        worker_cap: int,
    ) -> dict[str, object]:
        normalized_urls: list[str] = []
        for property_url in listing_urls:
            normalized = urllib.parse.urldefrag(str(property_url or "").strip())[0]
            if normalized and normalized not in normalized_urls:
                normalized_urls.append(normalized)
        if not normalized_urls:
            return {
                "previews": {},
                "errors": {},
                "cache_hit_total": 0,
                "cache_refresh_total": 0,
                "worker_concurrency": 0,
            }

        cache_lock = threading.Lock()
        preview_rows: dict[str, dict[str, object]] = {}
        preview_errors: dict[str, str] = {}
        cache_hit_total = 0
        cache_refresh_total = 0

        def _task(property_url: str) -> tuple[str, dict[str, object] | None, str]:
            with cache_lock:
                cached_preview = self._property_public_preview_cache_lookup(
                    cache_index=cache_index,
                    property_url=property_url,
                )
            if cached_preview:
                return property_url, dict(cached_preview), "hit"
            preview = _property_scout_page_preview_with_timeout(property_url, prefer_fast=True)
            with cache_lock:
                self._property_public_preview_cache_store(
                    cache_index=cache_index,
                    property_url=property_url,
                    preview=preview,
                )
            return property_url, dict(preview or {}), "refresh"

        max_workers = max(1, min(int(worker_cap or 1), len(normalized_urls)))
        with concurrent.futures.ThreadPoolExecutor(
            max_workers=max_workers,
            thread_name_prefix="property-preview-prefetch",
        ) as executor:
            futures = {
                executor.submit(_task, property_url): property_url
                for property_url in normalized_urls
            }
            for future in concurrent.futures.as_completed(futures):
                property_url = futures[future]
                try:
                    resolved_url, preview, status = future.result()
                except Exception as exc:
                    preview_errors[property_url] = compact_text(
                        str(exc or "property_scout_preview_prefetch_failed"),
                        fallback="property_scout_preview_prefetch_failed",
                        limit=200,
                    )
                    continue
                if preview:
                    preview_rows[resolved_url] = dict(preview)
                if status == "hit":
                    cache_hit_total += 1
                elif status == "refresh":
                    cache_refresh_total += 1
        return {
            "previews": preview_rows,
            "errors": preview_errors,
            "cache_hit_total": cache_hit_total,
            "cache_refresh_total": cache_refresh_total,
            "worker_concurrency": max_workers,
        }

    def _prefetch_property_public_previews_for_sources(
        self,
        *,
        source_jobs: list[dict[str, object]],
        cache_index: dict[str, dict[str, object]],
        worker_cap: int,
        on_source_started: callable | None = None,
        on_source_finished: callable | None = None,
    ) -> dict[str, object]:
        normalized_jobs: list[dict[str, object]] = []
        for job in _property_search_interleave_by_provider_group(source_jobs):
            source_url = urllib.parse.urldefrag(str(job.get("url") or job.get("__source_url__") or "").strip())[0]
            platform = str(job.get("platform") or "").strip().lower()
            listing_urls: list[str] = []
            for property_url in list(job.get("__listing_urls__") or []):
                normalized_property_url = urllib.parse.urldefrag(str(property_url or "").strip())[0]
                if normalized_property_url and normalized_property_url not in listing_urls:
                    listing_urls.append(normalized_property_url)
            if not source_url or not platform or not listing_urls:
                continue
            normalized_jobs.append(
                {
                    **dict(job),
                    "__source_url__": source_url,
                    "__platform__": platform,
                    "__listing_urls__": listing_urls,
                }
            )
        if not normalized_jobs:
            return {
                "source_results": {},
                "cache_hit_total": 0,
                "cache_refresh_total": 0,
                "worker_concurrency": 0,
            }

        cache_lock = threading.Lock()
        source_results: dict[tuple[str, str], dict[str, object]] = {}
        cache_hit_total = 0
        cache_refresh_total = 0

        def _task(job: dict[str, object]) -> dict[str, object]:
            previews: dict[str, dict[str, object]] = {}
            errors: dict[str, str] = {}
            hit_total = 0
            refresh_total = 0
            for property_url in list(job.get("__listing_urls__") or []):
                with cache_lock:
                    cached_preview = self._property_public_preview_cache_lookup(
                        cache_index=cache_index,
                        property_url=property_url,
                    )
                if cached_preview:
                    previews[property_url] = dict(cached_preview)
                    hit_total += 1
                    continue
                try:
                    preview = _property_scout_page_preview_with_timeout(property_url, prefer_fast=True)
                except Exception as exc:
                    errors[property_url] = compact_text(
                        str(exc or "property_scout_preview_prefetch_failed"),
                        fallback="property_scout_preview_prefetch_failed",
                        limit=200,
                    )
                    continue
                with cache_lock:
                    self._property_public_preview_cache_store(
                        cache_index=cache_index,
                        property_url=property_url,
                        preview=preview,
                    )
                previews[property_url] = dict(preview or {})
                refresh_total += 1
            return {
                "previews": previews,
                "errors": errors,
                "cache_hit_total": hit_total,
                "cache_refresh_total": refresh_total,
            }

        max_workers = max(1, min(int(worker_cap or 1), len(normalized_jobs)))
        queued_jobs = iter(normalized_jobs)

        def _submit(executor: concurrent.futures.ThreadPoolExecutor, active: dict[concurrent.futures.Future, dict[str, object]]) -> bool:
            try:
                job = next(queued_jobs)
            except StopIteration:
                return False
            if callable(on_source_started):
                try:
                    on_source_started(dict(job))
                except Exception:
                    pass
            active[executor.submit(_task, dict(job))] = dict(job)
            return True

        with concurrent.futures.ThreadPoolExecutor(
            max_workers=max_workers,
            thread_name_prefix="property-source-preview",
        ) as executor:
            active: dict[concurrent.futures.Future, dict[str, object]] = {}
            for _ in range(max_workers):
                if not _submit(executor, active):
                    break
            while active:
                done, _ = concurrent.futures.wait(
                    tuple(active.keys()),
                    return_when=concurrent.futures.FIRST_COMPLETED,
                )
                for future in done:
                    job = active.pop(future)
                    platform = str(job.get("__platform__") or "").strip().lower()
                    source_url = str(job.get("__source_url__") or "").strip()
                    result: dict[str, object]
                    try:
                        result = dict(future.result() or {})
                    except Exception as exc:
                        result = {
                            "previews": {},
                            "errors": {
                                source_url or platform or "source": compact_text(
                                    str(exc or "property_scout_preview_prefetch_failed"),
                                    fallback="property_scout_preview_prefetch_failed",
                                    limit=200,
                                )
                            },
                            "cache_hit_total": 0,
                            "cache_refresh_total": 0,
                        }
                    source_results[(platform, source_url)] = result
                    cache_hit_total += int(result.get("cache_hit_total") or 0)
                    cache_refresh_total += int(result.get("cache_refresh_total") or 0)
                    if callable(on_source_finished):
                        try:
                            on_source_finished(dict(job), dict(result))
                        except Exception:
                            pass
                    _submit(executor, active)

        return {
            "source_results": source_results,
            "cache_hit_total": cache_hit_total,
            "cache_refresh_total": cache_refresh_total,
            "worker_concurrency": max_workers,
        }

    def _recover_floorplans_for_candidates(
        self,
        *,
        candidates: list[dict[str, object]],
        cache_index: dict[str, dict[str, object]],
        plan_key: str = "free",
    ) -> dict[str, dict[str, object]]:
        recovery_limit = _property_search_floorplan_worker_limit()
        worker_cap = _property_search_floorplan_worker_concurrency_for_plan(plan_key)
        queued = [
            dict(row)
            for row in list(candidates or [])[:recovery_limit]
            if isinstance(row, dict) and str(row.get("property_url") or "").strip()
        ]
        if recovery_limit <= 0 or worker_cap <= 0 or not queued:
            return {}

        cache_lock = threading.Lock()
        recovered: dict[str, dict[str, object]] = {}

        def _task(candidate: dict[str, object]) -> tuple[str, dict[str, object]] | None:
            property_url = urllib.parse.urldefrag(str(candidate.get("property_url") or "").strip())[0]
            if not property_url:
                return None
            try:
                preview = _property_scout_page_preview_with_timeout(property_url, prefer_fast=False)
            except Exception:
                return None
            if not _property_candidate_has_floorplan(
                property_url=property_url,
                title=str(preview.get("title") or ""),
                summary=str(preview.get("summary") or ""),
                property_facts=dict(preview.get("property_facts_json") or {}),
                preview=preview,
            ):
                return None
            with cache_lock:
                self._property_public_preview_cache_store(
                    cache_index=cache_index,
                    property_url=property_url,
                    preview=preview,
                )
            return property_url, preview

        with concurrent.futures.ThreadPoolExecutor(
            max_workers=max(1, min(worker_cap, len(queued))),
            thread_name_prefix="property-floorplan-worker",
        ) as executor:
            futures = [executor.submit(_task, row) for row in queued]
            for future in concurrent.futures.as_completed(futures):
                try:
                    outcome = future.result()
                except Exception:
                    continue
                if not outcome:
                    continue
                property_url, preview = outcome
                recovered[property_url] = dict(preview)
        return recovered

    def _resolve_google_location_history_import_path(self, path: str) -> Path:
        raw = str(path or "").strip()
        if not raw:
            raise RuntimeError("google_location_history_import_path_not_found")
        candidate = Path(raw).expanduser()
        candidate = candidate.resolve() if candidate.is_absolute() else (_repo_root() / candidate).resolve()
        if not candidate.exists() or not candidate.is_file():
            raise RuntimeError("google_location_history_import_path_not_found")
        return candidate

    def _google_location_portability_principal_ids(self, principal_id: str) -> tuple[str, ...]:
        ordered: list[str] = []
        for raw in (
            principal_id,
            os.environ.get("EA_GOOGLE_DEFAULT_PRINCIPAL_ID", ""),
            os.environ.get("EA_DEFAULT_PRINCIPAL_ID", ""),
            "local-user",
        ):
            normalized = str(raw or "").strip()
            if normalized and normalized not in ordered:
                ordered.append(normalized)
        return tuple(ordered)

    def _google_location_portability_primary_binding_id(self, principal_id: str) -> str:
        return f"{str(principal_id or '').strip()}:{_GOOGLE_LOCATION_PORTABILITY_PROVIDER_KEY}"

    def _list_google_location_portability_binding_records(self, *, principal_id: str) -> list[object]:
        rows: list[object] = []
        seen: set[str] = set()
        for binding_principal_id in self._google_location_portability_principal_ids(principal_id):
            for row in self._container.provider_registry.list_persisted_binding_records(principal_id=binding_principal_id, limit=100):
                if str(getattr(row, "provider_key", "") or "").strip() != _GOOGLE_LOCATION_PORTABILITY_PROVIDER_KEY:
                    continue
                binding_id = str(getattr(row, "binding_id", "") or "").strip()
                if binding_id and binding_id not in seen:
                    seen.add(binding_id)
                    rows.append(row)
        rows.sort(key=lambda row: (str(getattr(row, "updated_at", "") or ""), str(getattr(row, "binding_id", "") or "")), reverse=True)
        return rows

    def _resolve_google_location_portability_access_token(self, *, principal_id: str) -> tuple[object, str, dict[str, object]]:
        config = google_oauth_service.load_google_oauth_config()
        for binding in self._list_google_location_portability_binding_records(principal_id=principal_id):
            metadata = dict(getattr(binding, "auth_metadata_json", {}) or {})
            granted_scopes = {
                str(scope or "").strip()
                for scope in list(metadata.get("granted_scopes") or [])
                if str(scope or "").strip()
            }
            if _GOOGLE_LOCATION_PORTABILITY_SCOPE not in granted_scopes:
                continue
            refresh_token_ref = str(metadata.get("refresh_token_ref") or "").strip()
            if not refresh_token_ref:
                continue
            refresh_token = google_oauth_service._decrypt_secret(refresh_token_ref, key=config.provider_secret_key)
            token_payload = google_oauth_service._refresh_google_access_token(
                refresh_token=refresh_token,
                client_id=config.client_id,
                client_secret=config.client_secret,
            )
            access_token = str(token_payload.get("access_token") or "").strip()
            if not access_token:
                continue
            updated_metadata = dict(metadata)
            updated_metadata["access_token_expires_at"] = google_oauth_service._utc_iso_after_seconds(
                google_oauth_service._safe_int(token_payload.get("expires_in"), default=0)
            )
            updated_metadata["last_refresh_at"] = google_oauth_service._utc_iso_now()
            updated_metadata["last_successful_api_call_at"] = google_oauth_service._utc_iso_now()
            updated_metadata["token_status"] = "active"
            binding_principal_id = str(getattr(binding, "principal_id", "") or principal_id).strip() or principal_id
            self._container.provider_registry.upsert_binding_record(
                binding_id=str(getattr(binding, "binding_id", "") or "").strip(),
                principal_id=binding_principal_id,
                provider_key=_GOOGLE_LOCATION_PORTABILITY_PROVIDER_KEY,
                status=str(getattr(binding, "status", "") or "enabled").strip() or "enabled",
                priority=int(getattr(binding, "priority", 70) or 70),
                probe_state="ready",
                probe_details_json=dict(getattr(binding, "probe_details_json", {}) or {}),
                scope_json=dict(getattr(binding, "scope_json", {}) or {}),
                auth_metadata_json=updated_metadata,
            )
            return binding, access_token, updated_metadata
        raise RuntimeError("google_location_history_binding_not_found")

    def _google_location_portability_http_json(
        self,
        *,
        access_token: str,
        method: str,
        url: str,
        payload: dict[str, object] | None = None,
    ) -> dict[str, object]:
        headers = {
            "Authorization": f"Bearer {str(access_token or '').strip()}",
            "Content-Type": "application/json; charset=utf-8",
        }
        data = None if payload is None else json.dumps(payload).encode("utf-8")
        request = urllib.request.Request(url, data=data, headers=headers, method=method.upper())
        try:
            with urllib.request.urlopen(request, timeout=120) as response:
                raw = response.read().decode("utf-8")
        except urllib.error.HTTPError as exc:
            detail = exc.read().decode("utf-8", "ignore")
            raise RuntimeError(f"google_location_history_api_http_{exc.code}:{detail}") from exc
        except urllib.error.URLError as exc:
            raise RuntimeError(f"google_location_history_api_unreachable:{exc}") from exc
        return json.loads(raw) if raw.strip() else {}

    def start_google_location_history_connect(
        self,
        *,
        principal_id: str,
        actor: str,
        redirect_uri_override: str = "",
    ) -> dict[str, object]:
        config = google_oauth_service.load_google_oauth_config()
        redirect_uri = str(redirect_uri_override or config.redirect_uri).strip() or config.redirect_uri
        state_payload = {
            "principal_id": principal_id,
            "oauth_lane": "google_location_history",
            "redirect_uri": redirect_uri,
            "issued_at": int(time.time()),
            "nonce": secrets.token_urlsafe(12),
        }
        state = google_oauth_service._encode_signed_state(state_payload, secret=config.state_secret)
        query = urllib.parse.urlencode(
            {
                "response_type": "code",
                "client_id": config.client_id,
                "redirect_uri": redirect_uri,
                "scope": " ".join(_GOOGLE_LOCATION_PORTABILITY_AUTH_SCOPES),
                "access_type": "offline",
                "include_granted_scopes": "false",
                "prompt": "consent",
                "state": state,
            }
        )
        self._record_product_event(
            principal_id=principal_id,
            event_type="google_location_history_connect_started",
            payload={
                "actor": str(actor or "").strip() or "office_api",
                "redirect_uri": redirect_uri,
            },
            source_id="google-location-history",
            dedupe_key=f"{principal_id}|google-location-history-connect-started|{state}",
        )
        return {
            "provider_key": _GOOGLE_LOCATION_PORTABILITY_PROVIDER_KEY,
            "principal_id": principal_id,
            "requested_scopes": list(_GOOGLE_LOCATION_PORTABILITY_AUTH_SCOPES),
            "auth_url": f"{google_oauth_service.GOOGLE_AUTH_ENDPOINT}?{query}",
            "state": state,
        }

    def complete_google_location_history_connect(
        self,
        *,
        code: str,
        state: str,
    ) -> dict[str, object]:
        config = google_oauth_service.load_google_oauth_config()
        state_payload = google_oauth_service._decode_signed_state(state, secret=config.state_secret)
        if str(state_payload.get("oauth_lane") or "").strip() != "google_location_history":
            raise RuntimeError("google_location_history_state_invalid")
        principal_id = str(state_payload.get("principal_id") or "").strip()
        if not principal_id:
            raise RuntimeError("google_location_history_principal_missing")
        redirect_uri = str(state_payload.get("redirect_uri") or config.redirect_uri).strip() or config.redirect_uri
        google_oauth_service._consume_google_oauth_state(state_payload)
        token_payload = google_oauth_service._exchange_google_code_for_tokens(
            code=code,
            client_id=config.client_id,
            client_secret=config.client_secret,
            redirect_uri=redirect_uri,
        )
        existing_google_accounts = google_oauth_service.list_google_accounts(
            container=self._container,
            principal_id=principal_id,
        )
        google_email = str(existing_google_accounts[0].google_email or "").strip().lower() if existing_google_accounts else ""
        google_subject = (
            str(existing_google_accounts[0].google_subject or "").strip()
            if existing_google_accounts
            else f"dataportability:{principal_id}"
        )
        granted_scopes = tuple(
            sorted(
                {
                    scope.strip()
                    for scope in str(token_payload.get("scope") or "").split(" ")
                    if scope.strip()
                }
            )
        ) or _GOOGLE_LOCATION_PORTABILITY_AUTH_SCOPES
        refresh_token = str(token_payload.get("refresh_token") or "").strip()
        if not refresh_token:
            raise RuntimeError("google_location_history_refresh_token_missing")
        refresh_token_ref = google_oauth_service._encrypt_secret(refresh_token, key=config.provider_secret_key)
        binding_id = self._google_location_portability_primary_binding_id(principal_id)
        auth_metadata_json = {
            "google_subject": google_subject,
            "google_email": google_email,
            "google_hosted_domain": "",
            "granted_scopes": list(granted_scopes),
            "refresh_token_ref": refresh_token_ref,
            "token_status": "active",
            "last_successful_api_call_at": google_oauth_service._utc_iso_now(),
            "last_refresh_at": google_oauth_service._utc_iso_now(),
            "reauth_required_reason": "",
        }
        binding = self._container.provider_registry.upsert_binding_record(
            binding_id=binding_id,
            principal_id=principal_id,
            provider_key=_GOOGLE_LOCATION_PORTABILITY_PROVIDER_KEY,
            status="enabled",
            priority=70,
            probe_state="ready",
            probe_details_json={
                "google_email": google_email,
                "google_subject": google_subject,
                "oauth_lane": "google_location_history",
            },
            scope_json={"scopes": list(granted_scopes), "bundle": "dataportability_maps"},
            auth_metadata_json=auth_metadata_json,
        )
        self._record_product_event(
            principal_id=principal_id,
            event_type="google_location_history_connected",
            payload={
                "binding_id": binding.binding_id,
                "google_email": google_email,
                "google_subject": google_subject,
            },
            source_id="google-location-history",
            dedupe_key=f"{principal_id}|google-location-history-connected|{google_subject}",
        )
        return {
            "provider_key": _GOOGLE_LOCATION_PORTABILITY_PROVIDER_KEY,
            "principal_id": principal_id,
            "binding_id": binding.binding_id,
            "google_email": google_email,
            "google_subject": google_subject,
            "granted_scopes": list(granted_scopes),
            "token_status": "active",
        }

    def _load_google_location_history_payload(self, source_path: Path) -> tuple[object, list[str]]:
        if source_path.suffix.lower() == ".zip":
            with zipfile.ZipFile(source_path) as archive:
                names = archive.namelist()
                candidate_name = next(
                    (
                        name
                        for name in names
                        if name.lower().endswith(".json")
                        and any(marker in name.lower() for marker in ("records.json", "timeline", "location history"))
                    ),
                    "",
                )
                if not candidate_name:
                    candidate_name = next((name for name in names if name.lower().endswith(".json")), "")
                if not candidate_name:
                    raise RuntimeError("google_location_history_import_payload_not_found")
                with archive.open(candidate_name) as handle:
                    return json.loads(handle.read().decode("utf-8")), ["zip", Path(candidate_name).name]
        return json.loads(source_path.read_text(encoding="utf-8")), ["json", source_path.name]

    def _google_location_history_windows(self, *, principal_id: str) -> list[dict[str, object]]:
        windows: list[dict[str, object]] = []
        for row in self._container.channel_runtime.list_recent_observations(
            limit=_GOOGLE_LOCATION_HISTORY_LOOKBACK,
            principal_id=principal_id,
        ):
            if str(getattr(row, "channel", "") or "").strip() != "product":
                continue
            if str(getattr(row, "event_type", "") or "").strip() != "google_location_history_window_imported":
                continue
            payload = dict(getattr(row, "payload", {}) or {})
            if str(payload.get("location_start_at") or "").strip():
                windows.append(payload)
        return windows

    def _match_google_location_window(self, *, principal_id: str, recording_at: str) -> dict[str, object]:
        when = _parse_utcish(recording_at)
        if when is None:
            return {
                "location_match_status": "unmatched",
                "location_match_reason": "recording_time_missing",
                "location_name": "",
                "location_address": "",
                "location_latitude": None,
                "location_longitude": None,
                "location_start_at": "",
                "location_end_at": "",
                "location_source": "",
                "location_confidence": 0.0,
            }
        containing_match: dict[str, object] | None = None
        containing_duration: float | None = None
        nearest_match: dict[str, object] | None = None
        nearest_gap: float | None = None
        for payload in self._google_location_history_windows(principal_id=principal_id):
            start_at = _parse_utcish(str(payload.get("location_start_at") or "").strip())
            end_at = _parse_utcish(str(payload.get("location_end_at") or payload.get("location_start_at") or "").strip())
            if start_at is None or end_at is None:
                continue
            if start_at <= when <= end_at:
                duration_seconds = max(0.0, (end_at - start_at).total_seconds())
                if containing_duration is None or duration_seconds < containing_duration:
                    containing_duration = duration_seconds
                    containing_match = payload
                continue
            gap_seconds = min(abs((when - start_at).total_seconds()), abs((when - end_at).total_seconds()))
            if nearest_gap is None or gap_seconds < nearest_gap:
                nearest_gap = gap_seconds
                nearest_match = payload
        if containing_match is not None:
            return {
                **_google_location_match_projection(containing_match),
                "location_match_status": "matched",
                "location_match_reason": "timeline_window_contains_recording",
                "location_source": str(containing_match.get("source_format") or "").strip(),
                "location_confidence": 1.0,
            }
        max_gap_seconds = _google_location_history_match_max_gap_seconds()
        if nearest_match is not None and nearest_gap is not None and nearest_gap <= max_gap_seconds:
            confidence = max(0.1, 1.0 - (nearest_gap / max(max_gap_seconds, 1.0)))
            return {
                **_google_location_match_projection(nearest_match),
                "location_match_status": "nearest",
                "location_match_reason": "nearest_timeline_window",
                "location_source": str(nearest_match.get("source_format") or "").strip(),
                "location_confidence": round(confidence, 4),
            }
        return {
            "location_match_status": "unmatched",
            "location_match_reason": "no_timeline_window_match",
            "location_name": "",
            "location_address": "",
            "location_latitude": None,
            "location_longitude": None,
            "location_start_at": "",
            "location_end_at": "",
            "location_source": "",
            "location_confidence": 0.0,
        }

    def _pocket_recording_signal_projection_map(self, *, principal_id: str) -> dict[str, dict[str, object]]:
        projection: dict[str, dict[str, object]] = {}
        for row in self._container.channel_runtime.list_recent_observations(
            limit=_POCKET_RECORDING_INDEX_LOOKBACK,
            principal_id=principal_id,
        ):
            source_id = str(getattr(row, "source_id", "") or "").strip()
            if not source_id.startswith("pocket-recording:"):
                continue
            payload = dict(getattr(row, "payload", {}) or {})
            recording_id = str(payload.get("recording_id") or source_id.removeprefix("pocket-recording:")).strip()
            if not recording_id:
                continue
            if recording_id not in projection:
                projection[recording_id] = payload
                continue
            existing = projection[recording_id]
            for key, value in payload.items():
                if existing.get(key) in (None, "", [], {}):
                    existing[key] = value
        return projection

    def _record_pocket_archive_index(
        self,
        *,
        principal_id: str,
        recording_id: str,
        title: str,
        recording_at: str,
        archive_result: dict[str, object],
        summary_markdown: str,
        transcript_text: str,
        transcript_excerpt: str,
        location_match: dict[str, object],
        topic_keywords_csv: str = "",
        tags: Sequence[str] | None = None,
    ) -> None:
        payload = {
            "recording_id": recording_id,
            "title": title,
            "recording_at": recording_at,
            "archive_status": str(archive_result.get("archive_status") or "").strip(),
            "archive_path": str(archive_result.get("archive_path") or "").strip(),
            "archive_sha256": str(archive_result.get("archive_sha256") or "").strip(),
            "summary_markdown": summary_markdown,
            "transcript_text": compact_text(transcript_text, fallback="", limit=12000),
            "transcript_excerpt": transcript_excerpt,
            "topic_keywords_csv": str(topic_keywords_csv or "").strip(),
            "tags_csv": ", ".join(str(item).strip() for item in list(tags or []) if str(item).strip()),
            **_google_location_match_projection(location_match),
        }
        dedupe_material = json.dumps(payload, sort_keys=True, ensure_ascii=False)
        dedupe_key = f"{principal_id}|pocket-recording-archive-indexed|{hashlib.sha256(dedupe_material.encode('utf-8')).hexdigest()}"
        if self._container.channel_runtime.find_observation_by_dedupe(dedupe_key, principal_id=principal_id) is not None:
            return
        self._record_product_event(
            principal_id=principal_id,
            event_type="pocket_recording_archive_indexed",
            payload=payload,
            source_id=f"pocket-recording:{recording_id}",
            dedupe_key=dedupe_key,
        )

    def _reindex_pocket_archive_locations(self, *, principal_id: str) -> dict[str, int]:
        archive_root = _pocket_audio_archive_root()
        principal_token = _pocket_archive_safe_token(principal_id, fallback="local-user", limit=64)
        archive_dir = archive_root / principal_token
        if not archive_dir.exists():
            return {
                "matched_recording_total": 0,
                "unmatched_recording_total": 0,
                "indexed_recording_total": 0,
                "updated_metadata_total": 0,
            }
        signal_payloads = self._pocket_recording_signal_projection_map(principal_id=principal_id)
        matched_total = 0
        unmatched_total = 0
        indexed_total = 0
        updated_total = 0
        for metadata_path in archive_dir.rglob("*.json"):
            try:
                payload = json.loads(metadata_path.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                continue
            recording_id = str(payload.get("recording_id") or "").strip()
            if not recording_id:
                continue
            title = str(payload.get("title") or "").strip() or f"Pocket recording {recording_id}"
            recording_at = str(payload.get("recording_at") or "").strip()
            location_match = self._match_google_location_window(principal_id=principal_id, recording_at=recording_at)
            next_location_payload = _google_location_match_projection(location_match)
            if dict(payload.get("location_match") or {}) != next_location_payload:
                payload["location_match"] = next_location_payload
                try:
                    metadata_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False) + "\n", encoding="utf-8")
                except OSError:
                    pass
                else:
                    updated_total += 1
            signal_payload = dict(signal_payloads.get(recording_id) or {})
            self._record_pocket_archive_index(
                principal_id=principal_id,
                recording_id=recording_id,
                title=title,
                recording_at=recording_at,
                archive_result={
                    "archive_status": "already_archived",
                    "archive_path": str(payload.get("archive_path") or "").strip(),
                    "archive_sha256": str(payload.get("archive_sha256") or "").strip(),
                },
                summary_markdown=str(signal_payload.get("summary_markdown") or "").strip(),
                transcript_text=str(signal_payload.get("transcript_text") or signal_payload.get("transcript_excerpt") or "").strip(),
                transcript_excerpt=str(signal_payload.get("transcript_excerpt") or "").strip(),
                location_match=location_match,
                topic_keywords_csv=str(signal_payload.get("topic_keywords_csv") or "").strip(),
                tags=[item.strip() for item in str(signal_payload.get("tags_csv") or "").split(",") if item.strip()],
            )
            indexed_total += 1
            if str(location_match.get("location_match_status") or "").strip() in {"matched", "nearest"}:
                matched_total += 1
            else:
                unmatched_total += 1
        return {
            "matched_recording_total": matched_total,
            "unmatched_recording_total": unmatched_total,
            "indexed_recording_total": indexed_total,
            "updated_metadata_total": updated_total,
        }

    def _deliver_google_keep_shopping_list_item(
        self,
        *,
        principal_id: str,
        actor: str,
        recording_id: str,
        title: str,
        recording_at: str,
        trigger_text: str,
        item_text: str,
    ) -> dict[str, object]:
        try:
            receipt = google_oauth_service.create_google_keep_note(
                container=self._container,
                principal_id=principal_id,
                title="Shopping list",
                list_item_texts=(item_text,),
            )
            return {
                "status": "created",
                "backend": "google_keep",
                "note_name": receipt.note_name,
                "note_title": receipt.title,
                "list_item_texts": list(receipt.list_item_texts),
                "created_at": receipt.created_at,
            }
        except RuntimeError as exc:
            if str(exc or "").strip() not in {
                "google_keep_scope_missing",
                "google_oauth_binding_not_found",
                "google_keep_refresh_token_missing",
                "google_keep_access_token_missing",
            }:
                raise
        followup = self._open_pocket_assistant_followup(
            principal_id=principal_id,
            recording_id=recording_id,
            title=title,
            recording_at=recording_at,
            trigger_text=trigger_text,
            action="manual_followup",
            reason="google_keep_reconnect_required",
            params={
                "brief": f"Complete Google Keep reconnect for shopping list item: {item_text}",
                "why": "Google Keep authorization is not available for this principal, so EA cannot safely write the note automatically.",
                "requested_action": "shopping_list_add",
                "item_text": item_text,
            },
        )
        return {
            "status": "queued",
            "backend": "human_followup",
            "reason": "google_keep_reconnect_required",
            "task_id": str(getattr(followup, "task_id", "") or ""),
            "session_id": str(getattr(followup, "session_id", "") or ""),
        }

